        redirectTo: payload.redirectTo || getResetPasswordRedirectUrl(),
      }),
    });
  } catch (error) {
    return {
      ok: false,
      error: error?.message || "Không gọi được API tạo user.",
      code: "ADMIN_API_UNREACHABLE",
    };
