  }
  return true;
}

import { createId } from "../../../utils/id.js";
import {
  ACTIVATION_RULE,
  DREAMBREAKER_ORDER_SOURCE,
  DREAMBREAKER_STATUS,
  DISCIPLINE_KIND,
  MATCHUP_STATUS,
  SUB_MATCH_STATUS,
} from "../constants.js";
import {
  findMatchup,
  findTeam,
  normalizeTeamData,
} from "../models/index.js";
import {
  getDreambreakerDiscipline,
  isMlpFormat,
