export function appendVprAuditLog(entry) {
  const rows = listVprAuditLogs();
  rows.unshift({
    id: `vpr-audit-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    createdAt: new Date().toISOString(),
    ...entry,
  });
  const capped = rows.slice(0, 500);
  if (useMemory()) {
    ensureMemoryStore().audit = capped;
    return capped[0];
  }
  writeJson(KEYS.audit, capped);
  return capped[0];
}

import { useEffect, useMemo, useState } from "react";
import {
  Alert,
  Autocomplete,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControl,
  InputLabel,
  MenuItem,
  Select,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Typography,
  Paper,
  Checkbox,
  FormControlLabel,
  IconButton,
  Tooltip,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import DirectionsIcon from "@mui/icons-material/Directions";
import InfoOutlinedIcon from "@mui/icons-material/InfoOutlined";
import EditIcon from "@mui/icons-material/Edit";

import { useTenant } from "../../context/TenantContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { useCluster } from "../../context/ClusterContext.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import { isPlatformScopedRole } from "../../auth/roles.js";
import { listTenants, getTenantById } from "../../features/tenant/index.js";
import { isCourtClustersEnabled } from "../../features/court-cluster/config/clusterFlags.js";
import {
  createCourtCluster,
  getClusterById,
  isClusterAssigned,
  listAssignmentsForCluster,
  ADMIN_ALL_TENANTS_ID,
  listClustersForAdminManagement,
  listClustersForVenue,
  updateCourtCluster,
} from "../../features/court-cluster/services/courtClusterService.js";
import {
  assignClusterOwnerToUser,
  persistCourtClusterToCloud,
  removeClusterOwner,
  removeCourtCluster,
  syncClustersForVenueToCloud,
} from "../../features/court-cluster/services/courtClusterAdminService.js";
import { pullClusterContextForUser } from "../../features/court-cluster/services/courtClusterCloudSync.js";
import { isValidProfileUserId } from "../../features/court-cluster/utils/profileUserId.js";
import { listUsers } from "../../features/identity/services/userManagementService.js";
import { openClusterInGoogleMaps } from "../../features/court-cluster/utils/clusterMapsUtils.js";
import {
  listPendingCourtClaimRequests,
  reviewCourtClaimRequest,
} from "../../features/court-cluster/services/courtClaimRequestService.js";
import { fetchProfileByUserId } from "../../auth/profileService.js";

const EMPTY_FORM = {
  name: "",
  slug: "",
  address: "",
  googleMapsUrl: "",
};

export default function CourtClusterManagement() {
  const { currentTenantId, currentTenant, switchTenant, isSuperAdmin } = useTenant();
  const { user, can, rbacEnabled } = useAuth();
  const { refreshClusters } = useCluster();
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [createOpen, setCreateOpen] = useState(false);
  const [editOpen, setEditOpen] = useState(false);
  const [assignOpen, setAssignOpen] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingCluster, setEditingCluster] = useState(null);
  const [assignForm, setAssignForm] = useState({
    user: null,
    clusterIds: [],
  });
  const [assignUsers, setAssignUsers] = useState([]);
  const [assignUsersLoading, setAssignUsersLoading] = useState(false);
  const [assignSaving, setAssignSaving] = useState(false);
  const [pendingClaims, setPendingClaims] = useState([]);
  const [reviewNote, setReviewNote] = useState("");
  const [reviewingId, setReviewingId] = useState(null);

  const [infoOpen, setInfoOpen] = useState(false);
  const [infoCluster, setInfoCluster] = useState(null);
  const [ownerUserId, setOwnerUserId] = useState(null);
  const [ownerLoading, setOwnerLoading] = useState(false);
  const [ownerError, setOwnerError] = useState(null);
  const [ownerProfile, setOwnerProfile] = useState(null);
  const [createSaving, setCreateSaving] = useState(false);
  const [editSaving, setEditSaving] = useState(false);
  const [syncSaving, setSyncSaving] = useState(false);
  const [removeOwnerSaving, setRemoveOwnerSaving] = useState(false);
  const [removeOwnerConfirmOpen, setRemoveOwnerConfirmOpen] = useState(false);
  const [clusterRevision, setClusterRevision] = useState(0);
  const [venueFilter, setVenueFilter] = useState(ADMIN_ALL_TENANTS_ID);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [deleteSaving, setDeleteSaving] = useState(false);

  const canPickTenant = isSuperAdmin || isPlatformScopedRole(user?.role);
  const tenants = useMemo(() => listTenants(), [message]);
  const effectiveVenueId = canPickTenant
    ? venueFilter === ADMIN_ALL_TENANTS_ID
      ? ADMIN_ALL_TENANTS_ID
      : venueFilter || currentTenantId || user?.venueId || null
    : currentTenantId || user?.venueId || null;
  const venueId =
    effectiveVenueId === ADMIN_ALL_TENANTS_ID ? ADMIN_ALL_TENANTS_ID : effectiveVenueId;
  const createVenueId =
    effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId;
  const clusters = useMemo(
    () => listClustersForAdminManagement(user, venueId),
    [user, venueId, message, clusterRevision]
  );
  const showVenueColumn =
    canPickTenant &&
    (venueFilter === ADMIN_ALL_TENANTS_ID ||
      clusters.some((cluster) => cluster.venueId !== effectiveVenueId));
  const organizationLabel =
    venueFilter === ADMIN_ALL_TENANTS_ID
      ? "Tất cả"
      : getTenantById(effectiveVenueId)?.name || effectiveVenueId || "—";
  const canManage =
    !rbacEnabled ||
    can(PERMISSIONS.CLUSTER_MANAGE, {
      tenantId: effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId,
      venueId: effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId,
    });

  useEffect(() => {
    if (!canPickTenant && currentTenantId) {
      setVenueFilter(currentTenantId);
    }
  }, [canPickTenant, currentTenantId]);

  useEffect(() => {
    if (!isCourtClustersEnabled()) {
      setError("Bật VITE_COURT_CLUSTERS_ENABLED=true để quản lý cụm sân.");
    }
  }, []);

  useEffect(() => {
    if (!canManage || !user?.id) {
      return;
    }
    void pullClusterContextForUser(user).then((result) => {
      if (result.ok) {
        refreshClusters();
        setClusterRevision((value) => value + 1);
      }
    });
  }, [canManage, refreshClusters, user]);

  const loadPendingClaims = async () => {
    const result = await listPendingCourtClaimRequests();
    if (result.ok) {
      setPendingClaims(result.requests || []);
    }
  };

  useEffect(() => {
    if (canManage) {
      void loadPendingClaims();
    }
  }, [canManage, message]);

  const handleReviewClaim = async (requestId, action) => {
    setReviewingId(requestId);
    setError(null);
    const result = await reviewCourtClaimRequest({
      requestId,
      action,
      reviewNote,
    });
    setReviewingId(null);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(action === "approve" ? "Đã duyệt yêu cầu gắn cụm." : "Đã từ chối yêu cầu.");
    setReviewNote("");
    refreshClusters();
    await loadPendingClaims();
  };

  const resetForm = () => {
    setForm(EMPTY_FORM);
    setEditingCluster(null);
  };

  const handleCreate = async () => {
    setError(null);
    setCreateSaving(true);
    const result = createCourtCluster({
      venueId: createVenueId,
      name: form.name,
      slug: form.slug || undefined,
      address: form.address,
      googleMapsUrl: form.googleMapsUrl,
      ownerUserId: user?.id || null,
      user,
    });

    if (!result.ok) {
      setCreateSaving(false);
      setError(result.error);
      return;
    }

    const cloudResult = await persistCourtClusterToCloud(result.cluster, { venueId, actor: user });
    setCreateSaving(false);

    if (!cloudResult.ok) {
      setError(cloudResult.error || "Không đồng bộ được cụm lên Supabase.");
      return;
    }

    setMessage(`Đã tạo cụm sân: ${result.cluster.name}`);
    setCreateOpen(false);
    resetForm();
    refreshClusters();
  };

  const openEditDialog = (cluster) => {
    setEditingCluster(cluster);
    setForm({
      name: cluster.name || "",
      slug: cluster.slug || "",
      address: cluster.address || "",
      googleMapsUrl: cluster.googleMapsUrl || "",
    });
    setEditOpen(true);
  };

  const handleEdit = async () => {
    if (!editingCluster) {
      return;
    }

    setError(null);
    setEditSaving(true);
    const result = updateCourtCluster(
      editingCluster.id,
      {
        name: form.name,
        slug: form.slug || undefined,
        address: form.address,
        googleMapsUrl: form.googleMapsUrl,
      },
      { user }
    );

    if (!result.ok) {
      setEditSaving(false);
      setError(result.error);
      return;
    }

    const cloudResult = await persistCourtClusterToCloud(result.cluster, { venueId, actor: user });
    setEditSaving(false);

    if (!cloudResult.ok) {
      setError(cloudResult.error || "Không đồng bộ được cụm lên Supabase.");
      return;
    }

    setMessage(`Đã cập nhật cụm sân: ${result.cluster.name}`);
    setEditOpen(false);
    resetForm();
    refreshClusters();
  };

  const handleToggleStatus = async (cluster) => {
    const nextStatus = cluster.status === "active" ? "inactive" : "active";
    const result = updateCourtCluster(cluster.id, { status: nextStatus }, { user });
    if (!result.ok) {
      setError(result.error);
      return;
    }

    const cloudResult = await persistCourtClusterToCloud(result.cluster, { venueId, actor: user });
    if (!cloudResult.ok) {
      setError(cloudResult.error || "Không đồng bộ trạng thái lên Supabase.");
      return;
    }

    setMessage(`Cập nhật trạng thái: ${result.cluster.name}`);
    refreshClusters();
  };

  const handleSyncToCloud = async () => {
    setError(null);
    setSyncSaving(true);
    const result = await syncClustersForVenueToCloud({
      clusters,
      venueId,
      actor: user,
    });
    setSyncSaving(false);

    if (!result.ok) {
      setError(result.error || "Đồng bộ cụm lên cloud thất bại.");
      return;
    }

    setMessage(`Đã đồng bộ ${result.synced ?? clusters.length} cụm lên Supabase.`);
    refreshClusters();
    setClusterRevision((value) => value + 1);
  };

  const handleDelete = async () => {
    if (!deleteTarget?.id) {
      return;
    }

    const deletedName = deleteTarget.name;
    setDeleteSaving(true);
    setError(null);
    const result = await removeCourtCluster({
      clusterId: deleteTarget.id,
      venueId: effectiveVenueId === ADMIN_ALL_TENANTS_ID ? null : effectiveVenueId,
      actor: user,
    });
    setDeleteSaving(false);
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage(`Đã xóa cụm sân: ${deletedName}`);
    refreshClusters();
    setClusterRevision((value) => value + 1);
  };

  const openDeleteConfirm = (cluster) => {
    setDeleteTarget(cluster);
    setDeleteConfirmOpen(true);
  };

  const openClusterInfoDialog = async (cluster) => {
    setInfoOpen(true);
    setInfoCluster(cluster);
    setOwnerUserId(null);
    setOwnerLoading(false);
    setOwnerError(null);
    setOwnerProfile(null);

    const assignments = listAssignmentsForCluster(cluster.id) || [];
    const ownerAssignment = assignments.find((a) => a.role === "CLUSTER_OWNER");
    const nextOwnerUserId = cluster?.ownerUserId || ownerAssignment?.userId || null;
    setOwnerUserId(nextOwnerUserId);

    if (!nextOwnerUserId) {
      return;
    }

    if (!isValidProfileUserId(nextOwnerUserId)) {
      setOwnerError(
        "Gán chủ sân chưa đồng bộ cloud (ID không hợp lệ). Dùng Gán chủ và chọn user từ danh sách."
      );
      return;
    }

    setOwnerLoading(true);
    const result = await fetchProfileByUserId(nextOwnerUserId);
    setOwnerLoading(false);

    if (!result.ok) {
      setOwnerError(result.error || "Không tải được thông tin chủ sở hữu.");
      return;
    }

    setOwnerProfile(result.user);
  };

  const hasClusterOwner = Boolean(
    ownerUserId || listAssignmentsForCluster(infoCluster?.id || "").some((a) => a.role === "CLUSTER_OWNER")
  );
  const ownerIdIsValid = isValidProfileUserId(ownerUserId);

  const handleRemoveOwner = async () => {
    if (!infoCluster?.id) {
      return;
    }

    setError(null);
    setRemoveOwnerSaving(true);
    const result = await removeClusterOwner({ clusterId: infoCluster.id, venueId, actor: user });
    setRemoveOwnerSaving(false);
    setRemoveOwnerConfirmOpen(false);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage("Đã xóa gán chủ sân cho cụm.");
    setOwnerUserId(null);
    setOwnerProfile(null);
    setOwnerError(null);
    refreshClusters();
    const refreshed = getClusterById(infoCluster.id);
    if (refreshed) {
      setInfoCluster(refreshed);
    }
  };

  const loadAssignUsers = async () => {
    setAssignUsersLoading(true);
    const result = await listUsers({ search: "" });
    setAssignUsersLoading(false);
    if (result.ok) {
      setAssignUsers(result.users || []);
    }
  };

  const openAssignDialog = (clusterId = null) => {
    const initialClusterIds = clusterId ? [clusterId] : [];
    setAssignForm({ user: null, clusterIds: initialClusterIds });
    setAssignOpen(true);
    void loadAssignUsers();
  };

  const handleAssign = async () => {
    setError(null);
    setAssignSaving(true);
    const result = await assignClusterOwnerToUser({
      userId: assignForm.user?.id,
      clusterIds: assignForm.clusterIds,
      venueId,
      actor: user,
    });
    setAssignSaving(false);

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setMessage("Đã cập nhật gán chủ sân cho cụm (Supabase)");
    setAssignOpen(false);
    refreshClusters();
    setClusterRevision((value) => value + 1);
  };

  if (!canManage) {
    return <Alert severity="warning">Bạn không có quyền quản lý cụm sân.</Alert>;
  }

  const formFields = (
    <Stack spacing={2} sx={{ pt: 1 }}>
      <TextField
        label="Tên cụm sân"
        value={form.name}
        onChange={(event) => setForm((prev) => ({ ...prev, name: event.target.value }))}
        placeholder="Cụm sân Nam Long"
        fullWidth
        required
      />
      <TextField
        label="Slug (tuỳ chọn)"
        value={form.slug}
        onChange={(event) => setForm((prev) => ({ ...prev, slug: event.target.value }))}
        placeholder="nam-long"
        fullWidth
      />
      <TextField
        label="Địa chỉ"
        value={form.address}
        onChange={(event) => setForm((prev) => ({ ...prev, address: event.target.value }))}
        placeholder="123 Đường Nam Long, Quận 7, TP.HCM"
        fullWidth
        multiline
        minRows={2}
      />
      <TextField
        label="Link Google Maps"
        value={form.googleMapsUrl}
        onChange={(event) => setForm((prev) => ({ ...prev, googleMapsUrl: event.target.value }))}
        placeholder="https://www.google.com/maps/dir/?api=1&destination=..."
        fullWidth
        helperText="Bấm Chỉ đường sẽ mở link này trên Google Maps"
      />
    </Stack>
  );

  return (
    <Box>
      <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 2 }}>
        <Box>
          <Typography variant="h5" fontWeight={700}>
            Quản lý cụm sân
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Tổ chức: {organizationLabel}
          </Typography>
        </Box>
        <Stack direction="row" spacing={1} alignItems="center">
          {canPickTenant && tenants.length > 0 && (
            <FormControl size="small" sx={{ minWidth: 220 }}>
              <InputLabel id="cluster-tenant-picker">Chọn tổ chức</InputLabel>
              <Select
                labelId="cluster-tenant-picker"
                value={venueFilter || ADMIN_ALL_TENANTS_ID}
                label="Chọn tổ chức"
                onChange={(event) => {
                  const nextValue = event.target.value;
                  setVenueFilter(nextValue);
                  if (nextValue !== ADMIN_ALL_TENANTS_ID) {
                    switchTenant(nextValue);
                  }
                  setClusterRevision((value) => value + 1);
                }}
              >
                <MenuItem value={ADMIN_ALL_TENANTS_ID}>Tất cả</MenuItem>
                {tenants.map((tenant) => (
                  <MenuItem key={tenant.id} value={tenant.id}>
                    {tenant.name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          )}
          <Button variant="outlined" onClick={() => openAssignDialog()}>
            Gán chủ sân
          </Button>
          {canPickTenant && (
            <Button variant="outlined" onClick={handleSyncToCloud} disabled={syncSaving || clusters.length === 0}>
              {syncSaving ? "Đang đồng bộ…" : "Đồng bộ lên cloud"}
            </Button>
          )}
          <Button
            variant="contained"
            startIcon={<AddIcon />}
            onClick={() => {
              resetForm();
              setCreateOpen(true);
            }}
            disabled={!createVenueId}
          >
            Thêm cụm sân
          </Button>
        </Stack>
      </Stack>

      {message && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message}
        </Alert>
      )}
      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {pendingClaims.length > 0 && (
        <Card sx={{ mb: 2 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={700} sx={{ mb: 1.5 }}>
              Yêu cầu gắn cụm sân ({pendingClaims.length})
            </Typography>
            <TableContainer component={Paper} variant="outlined">
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>Người yêu cầu</TableCell>
                    <TableCell>Cụm sân</TableCell>
                    <TableCell>Ghi chú</TableCell>
                    <TableCell>Thời gian</TableCell>
                    <TableCell align="right">Thao tác</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {pendingClaims.map((request) => (
                    <TableRow key={request.id} hover>
                      <TableCell>
                        <Typography variant="body2" fontWeight={600}>
                          {request.userDisplayName || request.userId}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {request.userEmail || "—"}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        {(request.clusterIds || []).map((clusterId) => {
                          const cluster = getClusterById(clusterId);
                          return (
                            <Chip
                              key={clusterId}
                              size="small"
                              label={cluster?.name || clusterId}
                              sx={{ mr: 0.5, mb: 0.5 }}
                            />
                          );
                        })}
                      </TableCell>
                      <TableCell sx={{ maxWidth: 200 }}>
                        <Typography variant="body2" noWrap title={request.message}>
                          {request.message || "—"}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        {request.requestedAt
                          ? new Date(request.requestedAt).toLocaleString("vi-VN")
                          : "—"}
                      </TableCell>
                      <TableCell align="right">
                        <Stack direction="row" spacing={1} justifyContent="flex-end">
                          <Button
                            size="small"
                            variant="contained"
                            color="success"
                            disabled={reviewingId === request.id}
                            onClick={() => handleReviewClaim(request.id, "approve")}
                          >
                            Duyệt
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            disabled={reviewingId === request.id}
                            onClick={() => handleReviewClaim(request.id, "reject")}
                          >
                            Từ chối
                          </Button>
                        </Stack>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
            <TextField
              size="small"
              label="Ghi chú duyệt (áp dụng lần duyệt tiếp theo)"
              value={reviewNote}
              onChange={(event) => setReviewNote(event.target.value)}
              fullWidth
              sx={{ mt: 2 }}
            />
          </CardContent>
        </Card>
      )}

      <Card>
        <CardContent>
          <TableContainer component={Paper} variant="outlined">
            <Table size="small">
              <TableHead>
                <TableRow>
                  <TableCell>ID</TableCell>
                  <TableCell>Tên cụm</TableCell>
                  {showVenueColumn && <TableCell>Tổ chức</TableCell>}
                  <TableCell>Địa chỉ</TableCell>
                  <TableCell>Số sân</TableCell>
                  <TableCell>Chủ sân</TableCell>
                  <TableCell>Trạng thái</TableCell>
                  <TableCell align="right">Thao tác</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {clusters.map((cluster) => (
                  <TableRow key={cluster.id} hover>
                    <TableCell>{cluster.id}</TableCell>
                    <TableCell>{cluster.name}</TableCell>
                    {showVenueColumn && (
                      <TableCell>
                        <Typography variant="caption" color="text.secondary">
                          {tenants.find((tenant) => tenant.id === cluster.venueId)?.name ||
                            cluster.venueId}
                        </Typography>
                      </TableCell>
                    )}
                    <TableCell sx={{ maxWidth: 240 }}>
                      <Typography variant="body2" noWrap title={cluster.address || "—"}>
                        {cluster.address || "—"}
                      </Typography>
                    </TableCell>
                    <TableCell>{cluster.courtCount || 0}</TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={isClusterAssigned(cluster.id) ? "Đã gán" : "Chưa gán"}
                        color={isClusterAssigned(cluster.id) ? "primary" : "warning"}
                        variant={isClusterAssigned(cluster.id) ? "filled" : "outlined"}
                      />
                    </TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={cluster.status === "active" ? "Hoạt động" : "Tạm dừng"}
                        color={cluster.status === "active" ? "success" : "default"}
                      />
                    </TableCell>
                    <TableCell align="right">
                      <Stack direction="row" spacing={0.5} justifyContent="flex-end" alignItems="center">
                        <Tooltip title="Chỉ đường Google Maps">
                          <span>
                            <IconButton
                              size="small"
                              color="primary"
                              disabled={!cluster.googleMapsUrl}
                              onClick={() => openClusterInGoogleMaps(cluster)}
                            >
                              <DirectionsIcon fontSize="small" />
                            </IconButton>
                          </span>
                        </Tooltip>
                        <Tooltip title="Thông tin cụm sân">
                          <span>
                            <IconButton size="small" color="primary" onClick={() => void openClusterInfoDialog(cluster)}>
                              <InfoOutlinedIcon fontSize="small" />
                            </IconButton>
                          </span>
                        </Tooltip>
                        <Button size="small" startIcon={<EditIcon />} onClick={() => openEditDialog(cluster)}>
                          Sửa
                        </Button>
                        <Button size="small" onClick={() => openAssignDialog(cluster.id)}>
                          Gán chủ
                        </Button>
                        <Button size="small" onClick={() => handleToggleStatus(cluster)}>
                          {cluster.status === "active" ? "Tạm dừng" : "Kích hoạt"}
                        </Button>
                        <Button
                          size="small"
                          color="error"
                          onClick={() => openDeleteConfirm(cluster)}
                        >
                          Xóa
                        </Button>
                      </Stack>
                    </TableCell>
                  </TableRow>
                ))}
                {clusters.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={showVenueColumn ? 8 : 7}>
                      <Typography variant="body2" color="text.secondary">
                        Chưa có cụm sân. Tạo cụm đầu tiên (vd. Nam Long, Nam Lý).
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </TableContainer>
        </CardContent>
      </Card>

      <Dialog open={createOpen} onClose={() => setCreateOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>Thêm cụm sân</DialogTitle>
        <DialogContent>{formFields}</DialogContent>
        <DialogActions>
          <Button onClick={() => setCreateOpen(false)}>Huỷ</Button>
          <Button variant="contained" onClick={handleCreate} disabled={createSaving || !form.name.trim()}>
            {createSaving ? "Đang tạo…" : "Tạo"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={editOpen} onClose={() => setEditOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>Sửa cụm sân</DialogTitle>
        <DialogContent>{formFields}</DialogContent>
        <DialogActions>
          <Button onClick={() => setEditOpen(false)}>Huỷ</Button>
          <Button variant="contained" onClick={handleEdit} disabled={editSaving || !form.name.trim()}>
            {editSaving ? "Đang lưu…" : "Lưu"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={assignOpen} onClose={() => setAssignOpen(false)} fullWidth maxWidth="sm">
        <DialogTitle>Gán chủ sân cho cụm</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ pt: 1 }}>
            <Autocomplete
              options={assignUsers}
              loading={assignUsersLoading}
              value={assignForm.user}
              onChange={(_event, nextUser) =>
                setAssignForm((prev) => ({ ...prev, user: nextUser }))
              }
              getOptionLabel={(option) =>
                `${option.displayName || option.email || option.id} (${option.email || option.id})`
              }
              isOptionEqualToValue={(option, value) => option.id === value?.id}
              renderInput={(params) => (
                <TextField
                  {...params}
                  label="Chủ sân"
                  placeholder="Tìm theo tên hoặc email"
                  helperText="Chọn tài khoản từ danh sách người dùng"
                  fullWidth
                />
              )}
            />
            <Typography variant="subtitle2">Cụm được gán</Typography>
            {clusters.map((cluster) => (
              <FormControlLabel
                key={cluster.id}
                control={
                  <Checkbox
                    checked={assignForm.clusterIds.includes(cluster.id)}
                    onChange={(event) => {
                      const checked = event.target.checked;
                      setAssignForm((prev) => ({
                        ...prev,
                        clusterIds: checked
                          ? [...prev.clusterIds, cluster.id]
                          : prev.clusterIds.filter((id) => id !== cluster.id),
                      }));
                    }}
                  />
                }
                label={`${cluster.name} (${cluster.id})`}
              />
            ))}
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setAssignOpen(false)}>Huỷ</Button>
          <Button
            variant="contained"
            onClick={handleAssign}
            disabled={assignSaving || !assignForm.user?.id || assignForm.clusterIds.length === 0}
          >
            {assignSaving ? "Đang lưu…" : "Lưu gán"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog
        open={infoOpen}
        onClose={() => {
          setInfoOpen(false);
          setInfoCluster(null);
          setOwnerUserId(null);
          setOwnerLoading(false);
          setOwnerError(null);
          setOwnerProfile(null);
        }}
        fullWidth
        maxWidth="sm"
      >
        <DialogTitle>Thông tin cụm sân</DialogTitle>
        <DialogContent>
          {!infoCluster ? (
            <Typography variant="body2" color="text.secondary">
              — 
            </Typography>
          ) : (
            <Stack spacing={1.5} sx={{ pt: 1 }}>
              <Box>
                <Typography variant="subtitle1" fontWeight={700}>
                  {infoCluster.name}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  ID: {infoCluster.id}
                </Typography>
              </Box>

              <Box>
                <Typography variant="body2" fontWeight={600}>
                  Địa chỉ
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {infoCluster.address || "—"}
                </Typography>
              </Box>

              <Stack direction="row" spacing={1.25} alignItems="center" flexWrap="wrap">
                <Typography variant="body2" color="text.secondary">
                  Số sân: <b>{infoCluster.courtCount || 0}</b>
                </Typography>
                <Chip
                  size="small"
                  label={infoCluster.status === "active" ? "Hoạt động" : "Tạm dừng"}
                  color={infoCluster.status === "active" ? "success" : "default"}
                />
              </Stack>

              <Box>
                <Typography variant="body2" fontWeight={600}>
                  Google Maps
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ wordBreak: "break-word" }}>
                  {infoCluster.googleMapsUrl || "—"}
                </Typography>
                <Box sx={{ mt: 1 }}>
                  <Button
                    size="small"
                    variant="outlined"
                    startIcon={<DirectionsIcon fontSize="small" />}
                    disabled={!infoCluster.googleMapsUrl}
                    onClick={() => openClusterInGoogleMaps(infoCluster)}
                    sx={{ textTransform: "none" }}
                  >
                    Chỉ đường
                  </Button>
                </Box>
              </Box>

              <Box>
                <Typography variant="body2" fontWeight={600}>
                  Chủ sở hữu (CLUSTER_OWNER)
                </Typography>
                {ownerLoading ? (
                  <Typography variant="body2" color="text.secondary">
                    Đang tải...
                  </Typography>
                ) : (
                  <Stack spacing={0.5} sx={{ mt: 0.5 }}>
                    <Stack direction="row" spacing={1} alignItems="center" flexWrap="wrap">
                      <Typography variant="body2" color="text.secondary">
                        ID chủ sân:
                      </Typography>
                      <Typography
                        variant="body2"
                        component="code"
                        sx={{ fontFamily: "monospace", wordBreak: "break-all" }}
                      >
                        {ownerUserId || "—"}
                      </Typography>
                      {ownerUserId && !ownerIdIsValid && (
                        <Chip size="small" color="warning" label="Legacy (email)" />
                      )}
                    </Stack>
                    <Typography variant="body2" color="text.secondary">
                      Tên hiển thị: <b>{ownerProfile?.displayName || "—"}</b>
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      SĐT: <b>{ownerProfile?.phone || "—"}</b>
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      Email: <b>{ownerProfile?.email || "—"}</b>
                    </Typography>
                    {hasClusterOwner && (
                      <Box sx={{ mt: 1 }}>
                        <Button
                          size="small"
                          color="error"
                          variant="outlined"
                          disabled={removeOwnerSaving}
                          onClick={() => setRemoveOwnerConfirmOpen(true)}
                        >
                          Xóa gán chủ sân
                        </Button>
                      </Box>
                    )}
                  </Stack>
                )}
                {ownerError && (
                  <Typography variant="caption" color="error" sx={{ display: "block", mt: 0.75 }}>
                    {ownerError}
                  </Typography>
                )}
              </Box>
            </Stack>
          )}
        </DialogContent>
        <DialogActions>
          <Button
            onClick={() => {
              setInfoOpen(false);
              setInfoCluster(null);
              setOwnerUserId(null);
              setOwnerLoading(false);
              setOwnerError(null);
              setOwnerProfile(null);
            }}
          >
            Đóng
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={removeOwnerConfirmOpen} onClose={() => setRemoveOwnerConfirmOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>Xóa gán chủ sân?</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary">
            Thao tác này gỡ chủ sân khỏi cụm <b>{infoCluster?.name}</b> trên cloud và trình duyệt.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRemoveOwnerConfirmOpen(false)}>Huỷ</Button>
          <Button color="error" variant="contained" onClick={handleRemoveOwner} disabled={removeOwnerSaving}>
            {removeOwnerSaving ? "Đang xóa…" : "Xóa gán"}
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={deleteConfirmOpen} onClose={() => setDeleteConfirmOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>Xóa cụm sân?</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary">
            Bạn sắp xóa cụm <b>{deleteTarget?.name}</b> khỏi hệ thống
            {deleteTarget?.venueId ? ` (tổ chức: ${deleteTarget.venueId})` : ""}. Thao tác không
            hoàn tác trên cloud.
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteConfirmOpen(false)}>Huỷ</Button>
          <Button color="error" variant="contained" onClick={handleDelete} disabled={deleteSaving}>
            {deleteSaving ? "Đang xóa…" : "Xóa cụm"}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Alert,
  Autocomplete,
  Box,
  Button,
  Checkbox,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControlLabel,
  MenuItem,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import { useAuth } from "../../context/AuthContext.jsx";
import { ROLES, normalizeRole } from "../../auth/roles.js";
import GovernanceMemberSelect from "../../components/club/GovernanceMemberSelect.jsx";
import { listClustersForVenue } from "../../features/court-cluster/services/courtClusterService.js";
import {
  cacheRegisterableClusterLocally,
  listRegisterableClusters,
} from "../../features/court-cluster/services/courtClusterDiscoveryService.js";
import { CLUB_STATUSES, listClubGovernanceCandidates, canSelfRegisterClub } from "../../features/club/index.js";
import { createClub, updateClub } from "../../features/club/index.js";

const SEARCH_DEBOUNCE_MS = 300;

const defaultForm = {
  name: "",
  code: "",
  description: "",
  status: CLUB_STATUSES.ACTIVE,
  presidentUserId: "",
  vicePresidentUserId: "",
  registeredClusterId: "",
  assignOwnerToCreator: true,
};

function clusterSearchLabel(cluster) {
  return cluster?.name || cluster?.id || "";
}

function clusterSearchSubtitle(cluster) {
  const venue = cluster?.venueName || cluster?.venueId || "";
  const address = cluster?.address || "";
  return [venue, address].filter(Boolean).join(" · ");
}

export default function ClubFormDialog({
  open,
  club,
  tenantId,
  initialRegisteredClusterId = "",
  lockRegisteredCluster = false,
  onClose,
  onSuccess,
}) {
  const { user } = useAuth();
  const [form, setForm] = useState(defaultForm);
  const [error, setError] = useState(null);
  const [saving, setSaving] = useState(false);
  const [clusterOptions, setClusterOptions] = useState([]);
  const [selectedCluster, setSelectedCluster] = useState(null);
  const [clusterSearchInput, setClusterSearchInput] = useState("");
  const [clusterSearch, setClusterSearch] = useState("");
  const [clusterLoading, setClusterLoading] = useState(false);

  const isEdit = Boolean(club?.id);
  const isCourtOwner = normalizeRole(user?.role) === ROLES.TENANT_OWNER;
  const isSelfRegister = canSelfRegisterClub(user);

  const localVenueClusters = useMemo(
    () => (tenantId ? listClustersForVenue(tenantId) : []),
    [tenantId, open]
  );

  const useCloudClusterPicker = !isEdit && (localVenueClusters.length === 0 || isSelfRegister);

  const governanceCandidates = useMemo(
    () => (isEdit && club?.id ? listClubGovernanceCandidates(club.id, tenantId) : []),
    [isEdit, club?.id, tenantId]
  );

  useEffect(() => {
    const timer = setTimeout(() => {
      setClusterSearch(clusterSearchInput.trim());
    }, SEARCH_DEBOUNCE_MS);
    return () => clearTimeout(timer);
  }, [clusterSearchInput]);

  const loadClusterOptions = useCallback(async () => {
    if (!open || isEdit) {
      return;
    }

    if (!useCloudClusterPicker) {
      setClusterOptions(localVenueClusters);
      return;
    }

    setClusterLoading(true);
    const result = await listRegisterableClusters({ search: clusterSearch });
    setClusterLoading(false);

    if (!result.ok) {
      setClusterOptions(localVenueClusters);
      return;
    }

    let options = result.clusters || [];
    if (tenantId) {
      options = options.filter((cluster) => cluster.venueId === tenantId);
    }
    if (options.length === 0 && localVenueClusters.length > 0) {
      options = localVenueClusters;
    }
    setClusterOptions(options);
  }, [open, isEdit, useCloudClusterPicker, clusterSearch, tenantId, localVenueClusters]);

  useEffect(() => {
    void loadClusterOptions();
  }, [loadClusterOptions]);

  useEffect(() => {
    if (!open) return;
    if (club) {
      setForm({
        name: club.name || "",
        code: club.code || "",
        description: club.description || "",
        status: club.status || CLUB_STATUSES.ACTIVE,
        presidentUserId: club.governance?.presidentUserId || "",
        vicePresidentUserId: club.governance?.vicePresidentUserId || "",
        registeredClusterId: club.governance?.registeredClusterId || "",
        assignOwnerToCreator: true,
      });
      const existing = localVenueClusters.find(
        (item) => item.id === club.governance?.registeredClusterId
      );
      setSelectedCluster(existing || null);
    } else {
      const clusterId = String(initialRegisteredClusterId || "").trim();
      setForm({
        ...defaultForm,
        presidentUserId: isSelfRegister ? user?.id || "" : "",
        registeredClusterId: clusterId,
        assignOwnerToCreator: isCourtOwner,
      });
      setSelectedCluster(null);
    }
    setError(null);
  }, [open, club, user, isSelfRegister, isCourtOwner, initialRegisteredClusterId, localVenueClusters]);

  useEffect(() => {
    if (!open || isEdit || !initialRegisteredClusterId) {
      return;
    }

    const match =
      clusterOptions.find((item) => item.id === initialRegisteredClusterId) ||
      localVenueClusters.find((item) => item.id === initialRegisteredClusterId);

    if (match) {
      setSelectedCluster(match);
      setForm((prev) => ({ ...prev, registeredClusterId: match.id }));
    }
  }, [open, isEdit, initialRegisteredClusterId, clusterOptions, localVenueClusters]);

  const handleClusterChange = (_event, value) => {
    setSelectedCluster(value);
    setForm((prev) => ({
      ...prev,
      registeredClusterId: value?.id || "",
    }));
  };

  const handleSubmit = async () => {
    setSaving(true);
    setError(null);

    const presidentUserId = form.presidentUserId.trim() || (isSelfRegister ? user?.id : "");
    if (!isEdit && !presidentUserId) {
      setSaving(false);
      setError("Chủ tịch CLB bắt buộc — nhập user ID Chủ tịch.");
      return;
    }

    const registeredClusterId = form.registeredClusterId.trim() || null;
    if (registeredClusterId && selectedCluster) {
      const cacheResult = await cacheRegisterableClusterLocally(selectedCluster);
      if (!cacheResult.ok) {
        setSaving(false);
        setError(cacheResult.error || "Không lưu được cụm sân đã chọn.");
        return;
      }
    }

    const governance = {
      presidentUserId: presidentUserId || club?.governance?.presidentUserId,
      ownerUserId: club?.governance?.ownerUserId ?? null,
      vicePresidentUserId: form.vicePresidentUserId.trim() || null,
      registeredClusterId,
    };

    const payload = {
      name: form.name.trim(),
      code: form.code.trim() || null,
      description: form.description.trim(),
      status: form.status,
      tenantId,
      assignOwnerToCreator: form.assignOwnerToCreator,
      governance,
    };

    const result = isEdit
      ? updateClub(club.id, payload, tenantId)
      : await createClub(payload);

    setSaving(false);

    if (!result.ok) {
      setError(result.error || "Không tạo được CLB.");
      return;
    }

    onSuccess?.(result.club, result);
  };

  const clusterPickerOptions = useCloudClusterPicker ? clusterOptions : localVenueClusters;

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>{isEdit ? "Chỉnh sửa CLB" : "Tạo CLB mới"}</DialogTitle>
      <DialogContent>
        <Stack spacing={2} sx={{ mt: 1 }}>
          {error && <Alert severity="error">{error}</Alert>}
          {!isEdit && isSelfRegister && (
            <Alert severity="info">
              Bạn sẽ là <strong>Chủ tịch CLB</strong>. CLB hoạt động ngay sau khi tạo.
            </Alert>
          )}
          <TextField
            label="Tên CLB"
            required
            value={form.name}
            onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
            error={Boolean(error && !form.name.trim())}
          />
          <TextField
            label="Mã CLB"
            value={form.code}
            onChange={(e) => setForm((f) => ({ ...f, code: e.target.value }))}
            helperText="Tùy chọn — không trùng trong cùng tenant"
          />
          <TextField
            label="Mô tả"
            multiline
            minRows={2}
            value={form.description}
            onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))}
          />
          {!isEdit && (
            <TextField
              label="User ID Chủ tịch"
              required
              value={form.presidentUserId}
              onChange={(e) => setForm((f) => ({ ...f, presidentUserId: e.target.value }))}
              helperText={
                isSelfRegister
                  ? "Mặc định là tài khoản của bạn"
                  : "Bắt buộc — auth user id của Chủ tịch CLB"
              }
              disabled={isSelfRegister}
            />
          )}
          {isEdit ? (
            <>
              <GovernanceMemberSelect
                label="Phó chủ tịch"
                value={form.vicePresidentUserId}
                onChange={(value) => setForm((f) => ({ ...f, vicePresidentUserId: value }))}
                candidates={governanceCandidates.filter(
                  (item) =>
                    item.userId !== (form.presidentUserId || club?.governance?.presidentUserId)
                )}
                allowEmpty
                emptyLabel="Không có"
              />
              <Typography variant="caption" color="text.secondary">
                Phó chủ tịch phải là vận động viên trong danh sách CLB.
              </Typography>
            </>
          ) : (
            <TextField
              label="User ID Phó chủ tịch"
              value={form.vicePresidentUserId}
              onChange={(e) => setForm((f) => ({ ...f, vicePresidentUserId: e.target.value }))}
              helperText="Tùy chọn — gán sau khi CLB có vận động viên"
            />
          )}
          {lockRegisteredCluster && selectedCluster ? (
            <TextField
              label="Cụm sân đăng ký"
              value={clusterSearchLabel(selectedCluster)}
              helperText={clusterSearchSubtitle(selectedCluster)}
              disabled
              fullWidth
            />
          ) : (
            <Autocomplete
              options={clusterPickerOptions}
              value={selectedCluster}
              onChange={handleClusterChange}
              inputValue={clusterSearchInput}
              onInputChange={(_event, value) => setClusterSearchInput(value)}
              getOptionLabel={clusterSearchLabel}
              isOptionEqualToValue={(option, value) => option?.id === value?.id}
              loading={clusterLoading}
              disabled={lockRegisteredCluster}
              noOptionsText={
                clusterLoading
                  ? "Đang tải..."
                  : clusterSearch
                    ? "Không tìm thấy cụm sân"
                    : "Gõ tên cụm sân để tìm"
              }
              renderInput={(params) => {
                const autocompleteInputProps = params.InputProps ?? {};

                return (
                  <TextField
                    {...params}
                    label="Cụm sân đăng ký"
                    placeholder="Tùy chọn — tìm theo tên cụm sân"
                    InputProps={{
                      ...autocompleteInputProps,
                      endAdornment: (
                        <>
                          {clusterLoading ? <CircularProgress color="inherit" size={18} /> : null}
                          {autocompleteInputProps.endAdornment}
                        </>
                      ),
                    }}
                  />
                );
              }}
              renderOption={(props, cluster) => (
                <li {...props} key={cluster.id}>
                  <Box>
                    <Typography variant="body2">{clusterSearchLabel(cluster)}</Typography>
                    {clusterSearchSubtitle(cluster) && (
                      <Typography variant="caption" color="text.secondary">
                        {clusterSearchSubtitle(cluster)}
                      </Typography>
                    )}
                  </Box>
                </li>
              )}
            />
          )}
          {!isEdit && isCourtOwner && (
            <FormControlLabel
              control={
                <Checkbox
                  checked={form.assignOwnerToCreator}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, assignOwnerToCreator: e.target.checked }))
                  }
                />
              }
              label="Tôi là Chủ sở hữu CLB"
            />
          )}
          {isEdit && (
            <TextField
              select
              label="Trạng thái"
              value={form.status}
              onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
            >
              <MenuItem value={CLUB_STATUSES.ACTIVE}>Đang hoạt động</MenuItem>
              <MenuItem value={CLUB_STATUSES.PENDING_SETUP}>Chờ thiết lập</MenuItem>
              <MenuItem value={CLUB_STATUSES.PENDING_APPROVAL}>Chờ chủ sân duyệt</MenuItem>
              <MenuItem value={CLUB_STATUSES.INACTIVE}>Vô hiệu hóa</MenuItem>
            </TextField>
          )}
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose} disabled={saving}>
          Hủy
        </Button>
        <Button variant="contained" onClick={() => void handleSubmit()} disabled={saving || !form.name.trim()}>
          {saving ? "Đang lưu..." : isEdit ? "Cập nhật" : "Tạo CLB"}
        </Button>
      </DialogActions>
    </Dialog>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  IconButton,
  MenuItem,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Tooltip,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import EditIcon from "@mui/icons-material/Edit";
import VisibilityIcon from "@mui/icons-material/Visibility";
import BlockIcon from "@mui/icons-material/Block";
import CloudSyncIcon from "@mui/icons-material/CloudSync";
import CloudDownloadIcon from "@mui/icons-material/CloudDownload";

import { useTenant } from "../../context/TenantContext.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { isPlatformScopedRole } from "../../auth/roles.js";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  CLUB_STATUSES,
  deactivateClub,
  getClubStats,
  getClubsVisibleToUser,
  canApproveClubRegistration,
  approveClubRegistration,
  rejectClubRegistration,
  isClubStorageV2Enabled,
} from "../../features/club/index.js";
import {
  ClubEmptyState,
  ClubFeedbackAlert,
  ClubPageShell,
  ClubRegistrySkeleton,
  ClubStatusBadge,
  clubRegistryPaperSx,
} from "../../features/club/ui/index.js";
import { CLUB_REGISTRY_SCOPE } from "../../features/club/registry/clubRegistryCache.js";
import { useClubRegistry } from "../../features/club/hooks/useClubRegistry.js";
import { syncClubRegistryForUser } from "../../features/club/services/clubRegistryCloudSync.js";
import { syncClubsForVenueToCloud } from "../../features/club/services/clubRegistryCloudService.js";
import ClubFormDialog from "./ClubFormDialog.jsx";
import ClubDeactivateDialog from "./ClubDeactivateDialog.jsx";

const SORT_OPTIONS = [
  { value: "name", label: "Tên CLB" },
  { value: "members", label: "Số thành viên" },
  { value: "elo", label: "ELO trung bình" },
  { value: "created", label: "Ngày tạo" },
];

export default function ClubListPage() {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const { currentTenantId, currentTenant, revision, refreshTenant, isSuperAdmin } = useTenant();
  const { can, rbacEnabled, isAuthenticated, user } = useAuth();

  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [sortBy, setSortBy] = useState("name");
  const [formOpen, setFormOpen] = useState(false);
  const [editClub, setEditClub] = useState(null);
  const [deactivateTarget, setDeactivateTarget] = useState(null);
  const [error, setError] = useState(null);
  const [message, setMessage] = useState(null);
  const [syncSaving, setSyncSaving] = useState(false);
  const [localRevision, setLocalRevision] = useState(0);

  const storageV2 = isClubStorageV2Enabled();
  const registryFilters = useMemo(
    () => ({
      search,
      status: statusFilter,
      includeInactive: statusFilter === "all",
    }),
    [search, statusFilter]
  );

  const registry = useClubRegistry({
    scope: CLUB_REGISTRY_SCOPE.TENANT,
    tenantId: storageV2 ? currentTenantId : null,
    filters: registryFilters,
    enabled: storageV2 && Boolean(currentTenantId) && isAuthenticated,
  });

  const canSyncCloud = !storageV2 && (isSuperAdmin || isPlatformScopedRole(user?.role));

  useEffect(() => {
    if (storageV2 || !isAuthenticated || !user?.id) {
      return;
    }
    void syncClubRegistryForUser(user).then((result) => {
      if (result.ok) {
        setLocalRevision((value) => value + 1);
      }
    });
  }, [isAuthenticated, storageV2, user, revision]);

  const canCreate =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.CLUB_CREATE, { venueId: currentTenantId, tenantId: currentTenantId });
  const canUpdate =
    !rbacEnabled ||
    !isAuthenticated ||
    can(PERMISSIONS.CLUB_UPDATE, { venueId: currentTenantId, tenantId: currentTenantId });

  const clubsWithStats = useMemo(() => {
    if (storageV2) {
      return (registry.clubs || []).map((row) => ({
        club: {
          id: row.id,
          name: row.name,
          code: row.code,
          status: row.status,
          createdAt: row.createdAt,
          tenantId: row.tenantId,
          governance: {
            ownerUserId: row._raw?.governance?.ownerUserId || row._raw?.owner_user_id,
            presidentUserId: row._raw?.governance?.presidentUserId || row._raw?.president_user_id,
          },
        },
        stats: {
          memberCount: row.memberCount ?? 0,
          avgElo: 0,
          tournamentCount: 0,
          ownerName: row.ownerName,
          presidentName: row.presidentName,
        },
      }));
    }

    const clubs = getClubsVisibleToUser(currentTenantId, user).filter((c) => !c.isDefault);
    return clubs.map((club) => ({
      club,
      stats: getClubStats(
        club.id,
        club.tenantId || club.venueId || currentTenantId
      ) || {
        memberCount: 0,
        avgElo: 0,
        tournamentCount: 0,
      },
    }));
  }, [currentTenantId, user, revision, localRevision, registry.clubs, storageV2]);

  useEffect(() => {
    if (searchParams.get("create") === "1" && canCreate) {
      setEditClub(null);
      setFormOpen(true);
      setSearchParams({}, { replace: true });
    }
  }, [searchParams, canCreate, setSearchParams]);

  const filtered = useMemo(() => {
    let rows = [...clubsWithStats];

    if (search.trim()) {
      const q = search.trim().toLowerCase();
      rows = rows.filter(
        ({ club }) =>
          club.name.toLowerCase().includes(q) ||
          String(club.code || "").toLowerCase().includes(q)
      );
    }

    if (statusFilter !== "all") {
      rows = rows.filter(({ club }) => club.status === statusFilter);
    }

    rows.sort((a, b) => {
      switch (sortBy) {
        case "members":
          return b.stats.memberCount - a.stats.memberCount;
        case "elo":
          return b.stats.avgElo - a.stats.avgElo;
        case "created":
          return new Date(b.club.createdAt) - new Date(a.club.createdAt);
        default:
          return a.club.name.localeCompare(b.club.name, "vi");
      }
    });

    return rows;
  }, [clubsWithStats, search, statusFilter, sortBy]);

  const bumpList = () => {
    if (storageV2) {
      void registry.invalidate();
    } else {
      setLocalRevision((v) => v + 1);
    }
    refreshTenant();
  };

  const handleFormSuccess = () => {
    setFormOpen(false);
    setEditClub(null);
    bumpList();
  };

  const handleDeactivate = () => {
    if (!deactivateTarget) return;
    const result = deactivateClub(deactivateTarget.id, currentTenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setDeactivateTarget(null);
    bumpList();
  };

  const handleApprove = (club) => {
    const result = approveClubRegistration(club.id, currentTenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    bumpList();
  };

  const handleReject = (club) => {
    const result = rejectClubRegistration(club.id, currentTenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    bumpList();
  };

  const handleSyncToCloud = async () => {
    setError(null);
    setMessage(null);
    setSyncSaving(true);

    const clubs = clubsWithStats.map(({ club }) => club);
    const result = await syncClubsForVenueToCloud({
      clubs,
      venueId: canSyncCloud ? null : currentTenantId,
      actor: user,
    });

    setSyncSaving(false);

    if (!result.ok) {
      setError(result.error || "Đồng bộ CLB lên cloud thất bại.");
      return;
    }

    let successText = `Đã đồng bộ ${result.synced ?? 0} CLB lên Supabase.`;
    if (result.skipped > 0) {
      successText += ` Bỏ qua ${result.skipped} CLB thiếu Chủ tịch UUID hợp lệ.`;
    }
    setMessage(successText);
    setLocalRevision((value) => value + 1);
    refreshTenant();
  };

  const handlePullFromCloud = async () => {
    setError(null);
    setMessage(null);
    setSyncSaving(true);

    const result = await syncClubRegistryForUser(user);
    setSyncSaving(false);

    if (!result.ok) {
      setError(result.error || "Không tải được danh sách CLB từ cloud.");
      return;
    }

    setMessage(
      `Đã tải ${result.pulled ?? 0} CLB từ cloud` +
        (result.pushed ? `, đẩy thêm ${result.pushed} CLB local.` : ".")
    );
    setLocalRevision((value) => value + 1);
    refreshTenant();
  };

  if (!currentTenantId) {
    return (
      <Alert severity="info">
        {isSuperAdmin || isPlatformScopedRole(user?.role)
          ? "Chọn tenant ở header trước khi quản lý sổ đăng ký CLB."
          : "Chưa xác định được tenant. Vui lòng đăng nhập hoặc liên hệ quản trị."}
      </Alert>
    );
  }

  if (storageV2 && registry.loading) {
    return (
      <ClubPageShell
        title="Quản lý CLB"
        subtitle={`Tenant: ${currentTenant?.name || currentTenantId}`}
        breadcrumbs={[
          { label: "Quản lý", href: "/manage/clubs" },
          { label: "Sổ đăng ký CLB" },
        ]}
        maxWidth={1400}
      >
        <ClubRegistrySkeleton />
      </ClubPageShell>
    );
  }

  if (storageV2 && registry.error) {
    return (
      <ClubPageShell
        title="Quản lý CLB"
        subtitle={`Tenant: ${currentTenant?.name || currentTenantId}`}
        breadcrumbs={[
          { label: "Quản lý", href: "/manage/clubs" },
          { label: "Sổ đăng ký CLB" },
        ]}
        maxWidth={1400}
      >
        <Alert
          severity="error"
          action={
            <Button color="inherit" size="small" onClick={() => void registry.reload()}>
              Thử lại
            </Button>
          }
        >
          {registry.error}
        </Alert>
      </ClubPageShell>
    );
  }

  const headerActions = (
    <Stack direction="row" spacing={1} alignItems="center" flexWrap="wrap">
      {canSyncCloud && (
        <>
          <Button
            variant="outlined"
            startIcon={<CloudDownloadIcon />}
            onClick={() => void handlePullFromCloud()}
            disabled={syncSaving}
          >
            {syncSaving ? "Đang tải…" : "Tải từ cloud"}
          </Button>
          <Button
            variant="outlined"
            startIcon={<CloudSyncIcon />}
            onClick={() => void handleSyncToCloud()}
            disabled={syncSaving || filtered.length === 0}
          >
            {syncSaving ? "Đang đồng bộ…" : "Đồng bộ lên cloud"}
          </Button>
        </>
      )}
      <PermissionGate permission={PERMISSIONS.CLUB_CREATE} scope={{ venueId: currentTenantId }}>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => {
            setEditClub(null);
            setFormOpen(true);
          }}
          disabled={!canCreate}
        >
          Tạo CLB mới
        </Button>
      </PermissionGate>
    </Stack>
  );

  return (
    <ClubPageShell
      title="Quản lý CLB"
      subtitle={`Tenant: ${currentTenant?.name || currentTenantId} · ${currentTenantId}`}
      breadcrumbs={[
        { label: "Quản lý", href: "/manage/clubs" },
        { label: "Sổ đăng ký CLB" },
      ]}
      actions={headerActions}
      maxWidth={1400}
    >
      <ClubFeedbackAlert
        message={message ? { type: "success", text: message } : null}
        onClose={() => setMessage(null)}
      />
      <ClubFeedbackAlert message={error ? { type: "error", text: error } : null} onClose={() => setError(null)} />

      <Paper sx={clubRegistryPaperSx}>
        <Stack direction={{ xs: "column", md: "row" }} spacing={2}>
          <TextField
            label="Tìm theo tên / mã CLB"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            size="small"
            fullWidth
          />
          <TextField
            select
            label="Trạng thái"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            size="small"
            sx={{ minWidth: 160 }}
          >
            <MenuItem value="all">Tất cả</MenuItem>
            <MenuItem value={CLUB_STATUSES.ACTIVE}>Đang hoạt động</MenuItem>
            <MenuItem value={CLUB_STATUSES.PENDING_SETUP}>Chờ thiết lập</MenuItem>
            <MenuItem value={CLUB_STATUSES.PENDING_APPROVAL}>Chờ chủ sân duyệt</MenuItem>
            <MenuItem value={CLUB_STATUSES.INACTIVE}>Vô hiệu hóa</MenuItem>
          </TextField>
          <TextField
            select
            label="Sắp xếp"
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            size="small"
            sx={{ minWidth: 180 }}
          >
            {SORT_OPTIONS.map((opt) => (
              <MenuItem key={opt.value} value={opt.value}>
                {opt.label}
              </MenuItem>
            ))}
          </TextField>
        </Stack>
      </Paper>

      {filtered.length === 0 ? (
        <ClubEmptyState
          preset={search || statusFilter !== "all" ? "registryFilter" : "registry"}
          actionLabel={canCreate && !search && statusFilter === "all" ? "Tạo CLB đầu tiên" : undefined}
          onAction={
            canCreate && !search && statusFilter === "all"
              ? () => {
                  setEditClub(null);
                  setFormOpen(true);
                }
              : undefined
          }
        />
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Tên CLB</TableCell>
                <TableCell>Mã</TableCell>
                {storageV2 && <TableCell>Chủ sở hữu</TableCell>}
                {storageV2 && <TableCell>Chủ tịch</TableCell>}
                <TableCell align="right">Thành viên</TableCell>
                {!storageV2 && <TableCell align="right">ELO TB</TableCell>}
                {!storageV2 && <TableCell align="right">Giải nội bộ</TableCell>}
                <TableCell>Trạng thái</TableCell>
                <TableCell>Ngày tạo</TableCell>
                <TableCell align="right">Thao tác</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {filtered.map(({ club, stats }) => (
                <TableRow key={club.id} hover>
                  <TableCell>{club.name}</TableCell>
                  <TableCell>{club.code || "—"}</TableCell>
                  {storageV2 && <TableCell>{stats.ownerName || "—"}</TableCell>}
                  {storageV2 && <TableCell>{stats.presidentName || "—"}</TableCell>}
                  <TableCell align="right">{stats.memberCount}</TableCell>
                  {!storageV2 && <TableCell align="right">{stats.avgElo || "—"}</TableCell>}
                  {!storageV2 && <TableCell align="right">{stats.tournamentCount}</TableCell>}
                  <TableCell>
                    <ClubStatusBadge status={club.status} />
                  </TableCell>
                  <TableCell>
                    {new Date(club.createdAt).toLocaleDateString("vi-VN")}
                  </TableCell>
                  <TableCell align="right">
                    <Tooltip title="Xem chi tiết">
                      <IconButton size="small" onClick={() => navigate(`/manage/clubs/${club.id}`)}>
                        <VisibilityIcon fontSize="small" />
                      </IconButton>
                    </Tooltip>
                    {canApproveClubRegistration(user, club) && (
                      <>
                        <Tooltip title="Duyệt CLB">
                          <Button
                            size="small"
                            variant="outlined"
                            sx={{ ml: 0.5 }}
                            onClick={() => handleApprove(club)}
                          >
                            Duyệt
                          </Button>
                        </Tooltip>
                        <Tooltip title="Từ chối">
                          <Button
                            size="small"
                            color="inherit"
                            sx={{ ml: 0.5 }}
                            onClick={() => handleReject(club)}
                          >
                            Từ chối
                          </Button>
                        </Tooltip>
                      </>
                    )}
                    {canUpdate && (
                      <>
                        <Tooltip title="Chỉnh sửa">
                          <IconButton
                            size="small"
                            onClick={() => {
                              setEditClub(club);
                              setFormOpen(true);
                            }}
                          >
                            <EditIcon fontSize="small" />
                          </IconButton>
                        </Tooltip>
                        {club.status === CLUB_STATUSES.ACTIVE && (
                          <Tooltip title="Vô hiệu hóa">
                            <IconButton
                              size="small"
                              color="warning"
                              onClick={() => setDeactivateTarget(club)}
                            >
                              <BlockIcon fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        )}
                      </>
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <ClubFormDialog
        open={formOpen}
        club={editClub}
        tenantId={currentTenantId}
        onClose={() => {
          setFormOpen(false);
          setEditClub(null);
        }}
        onSuccess={handleFormSuccess}
      />

      <ClubDeactivateDialog
        open={Boolean(deactivateTarget)}
        club={deactivateTarget}
        onClose={() => setDeactivateTarget(null)}
        onConfirm={handleDeactivate}
      />
    </ClubPageShell>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  IconButton,
  MenuItem,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Tooltip,
  Typography,
} from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import PersonRemoveIcon from "@mui/icons-material/PersonRemove";

import { useAuth } from "../../../context/AuthContext.jsx";
import { PERMISSIONS } from "../../../auth/permissions.js";
import {
  CLUB_MEMBER_ROLE_LABELS,
  CLUB_MEMBER_STATUSES,
  addMemberToClub,
  getClubMembers,
  getClubRatings,
  getTenantPlayers,
  removeMemberFromClub,
  updateClubMemberRole,
  updateClubMemberStatus,
  canViewFullClubMembers,
  canDeleteClubMembers,
  canApproveClubMembershipRequests,
  listPendingMembershipRequests,
  approveClubMembershipRequest,
  rejectClubMembershipRequest,
} from "../../../features/club/index.js";
import { formatPickVnRating } from "../../../features/pick-vn-rating/constants/pickVnRatingScale.js";
import { writeAuditLog, AUDIT_ACTIONS } from "../../../features/identity/services/auditService.js";
import { getCurrentUser } from "../../../auth/authService.js";

export default function ClubMembersTab({ club, tenantId, onRefresh }) {
  const { can, rbacEnabled, isAuthenticated, user } = useAuth();
  const [addOpen, setAddOpen] = useState(false);
  const [selectedPlayerId, setSelectedPlayerId] = useState("");
  const [error, setError] = useState(null);
  const [removeTarget, setRemoveTarget] = useState(null);
  const [revision, setRevision] = useState(0);
  const [reviewNotes, setReviewNotes] = useState({});
  const [requestMessage, setRequestMessage] = useState(null);
  const [pendingMembershipRequests, setPendingMembershipRequests] = useState([]);
  const [loadingPendingRequests, setLoadingPendingRequests] = useState(false);

  const fullAccess = canViewFullClubMembers(user, club);
  const canApproveRequests = canApproveClubMembershipRequests(user, club);

  useEffect(() => {
    let cancelled = false;

    async function loadPending() {
      if (!canApproveRequests) {
        setPendingMembershipRequests([]);
        return;
      }

      setLoadingPendingRequests(true);
      try {
        const rows = await listPendingMembershipRequests(club.id, tenantId, user);
        if (!cancelled) {
          setPendingMembershipRequests(rows);
        }
      } finally {
        if (!cancelled) {
          setLoadingPendingRequests(false);
        }
      }
    }

    loadPending();
    return () => {
      cancelled = true;
    };
  }, [club.id, tenantId, user, revision, canApproveRequests]);

  const canManage =
    fullAccess &&
    (!rbacEnabled ||
      !isAuthenticated ||
      can(PERMISSIONS.PLAYER_UPDATE, { clubId: club.id, venueId: tenantId }));

  const canRemoveMembers = canDeleteClubMembers(user, club) && canManage;

  const members = useMemo(
    () => getClubMembers(club.id, tenantId),
    [club.id, tenantId, revision]
  );

  const ratings = useMemo(
    () => getClubRatings(club.id, tenantId),
    [club.id, tenantId, revision]
  );

  const playersById = useMemo(() => {
    const players = getTenantPlayers(tenantId);
    return new Map(players.map((p) => [p.id, p]));
  }, [tenantId, revision]);

  const ratingByPlayer = useMemo(
    () => new Map(ratings.map((r) => [r.playerId, r])),
    [ratings]
  );

  const existingMemberIds = useMemo(
    () => new Set(members.filter((m) => m.status === CLUB_MEMBER_STATUSES.ACTIVE).map((m) => m.playerId)),
    [members]
  );

  const availablePlayers = useMemo(
    () => getTenantPlayers(tenantId).filter((p) => !existingMemberIds.has(p.id)),
    [tenantId, existingMemberIds, revision]
  );

  const handleAdd = () => {
    const result = addMemberToClub(club.id, selectedPlayerId, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setAddOpen(false);
    setSelectedPlayerId("");
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleRemove = () => {
    if (!removeTarget) return;
    const result = removeMemberFromClub(club.id, removeTarget.playerId, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setRemoveTarget(null);
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleRoleChange = (playerId, role) => {
    const result = updateClubMemberRole(club.id, playerId, role, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleStatusToggle = (member) => {
    const nextStatus =
      member.status === CLUB_MEMBER_STATUSES.ACTIVE
        ? CLUB_MEMBER_STATUSES.INACTIVE
        : CLUB_MEMBER_STATUSES.ACTIVE;
    const result = updateClubMemberStatus(club.id, member.playerId, nextStatus, tenantId);
    if (!result.ok) {
      setError(result.error);
      return;
    }
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleApproveRequest = async (request) => {
    const result = await approveClubMembershipRequest(club.id, request.id, tenantId, {
      user,
      reviewNote: reviewNotes[request.id] || "",
    });

    if (!result.ok) {
      setRequestMessage({ type: "error", text: result.error });
      return;
    }

    await writeAuditLog({
      action: AUDIT_ACTIONS.UPDATE,
      resourceType: "club_membership_request",
      resourceId: request.id,
      clubId: club.id,
      metadata: {
        status: "approved",
        userId: request.userId,
        playerId: result.player?.id,
      },
      actor: getCurrentUser(),
    });

    setRequestMessage({ type: "success", text: "Đã duyệt yêu cầu tham gia CLB." });
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  const handleRejectRequest = async (request) => {
    const result = await rejectClubMembershipRequest(club.id, request.id, tenantId, {
      user,
      reviewNote: reviewNotes[request.id] || "",
    });

    if (!result.ok) {
      setRequestMessage({ type: "error", text: result.error });
      return;
    }

    await writeAuditLog({
      action: AUDIT_ACTIONS.UPDATE,
      resourceType: "club_membership_request",
      resourceId: request.id,
      clubId: club.id,
      metadata: {
        status: "rejected",
        userId: request.userId,
      },
      actor: getCurrentUser(),
    });

    setRequestMessage({ type: "info", text: "Đã từ chối yêu cầu tham gia." });
    setRevision((v) => v + 1);
    onRefresh?.();
  };

  return (
    <Box>
      {!fullAccess && (
        <Alert severity="info" sx={{ mb: 2 }}>
          Bạn không có quyền xem danh sách thành viên CLB này. Chỉ Chủ tịch / Chủ sở hữu CLB mới
          xem được chi tiết.
        </Alert>
      )}

      {fullAccess && error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {fullAccess && (
        <>
      {canApproveRequests && requestMessage && (
        <Alert
          severity={requestMessage.type}
          sx={{ mb: 2 }}
          onClose={() => setRequestMessage(null)}
        >
          {requestMessage.text}
        </Alert>
      )}

      {canApproveRequests && (
        <Box sx={{ mb: 3 }}>
          <Typography variant="subtitle1" fontWeight={600} gutterBottom>
            Yêu cầu tham gia ({pendingMembershipRequests.length})
          </Typography>
          {pendingMembershipRequests.length === 0 ? (
            <Paper sx={{ p: 2 }}>
              <Typography color="text.secondary" variant="body2">
                Không có yêu cầu đang chờ duyệt.
              </Typography>
            </Paper>
          ) : (
            <TableContainer component={Paper}>
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>VĐV</TableCell>
                    <TableCell>Pick_VN</TableCell>
                    <TableCell>Ngày gửi</TableCell>
                    <TableCell>Lời nhắn</TableCell>
                    <TableCell>Ghi chú duyệt</TableCell>
                    <TableCell align="right">Thao tác</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {pendingMembershipRequests.map((request) => (
                    <TableRow key={request.id} hover>
                      <TableCell>{request.displayName || request.userId}</TableCell>
                      <TableCell>
                        {request.pickVnRating != null
                          ? formatPickVnRating(request.pickVnRating)
                          : "—"}
                      </TableCell>
                      <TableCell>
                        {new Date(request.requestedAt).toLocaleDateString("vi-VN")}
                      </TableCell>
                      <TableCell>{request.message || "—"}</TableCell>
                      <TableCell sx={{ minWidth: 180 }}>
                        <TextField
                          size="small"
                          fullWidth
                          placeholder="Ghi chú"
                          value={reviewNotes[request.id] || ""}
                          onChange={(event) =>
                            setReviewNotes((prev) => ({
                              ...prev,
                              [request.id]: event.target.value,
                            }))
                          }
                        />
                      </TableCell>
                      <TableCell align="right">
                        <Stack direction="row" spacing={1} justifyContent="flex-end">
                          <Button
                            size="small"
                            color="success"
                            variant="contained"
                            onClick={() => handleApproveRequest(request)}
                          >
                            Duyệt
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            variant="outlined"
                            onClick={() => handleRejectRequest(request)}
                          >
                            Từ chối
                          </Button>
                        </Stack>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          )}
        </Box>
      )}

      <Stack direction="row" justifyContent="space-between" mb={2}>
        <Typography variant="subtitle1" fontWeight={600}>
          {members.length} thành viên
        </Typography>
        {canManage && (
          <Button startIcon={<AddIcon />} variant="contained" size="small" onClick={() => setAddOpen(true)}>
            Thêm thành viên
          </Button>
        )}
      </Stack>

      {members.length === 0 ? (
        <Paper sx={{ p: 3, textAlign: "center" }}>
          <Typography color="text.secondary">CLB chưa có thành viên.</Typography>
        </Paper>
      ) : (
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Tên</TableCell>
                <TableCell>SĐT</TableCell>
                <TableCell>Giới tính</TableCell>
                <TableCell>Level</TableCell>
                <TableCell align="right">ELO</TableCell>
                <TableCell>Vai trò</TableCell>
                <TableCell>Ngày tham gia</TableCell>
                <TableCell>Trạng thái</TableCell>
                    {canRemoveMembers && (
                      <TableCell align="right">Thao tác</TableCell>
                    )}
              </TableRow>
            </TableHead>
            <TableBody>
              {members.map((member) => {
                const player = playersById.get(member.playerId);
                const rating = ratingByPlayer.get(member.playerId);
                return (
                  <TableRow key={member.id} hover>
                    <TableCell>{player?.name || member.playerId}</TableCell>
                    <TableCell>{player?.phone || "—"}</TableCell>
                    <TableCell>{player?.gender || "—"}</TableCell>
                    <TableCell>{player?.level ?? rating?.level ?? "—"}</TableCell>
                    <TableCell align="right">{rating?.elo ?? "—"}</TableCell>
                    <TableCell>
                      {canManage ? (
                        <TextField
                          select
                          size="small"
                          value={member.role}
                          onChange={(e) => handleRoleChange(member.playerId, e.target.value)}
                          sx={{ minWidth: 120 }}
                        >
                          {Object.entries(CLUB_MEMBER_ROLE_LABELS).map(([value, label]) => (
                            <MenuItem key={value} value={value}>
                              {label}
                            </MenuItem>
                          ))}
                        </TextField>
                      ) : (
                        CLUB_MEMBER_ROLE_LABELS[member.role] || member.role
                      )}
                    </TableCell>
                    <TableCell>
                      {new Date(member.joinedAt).toLocaleDateString("vi-VN")}
                    </TableCell>
                    <TableCell>
                      <Chip
                        size="small"
                        label={member.status === CLUB_MEMBER_STATUSES.ACTIVE ? "Active" : "Inactive"}
                        color={member.status === CLUB_MEMBER_STATUSES.ACTIVE ? "success" : "default"}
                        onClick={canManage ? () => handleStatusToggle(member) : undefined}
                      />
                    </TableCell>
                    {canRemoveMembers && (
                      <TableCell align="right">
                        {member.status === CLUB_MEMBER_STATUSES.ACTIVE && (
                          <Tooltip title="Xóa khỏi CLB">
                            <IconButton size="small" color="error" onClick={() => setRemoveTarget(member)}>
                              <PersonRemoveIcon fontSize="small" />
                            </IconButton>
                          </Tooltip>
                        )}
                      </TableCell>
                    )}
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={addOpen} onClose={() => setAddOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Thêm thành viên</DialogTitle>
        <DialogContent>
          <TextField
            select
            fullWidth
            label="Chọn player"
            value={selectedPlayerId}
            onChange={(e) => setSelectedPlayerId(e.target.value)}
            sx={{ mt: 1 }}
          >
            {availablePlayers.length === 0 && (
              <MenuItem disabled>Không còn player khả dụng trong tenant</MenuItem>
            )}
            {availablePlayers.map((p) => (
              <MenuItem key={p.id} value={p.id}>
                {p.name} {p.phone ? `— ${p.phone}` : ""}
              </MenuItem>
            ))}
          </TextField>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setAddOpen(false)}>Hủy</Button>
          <Button variant="contained" disabled={!selectedPlayerId} onClick={handleAdd}>
            Thêm
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog open={Boolean(removeTarget)} onClose={() => setRemoveTarget(null)}>
        <DialogTitle>Xóa thành viên</DialogTitle>
        <DialogContent>
          <Typography>
            Xóa{" "}
            <strong>{playersById.get(removeTarget?.playerId)?.name || removeTarget?.playerId}</strong>{" "}
            khỏi CLB?
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setRemoveTarget(null)}>Hủy</Button>
          <Button color="error" variant="contained" onClick={handleRemove}>
            Xóa
          </Button>
        </DialogActions>
      </Dialog>
        </>
      )}
    </Box>
  );
}

import { Box, Chip, Stack, Typography } from "@mui/material";

import { CALENDAR_CELL_TONES, CALENDAR_LEGEND_ITEMS } from "./courtCalendarTokens.js";

export default function CourtCalendarLegend() {
  return (
    <Stack direction="row" spacing={1} flexWrap="wrap" sx={{ mt: 2 }}>
      {CALENDAR_LEGEND_ITEMS.map((tone) => {
        const token = CALENDAR_CELL_TONES[tone];
        return (
          <Chip
            key={tone}
            size="small"
            label={token.label}
            sx={{
              bgcolor: token.bg,
              color: token.color,
              border: `1px solid ${token.border}`,
              fontWeight: 600,
            }}
          />
        );
      })}
    </Stack>
  );
}

import { useMemo, useState } from "react";

import {
  Box,
  Chip,
  Drawer,
  List,
  ListItemButton,
  ListItemText,
  Paper,
  Stack,
  Typography,
} from "@mui/material";

import { getCourtDisplayName } from "../../../models/court.js";
import { getBookingsByDate, getWeekDates } from "../../../domain/courtBookingEngine.js";
import { isActiveBookingStatus } from "../../../models/booking.js";
import { formatDisplayDate } from "../courtManagement.constants.js";
import { CALENDAR_SHELL } from "./courtCalendarTokens.js";

const WEEKDAY_SHORT = ["T2", "T3", "T4", "T5", "T6", "T7", "CN"];

function OccupancyDots({ bookings, openHour = 6, closeHour = 22 }) {
  const peakHours = 8;
  const startHour = Math.max(openHour, 8);
  const dots = [];

  for (let index = 0; index < peakHours; index += 1) {
    const hour = startHour + index;
    const hasBooking = bookings.some((booking) => {
      const start = Number(booking.startTime?.slice(0, 2));
      const end = Number(booking.endTime?.slice(0, 2));
      return hour >= start && hour < end;
    });
    dots.push(hasBooking);
  }

  return (
    <Stack direction="row" spacing={0.4} sx={{ mt: 0.75 }}>
      {dots.map((active, index) => (
        <Box
          key={index}
          sx={{
            width: 8,
            height: 8,
            borderRadius: "50%",
            bgcolor: active ? CALENDAR_SHELL.primary : "action.hover",
          }}
        />
      ))}
    </Stack>
  );
}

export default function CourtCalendarWeekMatrix({
  courts = [],
  bookings = [],
  anchorDate,
  openHour = 6,
  closeHour = 22,
  onOpenDay,
  onBookingClick,
}) {
  const weekDates = useMemo(() => getWeekDates(anchorDate), [anchorDate]);
  const [drawer, setDrawer] = useState(null);

  const cellBookings = useMemo(() => {
    const map = new Map();

    courts.forEach((court) => {
      weekDates.forEach((date) => {
        const key = `${court.id}-${date}`;
        const dayBookings = getBookingsByDate(bookings, date)
          .filter((booking) => booking.courtId === court.id)
          .filter((booking) => isActiveBookingStatus(booking.bookingStatus));
        map.set(key, dayBookings);
      });
    });

    return map;
  }, [bookings, courts, weekDates]);

  return (
    <Box>
      <Paper
        elevation={0}
        sx={{
          border: CALENDAR_SHELL.cardBorder,
          borderRadius: `${CALENDAR_SHELL.cardRadius}px`,
          boxShadow: CALENDAR_SHELL.cardShadow,
          overflow: "auto",
        }}
      >
        <Box
          sx={{
            display: "grid",
            gridTemplateColumns: `160px repeat(7, minmax(120px, 1fr))`,
            minWidth: 900,
          }}
        >
          <Box
            sx={{
              p: 1.25,
              fontWeight: 700,
              borderBottom: 1,
              borderRight: 1,
              borderColor: "divider",
              bgcolor: "background.paper",
              position: "sticky",
              left: 0,
              zIndex: 2,
            }}
          >
            Sân
          </Box>

          {weekDates.map((date, index) => (
            <Box
              key={date}
              sx={{
                p: 1,
                borderBottom: 1,
                borderRight: 1,
                borderColor: "divider",
                bgcolor: "background.paper",
                textAlign: "center",
              }}
            >
              <Typography variant="caption" color="text.secondary" display="block">
                {WEEKDAY_SHORT[index]}
              </Typography>
              <Typography variant="subtitle2" fontWeight={700}>
                {formatDisplayDate(date)}
              </Typography>
            </Box>
          ))}

          {courts.map((court, courtIndex) => (
            <Box key={court.id} sx={{ display: "contents" }}>
              <Box
                sx={{
                  p: 1.25,
                  borderBottom: 1,
                  borderRight: 1,
                  borderColor: "divider",
                  bgcolor: "background.paper",
                  position: "sticky",
                  left: 0,
                  zIndex: 1,
                }}
              >
                <Typography variant="subtitle2" fontWeight={700}>
                  {getCourtDisplayName(court, courtIndex)}
                </Typography>
              </Box>

              {weekDates.map((date) => {
                const key = `${court.id}-${date}`;
                const dayBookings = cellBookings.get(key) || [];
                const visible = dayBookings.slice(0, 2);
                const overflow = dayBookings.length - visible.length;

                return (
                  <Box
                    key={key}
                    onClick={() =>
                      setDrawer({
                        court,
                        date,
                        bookings: dayBookings,
                      })
                    }
                    sx={{
                      p: 1,
                      borderBottom: 1,
                      borderRight: 1,
                      borderColor: "divider",
                      minHeight: 96,
                      cursor: "pointer",
                      transition: "background-color 0.15s",
                      "&:hover": { bgcolor: "rgba(16, 185, 129, 0.06)" },
                    }}
                  >
                    <OccupancyDots bookings={dayBookings} openHour={openHour} closeHour={closeHour} />
                    <Stack spacing={0.5} sx={{ mt: 0.75 }}>
                      {visible.map((booking) => (
                        <Chip
                          key={booking.id}
                          size="small"
                          label={`${booking.startTime} ${booking.customerName}`}
                          onClick={(event) => {
                            event.stopPropagation();
                            onBookingClick?.(booking);
                          }}
                          sx={{
                            justifyContent: "flex-start",
                            height: "auto",
                            py: 0.5,
                            "& .MuiChip-label": { whiteSpace: "normal" },
                          }}
                        />
                      ))}
                      {overflow > 0 && (
                        <Typography variant="caption" color="primary.main" fontWeight={700}>
                          +{overflow} booking
                        </Typography>
                      )}
                      {dayBookings.length === 0 && (
                        <Typography variant="caption" color="text.secondary">
                          Trống
                        </Typography>
                      )}
                    </Stack>
                  </Box>
                );
              })}
            </Box>
          ))}
        </Box>
      </Paper>

      <Drawer
        anchor="right"
        open={Boolean(drawer)}
        onClose={() => setDrawer(null)}
        PaperProps={{ sx: { width: { xs: "100%", sm: 380 } } }}
      >
        {drawer && (
          <Box sx={{ p: 2 }}>
            <Typography variant="h6" fontWeight={800}>
              {getCourtDisplayName(drawer.court)}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              {formatDisplayDate(drawer.date)}
            </Typography>

            <List dense>
              {drawer.bookings.length === 0 ? (
                <Typography color="text.secondary">Không có booking.</Typography>
              ) : (
                drawer.bookings.map((booking) => (
                  <ListItemButton
                    key={booking.id}
                    onClick={() => {
                      onBookingClick?.(booking);
                      setDrawer(null);
                    }}
                  >
                    <ListItemText
                      primary={booking.customerName}
                      secondary={`${booking.startTime} – ${booking.endTime}`}
                    />
                  </ListItemButton>
                ))
              )}
            </List>

            <Chip
              label="Xem theo ngày"
              color="primary"
              onClick={() => {
                onOpenDay?.(drawer.date);
                setDrawer(null);
              }}
              sx={{ mt: 2, fontWeight: 700 }}
            />
          </Box>
        )}
      </Drawer>
    </Box>
  );
}

