import { useEffect, useMemo, useState } from "react";
import { Link as RouterLink } from "react-router-dom";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  FormControl,
  FormControlLabel,
  FormLabel,
  Grid,
  Paper,
  Radio,
  RadioGroup,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import GroupsIcon from "@mui/icons-material/Groups";
import ChevronRightIcon from "@mui/icons-material/ChevronRight";

import { useAuth } from "../../context/AuthContext.jsx";
import { useTenant } from "../../context/TenantContext.jsx";
import { ROLE_LABELS } from "../../auth/roles.js";
import { resolveSelfProfileRoleLabel } from "../../features/identity/utils/selfProfileVariant.js";
import {
  fetchSelfProfile,
  updateSelfProfile,
  updateSelfDemographics,
} from "../../features/identity/services/selfProfileService.js";
import { changePassword } from "../../features/identity/services/passwordService.js";
import AvatarPicker from "../../features/identity/components/AvatarPicker.jsx";
import AthleteRatingSummary from "../../features/pick-vn-rating/components/AthleteRatingSummary.jsx";
import PickVnRatingBadge from "../../features/pick-vn-rating/components/PickVnRatingBadge.jsx";
import { getPickVnRatingByAuthUserId } from "../../features/pick-vn-rating/services/pickVnRatingService.js";
import { RATING_STATUS } from "../../features/pick-vn-rating/constants/ratingStatus.js";
import { getMyClubSummary } from "../../features/club/services/clubMembershipRequestService.js";
import { CLUB_STATUS_LABELS } from "../../features/club/constants/clubStatus.js";

const GENDER_OPTIONS = [
  { value: "Nam", label: "Nam" },
  { value: "Nữ", label: "Nữ" },
  { value: "Khác", label: "Khác" },
];

const CURRENT_YEAR = new Date().getFullYear();

export default function AthleteSelfProfilePage() {
  const { user, refresh } = useAuth();
  const { currentTenantId } = useTenant();

  const [displayName, setDisplayName] = useState("");
  const [phone, setPhone] = useState("");
  const [gender, setGender] = useState("");
  const [birthYear, setBirthYear] = useState("");
  const [avatarUrl, setAvatarUrl] = useState("");
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState(null);
  const [loading, setLoading] = useState(false);
  const [ratingTick, setRatingTick] = useState(0);

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      const result = await fetchSelfProfile();
      if (cancelled || !result.ok) {
        return;
      }
      setDisplayName(result.user.displayName || "");
      setPhone(result.user.phone || "");
      setGender(result.user.gender || "");
      setBirthYear(result.user.birthYear ? String(result.user.birthYear) : "");
      setAvatarUrl(result.user.avatarUrl || "");
    };

    load();
    return () => {
      cancelled = true;
    };
  }, [user?.id]);

  const ratingRecord = useMemo(() => {
    void ratingTick;
    return user?.id ? getPickVnRatingByAuthUserId(user.id) : null;
  }, [ratingTick, user?.id]);

  const clubSummary = useMemo(() => {
    if (!user?.clubId) {
      return null;
    }
    return getMyClubSummary(user.clubId, currentTenantId);
  }, [currentTenantId, user?.clubId]);

  const handleSaveProfile = async () => {
    setLoading(true);
    setMessage(null);

    const profileResult = await updateSelfProfile({ displayName, phone, avatarUrl });
    if (!profileResult.ok) {
      setLoading(false);
      setMessage({ type: "error", text: profileResult.error });
      return;
    }

    const demoResult = await updateSelfDemographics({
      gender,
      birthYear: birthYear ? Number(birthYear) : null,
    });

    setLoading(false);

    if (!demoResult.ok) {
      setMessage({ type: "error", text: demoResult.error });
      return;
    }

    refresh();
    setRatingTick((value) => value + 1);
    setMessage({ type: "success", text: "Đã cập nhật hồ sơ." });
  };

  const handleChangePassword = async () => {
    if (newPassword !== confirmPassword) {
      setMessage({ type: "error", text: "Mật khẩu xác nhận không khớp." });
      return;
    }

    setLoading(true);
    setMessage(null);
    const result = await changePassword({ currentPassword, newPassword });
    setLoading(false);

    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    setCurrentPassword("");
    setNewPassword("");
    setConfirmPassword("");
    setMessage({ type: "success", text: result.message });
  };

  if (!user) {
    return <Alert severity="warning">Vui lòng đăng nhập để xem hồ sơ.</Alert>;
  }

  const hasRating =
    ratingRecord &&
    ratingRecord.ratingStatus !== RATING_STATUS.UNRATED &&
    ratingRecord.currentRating != null;

  const roleLabel =
    resolveSelfProfileRoleLabel(user) || ROLE_LABELS[user.role] || "Vận động viên";

  return (
    <Box>
      <Typography variant="h4" fontWeight={800} gutterBottom>
        Hồ sơ của tôi
      </Typography>

      {message && (
        <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      )}

      <Grid container spacing={2}>
        <Grid item xs={12} md={4}>
          <Paper variant="outlined" sx={{ p: 2, position: { md: "sticky" }, top: 88 }}>
            <Stack spacing={2} alignItems="center">
              <AvatarPicker
                user={user}
                avatarUrl={avatarUrl}
                onAvatarUrlChange={setAvatarUrl}
                onAvatarUpdated={() => {
                  refresh();
                  setMessage({ type: "success", text: "Đã cập nhật hình đại diện." });
                }}
                disabled={loading}
              />
              <Box sx={{ textAlign: "center", width: "100%" }}>
                <Typography variant="h6" fontWeight={700}>
                  {displayName || user.displayName || "Vận động viên"}
                </Typography>
                <Chip
                  size="small"
                  color="primary"
                  label={roleLabel}
                  sx={{ mt: 0.5 }}
                />
                {clubSummary?.name && (
                  <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                    {clubSummary.name}
                  </Typography>
                )}
              </Box>
              {hasRating && (
                <PickVnRatingBadge
                  rating={ratingRecord.currentRating}
                  status={ratingRecord.ratingStatus}
                  confidence={ratingRecord.ratingConfidence}
                  size="medium"
                />
              )}
            </Stack>
          </Paper>
        </Grid>

        <Grid item xs={12} md={8}>
          <Stack spacing={2}>
            <Card>
              <CardContent>
                <Typography variant="h6" fontWeight={700} gutterBottom>
                  Thông tin cá nhân
                </Typography>
                <Stack spacing={2}>
                  <TextField
                    label="Họ tên"
                    value={displayName}
                    onChange={(e) => setDisplayName(e.target.value)}
                    fullWidth
                  />
                  <TextField
                    label="Số điện thoại"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    fullWidth
                  />
                  <FormControl>
                    <FormLabel>Giới tính</FormLabel>
                    <RadioGroup
                      row
                      value={gender}
                      onChange={(e) => setGender(e.target.value)}
                    >
                      {GENDER_OPTIONS.map((option) => (
                        <FormControlLabel
                          key={option.value}
                          value={option.value}
                          control={<Radio size="small" />}
                          label={option.label}
                        />
                      ))}
                    </RadioGroup>
                  </FormControl>
                  <TextField
                    label="Năm sinh"
                    type="number"
                    value={birthYear}
                    onChange={(e) => setBirthYear(e.target.value)}
                    inputProps={{ min: CURRENT_YEAR - 90, max: CURRENT_YEAR - 8 }}
                    fullWidth
                  />
                  <TextField label="Email" value={user.email || ""} disabled fullWidth />
                  <Button variant="contained" onClick={handleSaveProfile} disabled={loading}>
                    Lưu hồ sơ
                  </Button>
                </Stack>
              </CardContent>
            </Card>

            <AthleteRatingSummary authUserId={user.id} />

            <Card>
              <CardContent>
                <Stack
                  direction="row"
                  justifyContent="space-between"
                  alignItems="center"
                  spacing={1}
                >
                  <Stack direction="row" spacing={1} alignItems="center">
                    <GroupsIcon color="action" />
                    <Box>
                      <Typography variant="h6" fontWeight={700}>
                        CLB của tôi
                      </Typography>
                      {clubSummary ? (
                        <Typography variant="body2" color="text.secondary">
                          {clubSummary.name} · {clubSummary.memberCount} thành viên ·{" "}
                          {CLUB_STATUS_LABELS[clubSummary.status] || clubSummary.status}
                        </Typography>
                      ) : (
                        <Typography variant="body2" color="text.secondary">
                          Chưa gia nhập CLB
                        </Typography>
                      )}
                    </Box>
                  </Stack>
                  <Button
                    component={RouterLink}
                    to="/my-club"
                    endIcon={<ChevronRightIcon />}
                    size="small"
                  >
                    Xem CLB
                  </Button>
                </Stack>
              </CardContent>
            </Card>

            <Card>
              <CardContent>
                <Typography variant="h6" fontWeight={700} gutterBottom>
                  Bảo mật
                </Typography>
                <Stack spacing={2}>
                  <TextField
                    label="Mật khẩu hiện tại"
                    type="password"
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    fullWidth
                    autoComplete="current-password"
                  />
                  <TextField
                    label="Mật khẩu mới"
                    type="password"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    fullWidth
                    autoComplete="new-password"
                  />
                  <TextField
                    label="Xác nhận mật khẩu mới"
                    type="password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    fullWidth
                    autoComplete="new-password"
                  />
                  <Button
                    variant="outlined"
                    onClick={handleChangePassword}
                    disabled={loading || !currentPassword || !newPassword}
                  >
                    Đổi mật khẩu
                  </Button>
                </Stack>
              </CardContent>
            </Card>
          </Stack>
        </Grid>
      </Grid>
    </Box>
  );
}

import { useMemo, useState } from "react";
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  Chip,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Grid,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

import {
  CLUB_MEMBERSHIP_REQUEST_STATUS_LABELS,
  CLUB_MEMBERSHIP_REQUEST_STATUSES,
  cancelClubMembershipRequest,
  getClubDiscoverySummary,
  listDiscoverableClubs,
  listMyMembershipRequestsAll,
  submitClubMembershipRequest,
} from "../../../features/club/index.js";
import { resolveTenantIdForClub } from "../../../features/tenant/guards/tenantGuard.js";
import { Link } from "react-router-dom";

function requestStatusChip(status) {
  const label = CLUB_MEMBERSHIP_REQUEST_STATUS_LABELS[status] || status;
  const color =
    status === CLUB_MEMBERSHIP_REQUEST_STATUSES.PENDING
      ? "warning"
      : status === CLUB_MEMBERSHIP_REQUEST_STATUSES.APPROVED
        ? "success"
        : status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED
          ? "error"
          : "default";
  return <Chip size="small" label={label} color={color} />;
}

export default function MyClubJoinPanel({ tenantId, user, onRevision }) {
  const [revision, setRevision] = useState(0);
  const [message, setMessage] = useState(null);
  const [joinClub, setJoinClub] = useState(null);
  const [joinMessage, setJoinMessage] = useState("");

  const myRequests = useMemo(() => {
    void revision;
    if (!user?.id) {
      return [];
    }
    return listMyMembershipRequestsAll(user.id);
  }, [revision, user?.id]);

  const requestByClubId = useMemo(
    () => new Map(myRequests.map((request) => [request.clubId, request])),
    [myRequests]
  );

  const joinableClubs = useMemo(() => {
    void revision;
    return listDiscoverableClubs();
  }, [revision]);

  const bumpRevision = () => {
    setRevision((value) => value + 1);
    onRevision?.();
  };

  const handleSubmitJoin = () => {
    if (!joinClub) {
      return;
    }

    const clubTenantId = resolveTenantIdForClub(joinClub.id);
    const result = submitClubMembershipRequest(joinClub.id, clubTenantId, user, {
      message: joinMessage,
    });

    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }

    setMessage({ type: "success", text: "Đã gửi yêu cầu tham gia CLB." });
    setJoinClub(null);
    setJoinMessage("");
    bumpRevision();
  };

  const handleCancelRequest = (request) => {
    const result = cancelClubMembershipRequest(request.clubId, request.id, user.id);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error });
      return;
    }
    setMessage({ type: "info", text: "Đã hủy yêu cầu tham gia." });
    bumpRevision();
  };

  return (
    <Box>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
        Duyệt danh sách CLB trong hệ thống và gửi yêu cầu tham gia. Chủ tịch hoặc Phó chủ tịch
        CLB sẽ duyệt yêu cầu của bạn.{" "}
        <Typography component={Link} to="/discover-clubs" variant="body2" sx={{ fontWeight: 600 }}>
          Xem tất cả CLB →
        </Typography>
      </Typography>

      {message && (
        <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      )}

      {joinableClubs.length === 0 ? (
        <Alert severity="info">Chưa có CLB đang hoạt động trên hệ thống.</Alert>
      ) : (
        <Grid container spacing={2}>
          {joinableClubs.slice(0, 4).map((club) => {
            const summary = getClubDiscoverySummary(club.id);
            const request = requestByClubId.get(club.id);

            return (
              <Grid item xs={12} md={6} key={club.id}>
                <Card sx={{ height: "100%" }}>
                  <CardContent>
                    <Stack spacing={1.5}>
                      <Stack direction="row" justifyContent="space-between" alignItems="flex-start">
                        <Typography variant="h6" fontWeight={700}>
                          {club.name}
                        </Typography>
                        {request && requestStatusChip(request.status)}
                      </Stack>

                      <Typography variant="body2" color="text.secondary">
                        {summary?.activeMemberCount ?? 0} thành viên
                        {summary?.presidentLabel ? ` · Chủ tịch: ${summary.presidentLabel}` : ""}
                      </Typography>

                      {summary?.clusterLabel && (
                        <Typography variant="body2" color="text.secondary">
                          Cụm sân: {summary.clusterLabel}
                        </Typography>
                      )}

                      {request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED &&
                        request.reviewNote && (
                          <Typography variant="caption" color="error">
                            Lý do: {request.reviewNote}
                          </Typography>
                        )}

                      <Stack direction="row" spacing={1}>
                        {!request && (
                          <Button
                            variant="contained"
                            size="small"
                            onClick={() => {
                              setJoinClub(club);
                              setJoinMessage("");
                            }}
                          >
                            Xin tham gia
                          </Button>
                        )}
                        {request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.PENDING && (
                          <Button
                            variant="outlined"
                            size="small"
                            color="inherit"
                            onClick={() => handleCancelRequest(request)}
                          >
                            Hủy yêu cầu
                          </Button>
                        )}
                        {request?.status === CLUB_MEMBERSHIP_REQUEST_STATUSES.REJECTED && (
                          <Button
                            variant="outlined"
                            size="small"
                            onClick={() => {
                              setJoinClub(club);
                              setJoinMessage("");
                            }}
                          >
                            Gửi lại
                          </Button>
                        )}
                      </Stack>
                    </Stack>
                  </CardContent>
                </Card>
              </Grid>
            );
          })}
        </Grid>
      )}

      <Dialog open={Boolean(joinClub)} onClose={() => setJoinClub(null)} maxWidth="sm" fullWidth>
        <DialogTitle>Xin tham gia {joinClub?.name}</DialogTitle>
        <DialogContent>
          <TextField
            fullWidth
            multiline
            minRows={3}
            label="Lời nhắn (tùy chọn)"
            value={joinMessage}
            onChange={(event) => setJoinMessage(event.target.value)}
            sx={{ mt: 1 }}
            placeholder="Giới thiệu ngắn hoặc lý do muốn tham gia CLB..."
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setJoinClub(null)}>Hủy</Button>
          <Button variant="contained" onClick={handleSubmitJoin}>
            Gửi yêu cầu
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}

import { MembershipRequestBadge } from "../../../features/club/ui/index.js";

/** @deprecated Use MembershipRequestBadge from features/club/ui */
