import { useMemo, useState } from "react";
import { Link as RouterLink, useNavigate, useParams, useSearchParams } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Chip,
  FormControl,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  TextField,
  Typography,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";

import { useAuth } from "../../context/AuthContext.jsx";
import { useClub } from "../../context/ClubContext.jsx";
import { loadPlayersForClub } from "../../domain/clubStorage.js";
import { getTournament, updateTournament } from "../../domain/tournamentService.js";
import {
  ENTRY_STATUS,
  ENTRY_STATUS_LABELS,
  EVENT_TYPE_LABELS,
} from "../../models/tournament/index.js";
import {
  cancelRegistration,
  canSubmitRegistration,
  getPlayerRegistrationStatus,
  getRegistrationSettings,
  getRegistrationPolicy,
  getEntryFee,
  resolveFeeAmount,
  isRegistrationLocked,
  gatedSubmitRegistration,
  gatedConfirmPartnerInvite,
} from "../../features/individual-tournament/index.js";
import { buildIndividualAllGroupStandings } from "../../features/individual-tournament/adapters/individualStandingsAdapter.js";
import PlayerSeedStandingsPanel from "../../components/tournament/PlayerSeedStandingsPanel.jsx";
import PlayerSchedulePanel from "../../components/tournament/PlayerSchedulePanel.jsx";
import PlayerLiveResultsPanel from "../../components/tournament/PlayerLiveResultsPanel.jsx";
import PlayerFinalResultsPanel from "../../components/tournament/PlayerFinalResultsPanel.jsx";
import { getTournamentSetupPath } from "../../utils/tournamentNavigation.js";

function resolveIsSingle(eventType) {
  return eventType === "men_single" || eventType === "women_single";
}

export default function IndividualRegistrationPage() {
  const { tournamentId } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { activeClubId, revision, refreshClubs } = useClub();
  const { user } = useAuth();
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [partnerPlayerId, setPartnerPlayerId] = useState("");
  const [displayName, setDisplayName] = useState("");

  const inviteToken = searchParams.get("invite") || "";

  const tournament = useMemo(
    () => (tournamentId ? getTournament(activeClubId, tournamentId) : null),
    [activeClubId, tournamentId, revision]
  );

  const players = useMemo(() => loadPlayersForClub(activeClubId), [activeClubId, revision]);
  const event = tournament?.events?.[0] || null;
  const isSingle = resolveIsSingle(event?.eventType);
  const linkedPlayerId = user?.playerId ? String(user.playerId) : "";

  const actor = user
    ? { id: user.id, email: user.email || "", name: user.displayName || user.name || "" }
    : null;

  const myEntry = useMemo(() => {
    if (!tournament || !linkedPlayerId) return null;
    return getPlayerRegistrationStatus(tournament, linkedPlayerId, event?.id);
  }, [tournament, linkedPlayerId, event?.id]);

  const gate = tournament ? canSubmitRegistration(tournament) : { ok: false, error: "Không tìm thấy giải." };
  const locked = tournament ? isRegistrationLocked(tournament) : true;
  const settings = tournament ? getRegistrationSettings(tournament) : {};
  const feeInfo = tournament
    ? resolveFeeAmount(tournament, { playerCount: isSingle ? 1 : partnerPlayerId ? 2 : 1 })
    : null;
  const policy = tournament ? getRegistrationPolicy(tournament) : null;

  const playerSeed = useMemo(() => {
    if (!myEntry?.id) return null;
    const seeded =
      tournament?.settings?.engineV4?.seedResult?.participants ||
      tournament?.settings?.engineV4?.participants ||
      [];
    return seeded.find((row) => String(row.id) === String(myEntry.id)) || null;
  }, [tournament, myEntry?.id]);

  const playerStanding = useMemo(() => {
    if (!myEntry?.id || !event?.groups?.length) {
      return { row: null, explanation: "" };
    }
    const groups = buildIndividualAllGroupStandings(event);
    for (const group of groups) {
      const row = (group.standing || []).find((item) => String(item.id) === String(myEntry.id));
      if (row) {
        return { row, explanation: group.tieBreakExplanation || "" };
      }
    }
    return { row: null, explanation: groups[0]?.tieBreakExplanation || "" };
  }, [event, myEntry?.id]);

  const persist = (nextTournament) => {
    const result = updateTournament(activeClubId, tournamentId, {
      events: nextTournament.events,
      settings: nextTournament.settings,
      status: nextTournament.status,
    });
    if (result.ok) {
      refreshClubs();
    }
    return result.ok;
  };

  const handleRegister = () => {
    setError(null);
    setMessage(null);

    if (!linkedPlayerId) {
      setError("Tài khoản chưa liên kết VĐV. Liên kết hồ sơ trước khi đăng ký.");
      return;
    }

    const playerIds = isSingle
      ? [linkedPlayerId]
      : partnerPlayerId
        ? [linkedPlayerId, partnerPlayerId]
        : [linkedPlayerId];

    const player = players.find((item) => String(item.id) === linkedPlayerId);
    const partner = players.find((item) => String(item.id) === String(partnerPlayerId));
    const name =
      displayName.trim() ||
      (partner ? `${player?.name || "VĐV"} / ${partner.name}` : player?.name || "VĐV");

    const result = gatedSubmitRegistration(
      tournament,
      {
        eventId: event?.id,
        playerIds,
        name,
        clubName: player?.clubName || "",
      },
      { actor, clubId: activeClubId, userId: user?.id, players }
    );

    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (!persist(result.tournament)) {
      setError("Không lưu được đăng ký.");
      return;
    }

    const policy = getRegistrationPolicy(result.tournament);
    if (result.inviteToken) {
      setMessage(
        `${policy.confirmationMessage} Mời đồng đội: ?invite=${result.inviteToken}`
      );
    } else {
      setMessage(
        `${policy.confirmationMessage} (${ENTRY_STATUS_LABELS[result.entry.status] || result.entry.status}).`
      );
    }
  };

  const handleConfirmInvite = () => {
    setError(null);
    setMessage(null);
    if (!linkedPlayerId) {
      setError("Cần tài khoản liên kết VĐV để xác nhận lời mời.");
      return;
    }
    const player = players.find((item) => String(item.id) === linkedPlayerId);
    const result = gatedConfirmPartnerInvite(tournament, inviteToken, linkedPlayerId, {
      actor,
      clubId: activeClubId,
      userId: user?.id,
      partnerName: player?.name || "",
      players,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    if (!persist(result.tournament)) {
      setError("Không lưu được xác nhận.");
      return;
    }
    setMessage(getRegistrationPolicy(result.tournament).confirmationMessage);
  };

  const handleCancel = () => {
    setError(null);
    setMessage(null);
    if (!myEntry) return;
    const result = cancelRegistration(tournament, myEntry.id, {
      actor,
      clubId: activeClubId,
      userId: user?.id,
      eventId: event?.id,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    if (!persist(result.tournament)) {
      setError("Không hủy được đăng ký.");
      return;
    }
    setMessage("Đã hủy đăng ký.");
  };

  if (!tournament) {
    return (
      <Box sx={{ p: 2 }}>
        <Alert severity="error">Không tìm thấy giải.</Alert>
        <Button sx={{ mt: 2 }} onClick={() => navigate("/tournament/register")}>
          Quay lại
        </Button>
      </Box>
    );
  }

  if (!event) {
    return (
      <Box sx={{ p: 2 }}>
        <Alert severity="warning">
          Giải chưa có nội dung thi đấu. BTC cần tạo event trước khi mở đăng ký.
        </Alert>
        <Button
          sx={{ mt: 2 }}
          component={RouterLink}
          to={getTournamentSetupPath(tournament)}
          startIcon={<ArrowBackIcon />}
        >
          Mở setup BTC
        </Button>
      </Box>
    );
  }

  return (
    <Box sx={{ p: { xs: 1.5, md: 2 }, maxWidth: 720, mx: "auto" }}>
      <Button
        startIcon={<ArrowBackIcon />}
        onClick={() => navigate("/tournament/register")}
        sx={{ mb: 1 }}
      >
        Danh sách giải
      </Button>

      <Typography variant="h5" fontWeight="bold" gutterBottom>
        Đăng ký: {tournament.name}
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
        {EVENT_TYPE_LABELS[event.eventType] || event.eventType}
        {settings.maxEntries != null ? ` · Sức chứa ${settings.maxEntries}` : ""}
        {feeInfo ? ` · ${feeInfo.label}: ${feeInfo.amount} ${getEntryFee(tournament).currency}` : ""}
      </Typography>

      {policy?.eligibilityFailedMessage && !gate.ok && (
        <Alert severity="warning" sx={{ mb: 1 }}>
          {policy.eligibilityFailedMessage}
        </Alert>
      )}

      {error && (
        <Alert severity="error" sx={{ mb: 1 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}
      {message && (
        <Alert severity="success" sx={{ mb: 1 }} onClose={() => setMessage(null)}>
          {message}
        </Alert>
      )}

      {locked && (
        <Alert severity="info" sx={{ mb: 2 }}>
          Đăng ký đã khóa. Bạn chỉ có thể xem trạng thái hiện tại.
        </Alert>
      )}

      {!gate.ok && !locked && (
        <Alert severity="warning" sx={{ mb: 2 }}>
          {gate.error}
        </Alert>
      )}

      {myEntry ? (
        <Paper variant="outlined" sx={{ p: 2, mb: 2 }}>
          <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1 }}>
            <Typography fontWeight="bold">Đăng ký của bạn</Typography>
            <Chip
              size="small"
              label={ENTRY_STATUS_LABELS[myEntry.status] || myEntry.status}
              color={
                myEntry.status === ENTRY_STATUS.APPROVED || myEntry.status === ENTRY_STATUS.ACTIVE
                  ? "success"
                  : myEntry.status === ENTRY_STATUS.PENDING
                    ? "warning"
                    : "default"
              }
            />
          </Stack>
          <Typography variant="body2">{myEntry.name}</Typography>
          {myEntry.waitlistPosition != null && (
            <Typography variant="caption" color="text.secondary">
              Vị trí waitlist: #{myEntry.waitlistPosition}
            </Typography>
          )}
          {!locked && (
            <Button color="error" sx={{ mt: 1 }} onClick={handleCancel}>
              Hủy đăng ký
            </Button>
          )}
        </Paper>
      ) : null}

      {myEntry ? (
        <Box sx={{ mb: 2 }}>
          <PlayerSeedStandingsPanel
            seedNumber={playerSeed?.seed ?? null}
            seedReason={playerSeed?.seedReason || ""}
            standingRow={playerStanding.row}
            tieBreakExplanation={playerStanding.explanation}
          />
        </Box>
      ) : null}

      {myEntry ? (
        <Box sx={{ mb: 2 }}>
          <PlayerSchedulePanel
            tournament={tournament}
            entryId={myEntry.id}
            entryLabels={Object.fromEntries(
              (event?.entries || []).map((entry) => [entry.id, entry.name || entry.id])
            )}
          />
        </Box>
      ) : null}

      {tournament ? (
        <Box sx={{ mb: 2 }}>
          <PlayerLiveResultsPanel tournament={tournament} eventId={event?.id || ""} />
        </Box>
      ) : null}

      {tournament && myEntry ? (
        <Box sx={{ mb: 2 }}>
          <PlayerFinalResultsPanel tournament={tournament} eventId={event?.id || ""} />
        </Box>
      ) : null}

      {myEntry ? null : inviteToken ? (
        <Paper variant="outlined" sx={{ p: 2, mb: 2 }}>
          <Typography fontWeight="bold" gutterBottom>
            Xác nhận lời mời đồng đội
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
            Token: {inviteToken}
          </Typography>
          <Button variant="contained" disabled={!gate.ok || !linkedPlayerId} onClick={handleConfirmInvite}>
            Xác nhận tham gia cặp
          </Button>
        </Paper>
      ) : (
        <Paper variant="outlined" sx={{ p: 2, mb: 2 }}>
          <Stack spacing={1.5}>
            <TextField
              label="Tên hiển thị (tuỳ chọn)"
              size="small"
              fullWidth
              value={displayName}
              onChange={(event_) => setDisplayName(event_.target.value)}
              disabled={!gate.ok}
            />
            {!isSingle && (
              <FormControl fullWidth size="small" disabled={!gate.ok}>
                <InputLabel>Đồng đội (tuỳ chọn)</InputLabel>
                <Select
                  label="Đồng đội (tuỳ chọn)"
                  value={partnerPlayerId}
                  onChange={(event_) => setPartnerPlayerId(event_.target.value)}
                >
                  <MenuItem value="">
                    <em>Chưa chọn — gửi lời mời sau</em>
                  </MenuItem>
                  {players
                    .filter((player) => String(player.id) !== linkedPlayerId)
                    .map((player) => (
                      <MenuItem key={player.id} value={String(player.id)}>
                        {player.name}
                      </MenuItem>
                    ))}
                </Select>
              </FormControl>
            )}
            {!linkedPlayerId && (
              <Alert severity="warning">Tài khoản chưa gắn VĐV — chưa thể tự đăng ký.</Alert>
            )}
            <Button
              variant="contained"
              disabled={!gate.ok || !linkedPlayerId}
              onClick={handleRegister}
            >
              Gửi đăng ký
            </Button>
          </Stack>
        </Paper>
      )}

      <Typography variant="caption" color="text.secondary">
        Cửa sổ:{" "}
        {settings.opensAt ? new Date(settings.opensAt).toLocaleString("vi-VN") : "mở ngay"} →{" "}
        {settings.closesAt ? new Date(settings.closesAt).toLocaleString("vi-VN") : "không hạn"}
      </Typography>
    </Box>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Link as RouterLink, useNavigate, useParams, useSearchParams } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Chip,
  FormControl,
  Grid,
  InputLabel,
  Link,
  MenuItem,
  Paper,
  Select,
  Stack,
  Tab,
  Tabs,
  TextField,
  Typography,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";

import { useClub } from "../../context/ClubContext.jsx";
import { loadCourtsForClub, loadPlayersForClub } from "../../domain/clubStorage.js";
import TournamentCourtSchedulePanel from "../../components/tournament/TournamentCourtSchedulePanel.jsx";
import {
  getTournament,
  advanceTournamentStatus,
  updateTournament,
} from "../../domain/tournamentService.js";
import {
  EVENT_TYPE,
  TOURNAMENT_MODE,
  TOURNAMENT_STATUS,
  EVENT_TYPE_OPTIONS,
} from "../../models/tournament/index.js";
import {
  buildInternalTournamentPatch,
  buildInternalTournamentPlan,
  suggestEntriesFromPlayers,
  filterPlayersForEventType,
  isSingleEventType,
  canGenerateBracket,
  generateKnockoutBracket,
  resolveBracketProgress,
  setBracketWinner,
  submitKnockoutMatchScore,
  toggleBracketRoundUnlock,
  resetBracketState,
  submitTournamentDirectorMatchScore,
} from "../../tournament/engines/index.js";
import { buildIndividualAllGroupStandings } from "../../features/individual-tournament/adapters/individualStandingsAdapter.js";
import BracketView from "../../components/tournament/BracketView.jsx";
import GroupStagePanel from "../../components/tournament/GroupStagePanel.jsx";
import RefereeRosterPanel from "../../components/tournament/RefereeRosterPanel.jsx";
import TournamentAnimationDialog from "../../components/tournament/animation/TournamentAnimationDialog.jsx";
import BracketRevealAnimation from "../../components/tournament/animation/BracketRevealAnimation.jsx";
import {
  ANIMATION_MODES,
  buildGroupMatchPairingSteps,
  buildPairingSteps,
  buildPairingWaitingPlayers,
  buildSnakeSteps,
  stripMatchesFromEvent,
} from "../../components/tournament/animation/animationUtils.js";
import { useTournamentAnimation } from "../../components/tournament/animation/useTournamentAnimation.js";
import { useTournamentFlowOrchestrator } from "../../components/tournament/animation/useTournamentFlowOrchestrator.js";
import { createInternalFlowAdapters } from "../../components/tournament/animation/tournamentFlowAdapters.js";
import {
  BroadcastLiveIndicator,
  BroadcastSetupDialog,
  isTournamentBroadcastEnabled,
  useTournamentBroadcast,
  BroadcastVodResultAlert,
} from "../../features/tournament-broadcast/index.js";
import { PAIRING_CONTROL_MODES } from "../../components/tournament/animation/pairing/usePairingSequence.js";
import {
  buildRefereeSettingsPatch,
  getRefereeSettings,
} from "../../tournament/engines/refereeEngine.js";
import TournamentManageGate from "../../components/tournament/TournamentManageGate.jsx";
import TournamentSetupShell from "../../components/tournament/TournamentSetupShell.jsx";
import TournamentSelectedPlayersPanel from "../../components/tournament/TournamentSelectedPlayersPanel.jsx";
import {
  findTournamentClubId,
  getClubById,
  getClubInternalTournamentPlayers,
  getTenantPlayers,
  canViewFullClubMembers,
} from "../../features/club/index.js";
import { resolveTenantIdForClub } from "../../features/tenant/guards/tenantGuard.js";
import { isAiEngineEnabled } from "../../features/ai-assistant/index.js";
import TournamentAiAssistantPanel from "../../components/tournament/ai/TournamentAiAssistantPanel.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { canViewPlayerSkillLevel } from "../../auth/rbac.js";
import { useTenant } from "../../context/TenantContext.jsx";
import { formatOrganizerPlayerMeta } from "../../utils/skillLevelVisibility.js";
import {
  resolveTournamentEntryPlayers,
  TournamentRegistrationRatingPanel,
} from "../../features/pick-vn-rating/index.js";
import {
  INTERVENTION_PHASE,
  TournamentEntryEditor,
  TournamentGroupEditor,
  usePairingIntervention,
} from "../../features/pairing-intervention/index.js";
import {
  FounderPairingConstraintsPanel,
  guardFounderConstraints,
  getTournamentPairingConstraints,
  logConstraintChange,
} from "../../features/pairing-constraints/index.js";
import DrawPublishControls from "../../components/tournament/DrawPublishControls.jsx";
import RegistrationOpsPanel from "../../components/tournament/RegistrationOpsPanel.jsx";
import {
  canRegenerateDraw,
  forceRedrawDraw,
  getDrawPublishStatus,
  lockDraw,
  publishDraw,
  recordDrawCreated,
  reopenDraw,
  resolveDrawReopenPermission,
  summarizeGroups,
} from "../../tournament/engines/publishDrawEngine.js";
import { resolveEventTypeFromQuery } from "../../features/individual-tournament/index.js";

const EVENT_OPTIONS = EVENT_TYPE_OPTIONS;

export default function InternalTournamentSetup() {
  const { tournamentId } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { activeClubId, clubs, refreshClubs, switchClub } = useClub();
  const { user, rbacEnabled, can } = useAuth();
  const { currentTenantId } = useTenant();
  const aiEnabled = isAiEngineEnabled();
  const [setupTab, setSetupTab] = useState(0);
  const [localRevision, setLocalRevision] = useState(0);
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [warnings, setWarnings] = useState([]);

  const preselectedEvent = resolveEventTypeFromQuery(searchParams.get("event"));
  const [eventType, setEventType] = useState(preselectedEvent || EVENT_TYPE.MIXED_DOUBLE);
  const [groupCount, setGroupCount] = useState(4);
  const [sourceClubId, setSourceClubId] = useState("");
  const [selectedPlayerIds, setSelectedPlayerIds] = useState([]);
  const [previewEntries, setPreviewEntries] = useState([]);
  const [founderConstraints, setFounderConstraints] = useState([]);
  const [bracketAdvanceAnim, setBracketAdvanceAnim] = useState(null);
  const anim = useTournamentAnimation();
  const pendingPlanRef = useRef(null);

  const canViewSkillInSetup = useMemo(
    () =>
      canViewPlayerSkillLevel(
        user,
        { clubId: activeClubId, tournamentId, tournamentContext: true },
        { rbacEnabled }
      ),
    [user, activeClubId, tournamentId, rbacEnabled]
  );

  const tournamentClubId = useMemo(
    () => findTournamentClubId(tournamentId) || activeClubId,
    [tournamentId, activeClubId]
  );

  useEffect(() => {
    if (tournamentClubId && tournamentClubId !== activeClubId) {
      switchClub(tournamentClubId);
    }
  }, [tournamentClubId, activeClubId, switchClub]);

  useEffect(() => {
    if (tournamentClubId) {
      setSourceClubId(tournamentClubId);
    }
  }, [tournamentClubId]);

  const tournament = useMemo(
    () => getTournament(tournamentClubId, tournamentId),
    [tournamentClubId, tournamentId, localRevision]
  );

  useEffect(() => {
    if (tournament) {
      setFounderConstraints(getTournamentPairingConstraints(tournament));
    }
  }, [tournament?.id, tournament?.founderPairingConstraints]);

  const isClubInternal = tournament?.type === "club_internal";

  const players = useMemo(() => {
    if (!sourceClubId) {
      return [];
    }
    if (isClubInternal) {
      const tenantId = tournament?.tenantId || resolveTenantIdForClub(sourceClubId);
      const club = getClubById(sourceClubId, tenantId);
      const forTournamentInvite = Boolean(
        club && user && !canViewFullClubMembers(user, club)
      );
      return getClubInternalTournamentPlayers(sourceClubId, tenantId, {
        forTournamentInvite,
      });
    }
    return loadPlayersForClub(sourceClubId);
  }, [isClubInternal, tournament, sourceClubId, localRevision, user]);

  const courts = useMemo(
    () => loadCourtsForClub(tournamentClubId),
    [tournamentClubId, localRevision]
  );

  const refereeRoster = useMemo(
    () => getRefereeSettings(tournament).roster,
    [tournament, localRevision]
  );

  const isSingleEvent = isSingleEventType(eventType);

  const eligiblePlayers = useMemo(
    () => filterPlayersForEventType(players, eventType),
    [players, eventType]
  );

  const selectedPlayers = useMemo(() => {
    const tenantId =
      tournament?.tenantId || resolveTenantIdForClub(sourceClubId || tournamentClubId);
    const pool = new Map(getTenantPlayers(tenantId).map((player) => [String(player.id), player]));
    return selectedPlayerIds
      .map((id) => pool.get(String(id)))
      .filter(Boolean);
  }, [selectedPlayerIds, sourceClubId, tournamentClubId, tournament?.tenantId, localRevision]);

  const tenantPlayers = useMemo(() => {
    const tenantId =
      tournament?.tenantId || resolveTenantIdForClub(sourceClubId || tournamentClubId);
    return tenantId ? getTenantPlayers(tenantId) : [];
  }, [tournament?.tenantId, sourceClubId, tournamentClubId, localRevision]);

  const savedEvent = tournament?.events?.[0] || null;

  const groupStandings = useMemo(
    () => (savedEvent ? buildIndividualAllGroupStandings(savedEvent) : []),
    [savedEvent]
  );

  const bracketProgress = useMemo(
    () => (savedEvent ? resolveBracketProgress(savedEvent) : null),
    [savedEvent]
  );

  const knockoutMatchesByBracketId = useMemo(() => {
    const map = {};
    (savedEvent?.matches || []).forEach((match) => {
      if (match.bracketMatchId) {
        map[match.bracketMatchId] = match;
      }
    });
    return map;
  }, [savedEvent]);

  const scoreDraftScope = useMemo(
    () => ({
      clubId: tournamentClubId,
      tournamentId,
      eventId: savedEvent?.id,
    }),
    [tournamentClubId, tournamentId, savedEvent?.id]
  );

  const persistEvent = (nextEvent, options = {}) => {
    const result = updateTournament(
      tournamentClubId,
      tournamentId,
      {
        events: [{ ...savedEvent, ...nextEvent }],
      },
      {
        processMatchId: options.processMatchId || null,
        processEventId: savedEvent?.id || null,
      }
    );

    if (!result.ok) {
      setError(result.error);
      return false;
    }

    setLocalRevision((value) => value + 1);
    refreshClubs();
    return true;
  };

  const pairingIntervention = usePairingIntervention({
    phase: INTERVENTION_PHASE.TOURNAMENT,
    tournamentStatus: tournament?.status,
    clubId: tournamentClubId,
    resourceId: tournamentId,
  });

  const canInterveneSetup = pairingIntervention.canIntervene;

  const drawPublish = useMemo(
    () => getDrawPublishStatus(tournament),
    [tournament, localRevision]
  );

  const hasDrawReopenPermission = useMemo(
    () =>
      resolveDrawReopenPermission({
        canPermission: can,
        rbacEnabled,
        canIntervene: canInterveneSetup,
      }),
    [can, rbacEnabled, canInterveneSetup]
  );

  const buildDrawActor = () =>
    user
      ? { id: user.id, email: user.email || "", name: user.displayName || user.name || "" }
      : null;

  const handleLockDraw = () => {
    setError(null);
    const groups = savedEvent?.groups || [];
    const result = lockDraw(tournament, groups, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: tournamentClubId,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    const updateResult = updateTournament(tournamentClubId, tournamentId, {
      settings: result.tournament.settings,
    });
    if (updateResult.ok) {
      setLocalRevision((value) => value + 1);
      refreshClubs();
      setMessage("Đã khóa bốc thăm. Sẵn sàng công bố.");
    }
  };

  const handlePublishDraw = () => {
    setError(null);
    const groups = savedEvent?.groups || [];
    const result = publishDraw(tournament, groups, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: tournamentClubId,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    const events = (tournament.events || []).map((event) =>
      String(event.id) === String(savedEvent?.id)
        ? { ...event, groups: result.snapshot || groups }
        : event
    );
    const updateResult = updateTournament(tournamentClubId, tournamentId, {
      settings: result.tournament.settings,
      events,
    });
    if (updateResult.ok) {
      setLocalRevision((value) => value + 1);
      refreshClubs();
      setMessage("Đã công bố bốc thăm. Bracket bất biến.");
    }
  };

  const handleReopenDraw = () => {
    setError(null);
    const result = reopenDraw(tournament, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: tournamentClubId,
      hasReopenPermission: hasDrawReopenPermission,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    const updateResult = updateTournament(tournamentClubId, tournamentId, {
      settings: result.tournament.settings,
    });
    if (updateResult.ok) {
      setLocalRevision((value) => value + 1);
      refreshClubs();
      setMessage("Đã mở lại bốc thăm để chỉnh sửa.");
    }
  };

  const handleForceRedraw = () => {
    setError(null);
    const result = forceRedrawDraw(tournament, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: tournamentClubId,
      hasReopenPermission: hasDrawReopenPermission,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    const updateResult = updateTournament(tournamentClubId, tournamentId, {
      settings: result.tournament.settings,
    });
    if (updateResult.ok) {
      setLocalRevision((value) => value + 1);
      refreshClubs();
      setMessage("Force redraw được phép. Bạn có thể chia bảng lại.");
    }
  };

  const editorEntries =
    previewEntries.length > 0 ? previewEntries : savedEvent?.entries || [];

  const handleEntryInterventionApply = (result) => {
    if (!result?.ok) {
      return;
    }
    setPreviewEntries(result.entries);
    if (savedEvent?.entries?.length) {
      persistEvent({ entries: result.entries });
    }
    setMessage("Super Admin đã cập nhật ghép cặp.");
  };

  const handleGroupInterventionApply = (result) => {
    if (!result?.ok) {
      return;
    }
    if (
      persistEvent({
        entries: result.entries,
        groups: result.groups,
        matches: result.matches,
      })
    ) {
      setMessage("Super Admin đã cập nhật chia bảng và tạo lại lịch vòng bảng.");
    }
  };

  const handleSaveFounderConstraints = async () => {
    setError(null);
    const guard = guardFounderConstraints({ user });
    if (!guard.ok) {
      setError(guard.error);
      return;
    }

    const before = getTournamentPairingConstraints(tournament);
    const result = updateTournament(tournamentClubId, tournamentId, {
      founderPairingConstraints: founderConstraints,
    });

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setLocalRevision((value) => value + 1);
    setMessage("Đã lưu quy tắc ghép cặp Founder.");
    await logConstraintChange({
      user,
      tournamentId,
      clubId: tournamentClubId,
      before,
      after: founderConstraints,
    });
  };

  const applyConstraintWarnings = (pairingOptions) => {
    const constraintWarnings = pairingOptions?.constraintWarnings || [];
    if (constraintWarnings.length > 0) {
      setWarnings(
        constraintWarnings.map((item) =>
          typeof item === "string" ? item : item.message || String(item)
        )
      );
    }
  };

  const flowAdapters = useMemo(
    () =>
      createInternalFlowAdapters({
        tournament,
        tournamentClubId,
        tournamentId,
        players,
        courts,
        selectedPlayerIds,
        eventType,
        groupCount,
        isSingleEvent,
        setPreviewEntries,
        setWarnings,
        setMessage,
        setError,
        setLocalRevision,
        refreshClubs,
        persistEvent,
      }),
    [
      tournament,
      tournamentClubId,
      tournamentId,
      players,
      courts,
      selectedPlayerIds,
      eventType,
      groupCount,
      isSingleEvent,
      refreshClubs,
    ]
  );

  const flow = useTournamentFlowOrchestrator(anim, flowAdapters);

  const broadcastFeatureEnabled = isTournamentBroadcastEnabled();
  const broadcast = useTournamentBroadcast({
    tournamentId,
    tournamentName: tournament?.name || "Giải đấu",
    clubId: tournamentClubId,
  });
  const [broadcastDialogOpen, setBroadcastDialogOpen] = useState(false);

  const handleFlowExit = useCallback(async () => {
    if (broadcastFeatureEnabled) {
      const stopResult = await broadcast.stopBroadcast();
      if (stopResult?.ok === false && stopResult?.error) {
        setError(stopResult.error);
      }
    }
    flow.exitFlow();
  }, [broadcast, broadcastFeatureEnabled, flow]);

  const handleRefereeRosterChange = (nextRoster) => {
    const result = updateTournament(
      tournamentClubId,
      tournamentId,
      buildRefereeSettingsPatch(tournament, { roster: nextRoster })
    );

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setLocalRevision((value) => value + 1);
    refreshClubs();
    setMessage("Đã cập nhật danh sách trọng tài.");
  };

  const handleGenerateBracket = () => {
    setError(null);
    setMessage(null);

    const check = canGenerateBracket(savedEvent);
    if (!check.ok) {
      setError(check.errors.join(" "));
      setWarnings(check.warnings || []);
      return;
    }

    const generated = generateKnockoutBracket(savedEvent);
    if (!generated.ok) {
      setError(generated.errors?.join(" ") || "Khong tao duoc bracket.");
      return;
    }

    const progress = resolveBracketProgress(generated.event);

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.BRACKET_REVEAL,
        bracket: progress,
      },
      () => {
        if (!persistEvent(generated.event)) {
          return;
        }

        setWarnings(generated.warnings || []);
        setMessage(`Da tao bracket knock-out voi ${generated.knockoutMatchCount} tran.`);
      }
    );
  };

  const handleSelectBracketWinner = (bracketMatchId, winnerSide) => {
    const result = setBracketWinner(savedEvent, bracketMatchId, winnerSide || null);
    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (winnerSide) {
      const progress = resolveBracketProgress(result.event);
      const match = progress.rounds
        .flatMap((round) => round.matches)
        .find((item) => item.id === bracketMatchId);
      const winnerName =
        winnerSide === "home"
          ? match?.home?.name || match?.homeSeed
          : match?.away?.name || match?.awaySeed;

      setBracketAdvanceAnim({
        winnerName,
        bracket: progress,
      });
    } else {
      setBracketAdvanceAnim(null);
    }

    if (persistEvent(result.event)) {
      setMessage(winnerSide ? "Da cap nhat winner." : "Da xoa winner.");
    }
  };

  const handleSubmitGroupScore = (matchId, scores) => {
    const result = submitTournamentDirectorMatchScore(savedEvent, matchId, scores);
    if (!result.ok) {
      setError(result.error);
      return false;
    }

    if (persistEvent(result.event, { processMatchId: matchId })) {
      if (result.bracketAutoGenerated) {
        setMessage(
          `Đã lưu kết quả vòng bảng. Tự động tạo bracket knock-out (${result.bracketKnockoutMatchCount} trận).`
        );
      } else {
        setMessage("Đã lưu kết quả vòng bảng.");
      }
      return true;
    }

    return false;
  };

  const handleSubmitKnockoutScore = (matchId, scores) => {
    const result = submitKnockoutMatchScore(savedEvent, matchId, scores);
    if (!result.ok) {
      setError(result.error);
      return false;
    }

    if (persistEvent(result.event, { processMatchId: matchId })) {
      setMessage("Da luu ket qua knock-out.");
      return true;
    }

    return false;
  };

  const handleToggleRoundLock = (roundName, unlock) => {
    const result = toggleBracketRoundUnlock(savedEvent, roundName, unlock);
    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (persistEvent(result.event)) {
      setMessage(unlock ? `Da mo khoa vong ${roundName}.` : `Da khoa vong ${roundName}.`);
    }
  };

  const handleResetBracket = () => {
    const confirmed = window.confirm(
      "Reset bracket? Se xoa toan bo tran knock-out va winner hien tai."
    );
    if (!confirmed) {
      return;
    }

    const nextEvent = resetBracketState(savedEvent);
    if (persistEvent(nextEvent)) {
      setMessage("Da reset bracket.");
    }
  };

  const togglePlayer = (playerId) => {
    const key = String(playerId);
    setSelectedPlayerIds((current) =>
      current.includes(key) ? current.filter((id) => id !== key) : [...current, key]
    );
  };

  const handleSelectAllPlayers = () => {
    setSelectedPlayerIds(eligiblePlayers.map((player) => String(player.id)));
  };

  const handleClearAllPlayers = () => {
    setSelectedPlayerIds([]);
  };

  const handleRemoveSelectedPlayer = (playerId) => {
    const key = String(playerId);
    setSelectedPlayerIds((current) => current.filter((id) => id !== key));
  };

  const handleSourceClubChange = (clubId) => {
    setSourceClubId(clubId);
    setSelectedPlayerIds([]);
    setPreviewEntries([]);
  };

  const handleStartGuidedFlow = async () => {
    setError(null);
    setWarnings([]);
    setMessage(null);

    if (broadcastFeatureEnabled && broadcast.shouldBroadcastWithFlow) {
      const broadcastResult = await broadcast.startBroadcast();
      if (broadcastResult?.ok === false) {
        setError(broadcastResult.error || "Không thể bắt đầu phát live.");
        return;
      }
    }

    const result = flow.startFlow({});
    if (result?.ok === false) {
      if (broadcastFeatureEnabled && broadcast.isLive) {
        await broadcast.stopBroadcast();
      }
      setError(result.error || "Không thể bắt đầu trình chiếu.");
    }
  };

  const handleSuggestPairs = () => {
    setError(null);
    setWarnings([]);

    const pairingOptions = {
      tournamentId,
      eventId: savedEvent?.id || `event-${tournamentId}`,
      pairingConstraints: founderConstraints,
    };

    const entries = suggestEntriesFromPlayers(
      players.filter((player) => selectedPlayerIds.includes(String(player.id))),
      eventType,
      pairingOptions
    );

    applyConstraintWarnings(pairingOptions);

    if (entries.length === 0) {
      setError(
        isSingleEvent
          ? "Không tạo được danh sách VĐV. Kiểm tra giới tính và số VĐV đã chọn."
          : "Khong tao duoc cap nao. Kiem tra gioi tinh va so VDV da chon."
      );
      return;
    }

    const selectedPlayers = players.filter((player) =>
      selectedPlayerIds.includes(String(player.id))
    );

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.PAIRING_REVEAL,
        pairings: entries,
        steps: buildPairingSteps(entries),
        waitingPlayers: buildPairingWaitingPlayers(entries, selectedPlayers),
        title: isSingleEvent ? "Danh sách VĐV" : "Ghép cặp",
        subtitle: "Reveal từng cặp — danh sách chờ hiển thị từng VĐV",
        revealItemLabel: isSingleEvent ? "VĐV" : "Cặp",
      },
      () => {
        setPreviewEntries(entries);
        setMessage(
          isSingleEvent
            ? `Đã đề xuất ${entries.length} VĐV.`
            : `Da de xuat ${entries.length} cap/đội.`
        );
      }
    );
  };

  const handleBuildGroups = () => {
    setError(null);
    setWarnings([]);
    setMessage(null);

    const regenCheck = canRegenerateDraw(tournament);
    if (!regenCheck.ok && savedEvent?.groups?.length) {
      setError(regenCheck.error);
      return;
    }

    const pairingOptions = {
      tournamentId,
      eventId: savedEvent?.id || `event-${tournamentId}`,
      pairingConstraints: founderConstraints,
    };

    const entries =
      previewEntries.length > 0
        ? previewEntries
        : suggestEntriesFromPlayers(
            players.filter((player) => selectedPlayerIds.includes(String(player.id))),
            eventType,
            pairingOptions
          );

    if (previewEntries.length === 0) {
      applyConstraintWarnings(pairingOptions);
    }

    const plan = buildInternalTournamentPlan({
      tournament,
      players,
      selectedPlayerIds,
      eventType,
      groupCount,
      manualEntries: entries,
      pairingConstraints: founderConstraints,
    });

    if (!plan.ok) {
      setError(plan.errors?.join(" "));
      setWarnings(plan.warnings || []);
      return;
    }

    const selectedPlayers = players.filter((player) =>
      selectedPlayerIds.includes(String(player.id))
    );

    const steps = buildSnakeSteps({
      entries: plan.event.entries,
      players: selectedPlayers,
      groupCount,
      finalGroups: plan.event.groups,
    });

    pendingPlanRef.current = plan;

    const openMatchPairingFromDraw = () => {
      openMatchPairingAnimation(plan);
    };

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.SNAKE_GROUP,
        groups: plan.event.groups,
        steps,
        matchCount: plan.matchCount,
        onStartMatchPairing: openMatchPairingFromDraw,
      },
      () => {
        const patch = buildInternalTournamentPatch(tournament, plan);
        if (!patch.ok) {
          setError(patch.error || "Khong luu duoc giai.");
          return;
        }

        const eventWithoutMatches = stripMatchesFromEvent(patch.events[0]);
        const result = advanceTournamentStatus(tournamentClubId, tournamentId, TOURNAMENT_STATUS.READY, {
          events: [eventWithoutMatches],
        });

        if (!result.ok) {
          setError(result.error);
          return;
        }

        const created = recordDrawCreated(
          getTournament(tournamentClubId, tournamentId),
          patch.events[0]?.groups || [],
          {
            userId: user?.id,
            actor: buildDrawActor(),
            clubId: tournamentClubId,
            before: summarizeGroups(savedEvent?.groups || []),
          }
        );
        if (created.ok) {
          updateTournament(tournamentClubId, tournamentId, {
            settings: created.tournament.settings,
          });
        }

        setWarnings(patch.warnings || []);
        setLocalRevision((value) => value + 1);
        refreshClubs();
        setMessage(`Đã chia ${patch.events[0].groups.length} bảng. Bấm "Ghép cặp thi đấu" trên màn hình kết quả.`);
      }
    );
  };

  const persistMatchPairing = (plan) => {
    if ((savedEvent?.matches?.length || 0) > 0) {
      return true;
    }

    const patch = buildInternalTournamentPatch(tournament, plan);
    if (!patch.ok) {
      setError(patch.error || "Không lưu được lịch thi đấu.");
      return false;
    }

    const result = advanceTournamentStatus(tournamentClubId, tournamentId, TOURNAMENT_STATUS.READY, {
      events: patch.events,
    });

    if (!result.ok) {
      setError(result.error);
      return false;
    }

    pendingPlanRef.current = null;
    setWarnings(patch.warnings || []);
    setLocalRevision((value) => value + 1);
    refreshClubs();
    setMessage(`Đã ghép ${patch.matchCount} trận vòng bảng. Xem lịch bên dưới.`);
    return true;
  };

  const openMatchPairingAnimation = (plan) => {
    if (!plan?.ok || !plan.event?.groups?.length) {
      setError("Chưa có bảng đấu để ghép cặp.");
      return;
    }

    const steps = buildGroupMatchPairingSteps({
      groups: plan.event.groups,
      matches: plan.event.matches,
      entries: plan.event.entries,
      courts,
    });

    if (!steps.length) {
      setError("Không có trận đấu để ghép cặp.");
      return;
    }

    anim.transitionAnimation(
      {
        animationMode: ANIMATION_MODES.GROUP_MATCH_PAIRING,
        tournamentName: tournament.name,
        groups: plan.event.groups,
        entries: plan.event.entries,
        steps,
        courts,
        autoStart: true,
        controlMode: PAIRING_CONTROL_MODES.AUTO,
        autoNextGroup: true,
      },
      () => {
        persistMatchPairing(plan);
      }
    );
  };

  if (!tournament) {
    return (
      <Box>
        <Alert severity="error">Khong tim thay giai.</Alert>
        <Button component={RouterLink} to="/tournament" sx={{ mt: 2 }}>
          Quay lai
        </Button>
      </Box>
    );
  }

  if (tournament.mode !== TOURNAMENT_MODE.INTERNAL_TOURNAMENT) {
    return (
      <Box>
        <Alert severity="warning">Giai nay khong phai che do noi bo.</Alert>
        <Button component={RouterLink} to="/tournament" sx={{ mt: 2 }}>
          Quay lai
        </Button>
      </Box>
    );
  }

  return (
    <TournamentManageGate tournamentId={tournamentId}>
    <TournamentSetupShell
      tournament={tournament}
      description="Giải nội bộ — đơn/đôi, chia bảng snake seeding, tạo lịch vòng bảng"
      onBack={() => navigate("/tournament")}
      headerActions={
        savedEvent?.matches?.length > 0 ? (
          <Button
            variant="outlined"
            onClick={() => navigate(`/tournament/director/${tournamentId}`)}
          >
            Mở Director Mode
          </Button>
        ) : null
      }
      alerts={
        <>
          {broadcastFeatureEnabled && broadcast.lastVodUpload ? (
            <BroadcastVodResultAlert
              result={broadcast.lastVodUpload}
              onClose={broadcast.clearLastVodUpload}
            />
          ) : null}
          {message && (
            <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
              {message}
            </Alert>
          )}
          {error && (
            <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
              {error}
            </Alert>
          )}
          {warnings.length > 0 && (
            <Alert severity="warning" sx={{ mb: 2 }}>
              {warnings.join(" ")}
            </Alert>
          )}
        </>
      }
      setupTab={setupTab}
      onSetupTabChange={(_, value) => setSetupTab(value)}
      showAiTab={aiEnabled}
    >
      {aiEnabled && setupTab === 1 ? (
        <TournamentAiAssistantPanel
          tournamentId={tournamentId}
          clubId={tournamentClubId}
          tenantId={currentTenantId || tournament?.tenantId || resolveTenantIdForClub(tournamentClubId)}
          players={players}
          courts={courts}
          userId={user?.id || ""}
          onApplied={() => {
            setLocalRevision((v) => v + 1);
            refreshClubs();
            setMessage("Đã áp dụng đề xuất AI.");
          }}
        />
      ) : (
      <>
      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12 }}>
          <RefereeRosterPanel roster={refereeRoster} onChange={handleRefereeRosterChange} />
        </Grid>
        <Grid size={{ xs: 12 }}>
          <FounderPairingConstraintsPanel
            constraints={founderConstraints}
            players={players}
            onChange={setFounderConstraints}
            onSave={handleSaveFounderConstraints}
          />

          <RegistrationOpsPanel
            tournament={tournament}
            event={savedEvent}
            players={players}
            actor={
              user
                ? { id: user.id, email: user.email || "", name: user.displayName || user.name || "" }
                : null
            }
            clubId={tournamentClubId}
            onPersist={(nextTournament) => {
              const result = updateTournament(tournamentClubId, tournamentId, {
                events: nextTournament.events,
                settings: nextTournament.settings,
                status: nextTournament.status,
              });
              if (result.ok) {
                setLocalRevision((value) => value + 1);
                refreshClubs();
                return true;
              }
              setError(result.error);
              return false;
            }}
          />
        </Grid>
      </Grid>

      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12, md: 4 }}>
          <FormControl fullWidth size="small">
            <InputLabel>Nội dung</InputLabel>
            <Select
              label="Nội dung"
              value={eventType}
              onChange={(event) => setEventType(event.target.value)}
            >
              {EVENT_OPTIONS.map((option) => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid size={{ xs: 12, md: 4 }}>
          <TextField
            fullWidth
            size="small"
            type="number"
            label="Số bảng"
            value={groupCount}
            inputProps={{ min: 1, max: 16 }}
            onChange={(event) => setGroupCount(Number(event.target.value) || 1)}
          />
        </Grid>
        <Grid size={{ xs: 12, md: 4 }}>
          <Stack spacing={1}>
            <Button
              fullWidth
              variant="contained"
              color="secondary"
              onClick={handleStartGuidedFlow}
              disabled={selectedPlayerIds.length === 0}
            >
              Bắt đầu trình chiếu
            </Button>
            {broadcastFeatureEnabled ? (
              <Button
                fullWidth
                variant="outlined"
                onClick={() => setBroadcastDialogOpen(true)}
              >
                Cài đặt phát live
              </Button>
            ) : null}
            {broadcastFeatureEnabled && broadcast.isLive ? (
              <BroadcastLiveIndicator status={broadcast.status} error={broadcast.error} />
            ) : null}
            <Stack direction={{ xs: "column", sm: "row" }} spacing={1}>
              <Button fullWidth variant="outlined" onClick={handleSuggestPairs}>
                {isSingleEvent ? "Đề xuất danh sách" : "Đề xuất ghép cặp"}
              </Button>
              <Button fullWidth variant="contained" onClick={handleBuildGroups}>
                Chia bảng
              </Button>
            </Stack>
          </Stack>
        </Grid>
      </Grid>

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, lg: 4 }}>
          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Chọn VĐV tham gia ({selectedPlayerIds.length}
              {isSingleEvent ? ` / ${eligiblePlayers.length} đủ điều kiện` : ""})
            </Typography>
            <FormControl fullWidth size="small" sx={{ mb: 1.5 }}>
              <InputLabel id="source-club-label">Câu lạc bộ</InputLabel>
              <Select
                labelId="source-club-label"
                label="Câu lạc bộ"
                value={sourceClubId}
                onChange={(event) => handleSourceClubChange(event.target.value)}
              >
                {clubs.map((club) => (
                  <MenuItem key={club.id} value={club.id}>
                    {club.name}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
            <Stack direction="row" spacing={1} sx={{ mb: 1 }}>
              <Button
                size="small"
                variant="contained"
                onClick={handleSelectAllPlayers}
                disabled={!sourceClubId || eligiblePlayers.length === 0}
              >
                Chọn tất cả
              </Button>
              <Button
                size="small"
                variant="outlined"
                onClick={handleClearAllPlayers}
                disabled={selectedPlayerIds.length === 0}
              >
                Bỏ chọn tất cả
              </Button>
            </Stack>
            <Stack spacing={1} sx={{ maxHeight: 360, overflow: "auto" }}>
              {!sourceClubId ? (
                <Typography variant="body2" color="text.secondary">
                  Chọn câu lạc bộ để xem danh sách thành viên.
                </Typography>
              ) : eligiblePlayers.length === 0 ? (
                <Typography variant="body2" color="text.secondary">
                  CLB này chưa có thành viên. Thêm tại{" "}
                  <Link
                    component={RouterLink}
                    to={`/clubs/${sourceClubId}?tab=members`}
                    underline="hover"
                  >
                    Quản lý CLB → Thành viên
                  </Link>
                  .
                </Typography>
              ) : (
                eligiblePlayers.map((player) => {
                  const checked = selectedPlayerIds.includes(String(player.id));
                  return (
                    <Button
                      key={player.id}
                      fullWidth
                      variant={checked ? "contained" : "outlined"}
                      onClick={() => togglePlayer(player.id)}
                      sx={{ justifyContent: "space-between", minHeight: 44 }}
                    >
                      <span>{player.name}</span>
                      <span>
                        {formatOrganizerPlayerMeta(player, canViewSkillInSetup)}
                      </span>
                    </Button>
                  );
                })
              )}
            </Stack>
          </Paper>
        </Grid>

        <Grid size={{ xs: 12, lg: 4 }}>
          <TournamentSelectedPlayersPanel
            title="VĐV đã chọn"
            players={selectedPlayers}
            onRemove={handleRemoveSelectedPlayer}
            emptyMessage="Chưa chọn VĐV nào. Bấm tên VĐV bên trái để thêm."
          />
        </Grid>

        <Grid size={{ xs: 12, lg: 4 }}>
          <Paper variant="outlined" sx={{ p: 1.5, mb: 2 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              {isSingleEvent ? "VĐV đăng ký" : "Cặp / đội đề xuất"} (
              {previewEntries.length || savedEvent?.entries?.length || 0})
            </Typography>
            <Stack spacing={1} sx={{ maxHeight: 220, overflow: "auto" }}>
              {(previewEntries.length ? previewEntries : savedEvent?.entries || []).map(
                (entry) => (
                  <Paper key={entry.id} variant="outlined" sx={{ p: 1 }}>
                    <Stack direction="row" justifyContent="space-between" spacing={1}>
                      <Typography variant="body2" fontWeight="bold">
                        {entry.name}
                      </Typography>
                      <Chip size="small" label={`Seed ${entry.seed || "-"}`} />
                    </Stack>
                    <Typography variant="caption" color="text.secondary">
                      {isSingleEvent
                        ? `Rating: ${entry.rating}`
                        : `Rating đội: ${entry.rating}`}
                    </Typography>
                    <TournamentRegistrationRatingPanel
                      players={resolveTournamentEntryPlayers(entry, tenantPlayers)}
                      tournamentId={tournamentId}
                      hostClubId={tournamentClubId || activeClubId}
                      compact
                      onVerified={() => {
                        refreshClubs();
                        setLocalRevision((value) => value + 1);
                      }}
                    />
                  </Paper>
                )
              )}
            </Stack>
          </Paper>

          <TournamentEntryEditor
            entries={editorEntries}
            players={players}
            eventType={eventType}
            canIntervene={canInterveneSetup && editorEntries.length > 0}
            tournamentId={tournamentId}
            eventId={savedEvent?.id || ""}
            onApply={handleEntryInterventionApply}
            onAudit={pairingIntervention.auditEntryChange}
          />

          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Bảng đấu ({savedEvent?.groups?.length || 0})
            </Typography>
            {!savedEvent?.groups?.length ? (
              <Typography variant="body2" color="text.secondary">
                Chưa chia bảng. Chọn VĐV, đề xuất cặp rồi bấm &quot;Chia bảng&quot;.
              </Typography>
            ) : (
              <Stack spacing={1}>
                {savedEvent.groups.map((group) => (
                  <Paper key={group.id} variant="outlined" sx={{ p: 1.25 }}>
                    <Stack direction="row" justifyContent="space-between" alignItems="center">
                      <Typography fontWeight="bold">{group.name}</Typography>
                      <Chip
                        size="small"
                        label={`${group.entryIds?.length || 0} đội • ${group.matches?.length || 0} trận`}
                      />
                    </Stack>
                    <Typography variant="caption" color="text.secondary">
                      {(group.entries || []).map((entry) => entry.name).join(" | ")}
                    </Typography>
                  </Paper>
                ))}
                <DrawPublishControls
                  tournament={tournament}
                  groups={savedEvent.groups}
                  drawPublish={drawPublish}
                  hasReopenPermission={hasDrawReopenPermission}
                  onLock={handleLockDraw}
                  onPublish={handlePublishDraw}
                  onReopen={handleReopenDraw}
                  onForceRedraw={handleForceRedraw}
                  compact
                />
                <Button
                  component={RouterLink}
                  to={`/tournament/publish-schedule?tournamentId=${encodeURIComponent(tournamentId)}`}
                  variant="outlined"
                  size="small"
                  fullWidth
                >
                  Lịch thi đấu & công bố (S1-E)
                </Button>
              </Stack>
            )}
          </Paper>

          <TournamentGroupEditor
            groups={savedEvent?.groups || []}
            entries={savedEvent?.entries || editorEntries}
            players={players}
            canIntervene={canInterveneSetup && (savedEvent?.groups?.length || 0) > 0}
            tournamentId={tournamentId}
            eventId={savedEvent?.id || ""}
            onApply={handleGroupInterventionApply}
            onAudit={pairingIntervention.auditGroupChange}
          />
        </Grid>
      </Grid>

      {savedEvent?.groups?.length > 0 && (
        <Stack spacing={2} sx={{ mt: 2 }}>
          <GroupStagePanel
            event={savedEvent}
            players={players}
            onSubmitScore={handleSubmitGroupScore}
            draftScope={scoreDraftScope}
          />

          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Bảng xếp hạng vòng bảng
            </Typography>
            {groupStandings[0]?.tieBreakExplanation ? (
              <Typography variant="caption" color="text.secondary" display="block" sx={{ mb: 1 }}>
                Tie-break: {groupStandings[0].tieBreakExplanation}
                {groupStandings[0].source === "standings_v2" ? " · STANDINGS_V2" : " · Legacy"}
              </Typography>
            ) : null}
            {groupStandings.length === 0 ? (
              <Typography variant="body2" color="text.secondary">
                Chưa có kết quả trận vòng bảng. Nhập kết quả để tính BXH trước khi tạo bracket.
              </Typography>
            ) : (
              <Grid container spacing={1.5}>
                {groupStandings.map((groupStanding) => (
                  <Grid key={groupStanding.group} size={{ xs: 12, md: 6, lg: 3 }}>
                    <Paper variant="outlined" sx={{ p: 1.25 }}>
                      <Typography fontWeight="bold" sx={{ mb: 0.75 }}>
                        Bảng {groupStanding.group}
                      </Typography>
                      <Stack spacing={0.5}>
                        {groupStanding.standing.map((team, index) => (
                          <Typography
                            key={team.id}
                            variant="body2"
                            fontWeight={index < 2 ? "bold" : "regular"}
                          >
                            {index + 1}. {team.name} — {team.matchPoints} điểm
                            {team.qualificationStatus?.startsWith("qualified") ? " ✓ KO" : ""}
                          </Typography>
                        ))}
                      </Stack>
                    </Paper>
                  </Grid>
                ))}
              </Grid>
            )}
          </Paper>

          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Stack
              direction={{ xs: "column", sm: "row" }}
              spacing={1}
              justifyContent="space-between"
              alignItems={{ xs: "stretch", sm: "center" }}
              sx={{ mb: 1.5 }}
            >
              <Typography variant="subtitle1" fontWeight="bold">
                Sơ đồ knock-out
              </Typography>
              <Stack direction="row" spacing={1}>
                {savedEvent?.bracket?.rounds?.length > 0 && (
                  <Button
                    component={RouterLink}
                    to={`/tournament/internal/${tournamentId}/bracket`}
                    variant="outlined"
                  >
                    Mở sơ đồ đầy đủ
                  </Button>
                )}
                {!savedEvent?.bracket?.rounds?.length && (
                  <Button variant="contained" onClick={handleGenerateBracket}>
                    Tạo bracket từ BXH
                  </Button>
                )}
              </Stack>
            </Stack>

            {!savedEvent?.bracket?.rounds?.length ? (
              <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                Chưa có sơ đồ. Nhập điểm vòng bảng xong rồi bấm &quot;Tạo bracket từ BXH&quot;.
                Cần số bảng chẵn (2, 4, 8...).
              </Typography>
            ) : null}

            <BracketView
              progress={bracketProgress}
              unlockedRounds={savedEvent?.bracket?.unlockedRounds || {}}
              knockoutMatchesByBracketId={knockoutMatchesByBracketId}
              onSelectWinner={handleSelectBracketWinner}
              onToggleRoundLock={handleToggleRoundLock}
              onSubmitScore={handleSubmitKnockoutScore}
              onReset={handleResetBracket}
              canReset={Boolean(savedEvent?.bracket?.rounds?.length)}
              draftScope={scoreDraftScope}
            />
          </Paper>
        </Stack>
      )}

      <TournamentAnimationDialog
        {...flow.dialogProps}
        onFlowExit={handleFlowExit}
        broadcastStatus={broadcastFeatureEnabled ? broadcast.status : undefined}
        broadcastError={broadcastFeatureEnabled ? broadcast.error : undefined}
      />

      {broadcastFeatureEnabled ? (
        <BroadcastSetupDialog
          open={broadcastDialogOpen}
          tournamentId={tournamentId}
          config={broadcast.config}
          onChange={broadcast.updateConfig}
          onClose={() => setBroadcastDialogOpen(false)}
        />
      ) : null}

      {bracketAdvanceAnim && (
        <Box
          sx={{
            position: "fixed",
            bottom: 16,
            left: 16,
            right: 16,
            zIndex: 1300,
            maxWidth: 360,
            mx: "auto",
          }}
        >
          <BracketRevealAnimation
            animationMode={ANIMATION_MODES.BRACKET_ADVANCE}
            advanceHint={bracketAdvanceAnim}
            bracket={bracketAdvanceAnim.bracket}
            onAnimationComplete={() => setBracketAdvanceAnim(null)}
            onSkip={() => setBracketAdvanceAnim(null)}
          />
        </Box>
      )}

      {tournament && (
        <Box sx={{ mt: 3 }}>
          <TournamentCourtSchedulePanel
            clubId={tournamentClubId}
            tournament={tournament}
            courts={courts}
            onSaved={() => {
              refreshClubs();
              setLocalRevision((value) => value + 1);
            }}
          />
        </Box>
      )}
      </>
      )}
    </TournamentSetupShell>
    </TournamentManageGate>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Link as RouterLink, useNavigate, useParams, useSearchParams } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Chip,
  FormControl,
  FormControlLabel,
  Grid,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  Switch,
  Tab,
  Tabs,
  TextField,
  Typography,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";

import { useClub } from "../../context/ClubContext.jsx";
import { loadCourtsForClub, loadPlayersForClub } from "../../domain/clubStorage.js";
import TournamentVprPanel from "../../features/vpr-ranking/components/TournamentVprPanel.jsx";
import {
  getTournament,
  advanceTournamentStatus,
  updateTournament,
} from "../../domain/tournamentService.js";
import {
  EVENT_TYPE,
  OFFICIAL_MODE,
  TOURNAMENT_MODE,
  TOURNAMENT_STATUS,
  EVENT_TYPE_OPTIONS,
} from "../../models/tournament/index.js";
import { buildIndividualAllGroupStandings } from "../../features/individual-tournament/adapters/individualStandingsAdapter.js";
import {
  buildOfficialAiBalancePatch,
  buildOfficialAiBalancePlan,
  buildOfficialOpenPatch,
  buildOfficialOpenPlan,
  canGenerateBracket,
  createOfficialEventRecord,
  createOpenEntryFromPair,
  createOpenEntryFromPlayer,
  generateKnockoutBracket,
  isSingleEventType,
  resetBracketState,
  resolveBracketProgress,
  setBracketWinner,
  submitKnockoutMatchScore,
  submitTournamentDirectorMatchScore,
  suggestBalancedEntriesFromIndividuals,
  toggleBracketRoundUnlock,
  upsertOfficialEvent,
  validateOpenRegistrationPlayers,
} from "../../tournament/engines/index.js";
import BracketView from "../../components/tournament/BracketView.jsx";
import RefereeRosterPanel from "../../components/tournament/RefereeRosterPanel.jsx";
import GroupStagePanel from "../../components/tournament/GroupStagePanel.jsx";
import TournamentAnimationDialog from "../../components/tournament/animation/TournamentAnimationDialog.jsx";
import BracketRevealAnimation from "../../components/tournament/animation/BracketRevealAnimation.jsx";
import {
  ANIMATION_MODES,
  buildGroupMatchPairingSteps,
  buildPairingSteps,
  buildPairingWaitingPlayers,
  buildRandomDrawSteps,
  buildSnakeSteps,
  stripMatchesFromEvent,
} from "../../components/tournament/animation/animationUtils.js";
import {
  buildRefereeSettingsPatch,
  getRefereeSettings,
} from "../../tournament/engines/refereeEngine.js";
import { useTournamentAnimation } from "../../components/tournament/animation/useTournamentAnimation.js";
import { useTournamentFlowOrchestrator } from "../../components/tournament/animation/useTournamentFlowOrchestrator.js";
import { createOfficialFlowAdapters } from "../../components/tournament/animation/tournamentFlowAdapters.js";
import {
  BroadcastLiveIndicator,
  BroadcastSetupDialog,
  BroadcastVodResultAlert,
  isTournamentBroadcastEnabled,
  useTournamentBroadcast,
} from "../../features/tournament-broadcast/index.js";
import { resolveOfficialOpenPipeline } from "../../components/tournament/animation/shared/tournamentFlowConfig.js";
import { PAIRING_CONTROL_MODES } from "../../components/tournament/animation/pairing/usePairingSequence.js";
import TournamentManageGate from "../../components/tournament/TournamentManageGate.jsx";
import TournamentSetupShell from "../../components/tournament/TournamentSetupShell.jsx";
import TournamentSelectedPlayersPanel from "../../components/tournament/TournamentSelectedPlayersPanel.jsx";
import TournamentPlayerPickerPanel from "../../components/tournament/TournamentPlayerPickerPanel.jsx";
import TournamentPlayerQuickAddDialog from "../../components/tournament/TournamentPlayerQuickAddDialog.jsx";
import { getTenantPlayers } from "../../features/club/index.js";
import {
  resolveTournamentEntryPlayers,
  TournamentRegistrationRatingPanel,
} from "../../features/pick-vn-rating/index.js";
import {
  ALL_CLUBS_FILTER,
  filterTournamentPickerPlayers,
  formatPlayerPickerMeta,
} from "../../utils/tournamentPlayerPicker.js";
import { isAiEngineEnabled } from "../../features/ai-assistant/index.js";
import TournamentAiAssistantPanel from "../../components/tournament/ai/TournamentAiAssistantPanel.jsx";
import { useAuth } from "../../context/AuthContext.jsx";
import { canViewPlayerSkillLevel } from "../../auth/rbac.js";
import { useTenant } from "../../context/TenantContext.jsx";
import { resolveTenantIdForClub } from "../../features/tenant/guards/tenantGuard.js";
import {
  INTERVENTION_PHASE,
  TournamentEntryEditor,
  TournamentGroupEditor,
  usePairingIntervention,
} from "../../features/pairing-intervention/index.js";
import {
  FounderPairingConstraintsPanel,
  guardFounderConstraints,
  getTournamentPairingConstraints,
  logConstraintChange,
} from "../../features/pairing-constraints/index.js";
import DrawPublishControls from "../../components/tournament/DrawPublishControls.jsx";
import RegistrationOpsPanel from "../../components/tournament/RegistrationOpsPanel.jsx";
import {
  canRegenerateDraw,
  forceRedrawDraw,
  getDrawPublishStatus,
  lockDraw,
  publishDraw,
  recordDrawCreated,
  reopenDraw,
  resolveDrawReopenPermission,
  summarizeGroups,
} from "../../tournament/engines/publishDrawEngine.js";
import { resolveEventTypeFromQuery } from "../../features/individual-tournament/index.js";

const EVENT_OPTIONS = EVENT_TYPE_OPTIONS;

const OFFICIAL_MODE_OPTIONS = [
  { value: OFFICIAL_MODE.OPEN, label: "Open Mode" },
  { value: OFFICIAL_MODE.AI_BALANCE, label: "AI Balance Mode" },
];

export default function OfficialTournamentSetup() {
  const { tournamentId } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { activeClub, activeClubId, clubs, refreshClubs } = useClub();
  const { user, rbacEnabled, can } = useAuth();
  const { currentTenantId } = useTenant();
  const aiEnabled = isAiEngineEnabled();
  const [setupTab, setSetupTab] = useState(0);
  const [localRevision, setLocalRevision] = useState(0);
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [warnings, setWarnings] = useState([]);

  const [officialMode, setOfficialMode] = useState(OFFICIAL_MODE.OPEN);
  const [activeEventId, setActiveEventId] = useState("");
  const preselectedEvent = resolveEventTypeFromQuery(searchParams.get("event"));
  const [eventType, setEventType] = useState(preselectedEvent || EVENT_TYPE.MEN_DOUBLE);
  const [groupCount, setGroupCount] = useState(4);
  const [splitUnits, setSplitUnits] = useState(true);
  const [registeredEntries, setRegisteredEntries] = useState([]);
  const [selectedPlayerIds, setSelectedPlayerIds] = useState([]);
  const [sourceClubFilter, setSourceClubFilter] = useState(ALL_CLUBS_FILTER);
  const [previewEntries, setPreviewEntries] = useState([]);
  const [founderConstraints, setFounderConstraints] = useState([]);
  const [pairPlayerAId, setPairPlayerAId] = useState("");
  const [pairPlayerBId, setPairPlayerBId] = useState("");
  const [entryClubName, setEntryClubName] = useState("");
  const [pickerGenderFilter, setPickerGenderFilter] = useState("all");
  const [pickerSearch, setPickerSearch] = useState("");
  const [openClubFilter, setOpenClubFilter] = useState(ALL_CLUBS_FILTER);
  const [openRegistrationTab, setOpenRegistrationTab] = useState(0);
  const [quickAddOpen, setQuickAddOpen] = useState(false);
  const [bracketAdvanceAnim, setBracketAdvanceAnim] = useState(null);
  const anim = useTournamentAnimation();
  const pendingPlanRef = useRef(null);

  const canViewSkillInSetup = useMemo(
    () =>
      canViewPlayerSkillLevel(
        user,
        { clubId: activeClubId, tournamentId, tournamentContext: true },
        { rbacEnabled }
      ),
    [user, activeClubId, tournamentId, rbacEnabled]
  );

  const tournament = useMemo(
    () => getTournament(activeClubId, tournamentId),
    [activeClubId, tournamentId, localRevision]
  );

  useEffect(() => {
    if (tournament) {
      setFounderConstraints(getTournamentPairingConstraints(tournament));
    }
  }, [tournament?.id, tournament?.founderPairingConstraints]);

  const tenantId = useMemo(
    () => tournament?.tenantId || resolveTenantIdForClub(activeClubId) || currentTenantId || "",
    [tournament?.tenantId, activeClubId, currentTenantId]
  );

  const allTenantPlayers = useMemo(
    () => (tenantId ? getTenantPlayers(tenantId) : []),
    [tenantId, localRevision]
  );

  const players = useMemo(
    () => loadPlayersForClub(activeClubId),
    [activeClubId, localRevision]
  );

  const isAiBalance = officialMode === OFFICIAL_MODE.AI_BALANCE;

  const selectedPlayers = useMemo(() => {
    const pool = new Map(allTenantPlayers.map((player) => [String(player.id), player]));
    return selectedPlayerIds
      .map((id) => pool.get(String(id)))
      .filter(Boolean);
  }, [selectedPlayerIds, allTenantPlayers]);

  const flowPlayers = allTenantPlayers;

  const courts = useMemo(
    () => loadCourtsForClub(activeClubId),
    [activeClubId, localRevision]
  );

  const refereeRoster = useMemo(
    () => getRefereeSettings(tournament).roster,
    [tournament, localRevision]
  );

  const savedEvents = tournament?.events || [];
  const savedEvent =
    savedEvents.find((event) => String(event.id) === String(activeEventId)) ||
    savedEvents[0] ||
    null;

  const displayEntries = isAiBalance
    ? previewEntries.length > 0
      ? previewEntries
      : savedEvent?.entries || []
    : registeredEntries.length > 0
      ? registeredEntries
      : savedEvent?.entries || [];

  const registeredPlayerIds = useMemo(() => {
    const ids = new Set();
    displayEntries.forEach((entry) => {
      (entry.playerIds || []).forEach((id) => ids.add(String(id)));
    });
    return Array.from(ids);
  }, [displayEntries]);

  const openFilteredPlayers = useMemo(
    () =>
      filterTournamentPickerPlayers(allTenantPlayers, {
        clubFilter: openClubFilter,
        genderFilter: pickerGenderFilter,
        search: pickerSearch,
        eventType,
        excludePlayerIds: registeredPlayerIds,
      }),
    [allTenantPlayers, openClubFilter, pickerGenderFilter, pickerSearch, eventType, registeredPlayerIds]
  );

  const groupStandings = useMemo(
    () => (savedEvent ? buildIndividualAllGroupStandings(savedEvent) : []),
    [savedEvent]
  );

  const bracketProgress = useMemo(
    () => (savedEvent ? resolveBracketProgress(savedEvent) : null),
    [savedEvent]
  );

  const knockoutMatchesByBracketId = useMemo(() => {
    const map = {};
    (savedEvent?.matches || []).forEach((match) => {
      if (match.bracketMatchId) {
        map[match.bracketMatchId] = match;
      }
    });
    return map;
  }, [savedEvent]);

  const scoreDraftScope = useMemo(
    () => ({
      clubId: activeClubId,
      tournamentId,
      eventId: savedEvent?.id,
    }),
    [activeClubId, tournamentId, savedEvent?.id]
  );

  useEffect(() => {
    if (tournament?.officialMode) {
      setOfficialMode(tournament.officialMode);
    }
  }, [tournament?.officialMode]);

  useEffect(() => {
    if (!activeEventId && savedEvents[0]?.id) {
      setActiveEventId(savedEvents[0].id);
    }
  }, [activeEventId, savedEvents]);

  const persistTournament = (patch, options = {}) => {
    const { status, ...dataPatch } = patch;
    const result = status
      ? advanceTournamentStatus(activeClubId, tournamentId, status, dataPatch)
      : updateTournament(activeClubId, tournamentId, patch, options);

    if (!result.ok) {
      setError(result.error);
      return false;
    }

    setLocalRevision((value) => value + 1);
    refreshClubs();
    return true;
  };

  const persistEvent = (nextEvent, options = {}) => {
    if (!savedEvent) {
      return false;
    }

    const { processMatchId, ...extraPatch } = options;
    const events = upsertOfficialEvent(savedEvents, { ...savedEvent, ...nextEvent });
    return persistTournament(
      {
        events,
        ...extraPatch,
      },
      {
        processMatchId: processMatchId || null,
        processEventId: savedEvent?.id || null,
      }
    );
  };

  const pairingIntervention = usePairingIntervention({
    phase: INTERVENTION_PHASE.TOURNAMENT,
    tournamentStatus: tournament?.status,
    clubId: activeClubId,
    resourceId: tournamentId,
  });

  const canInterveneSetup = pairingIntervention.canIntervene;

  const drawPublish = useMemo(
    () => getDrawPublishStatus(tournament),
    [tournament, localRevision]
  );

  const hasDrawReopenPermission = useMemo(
    () =>
      resolveDrawReopenPermission({
        canPermission: can,
        rbacEnabled,
        canIntervene: canInterveneSetup,
      }),
    [can, rbacEnabled, canInterveneSetup]
  );

  const buildDrawActor = () =>
    user
      ? { id: user.id, email: user.email || "", name: user.displayName || user.name || "" }
      : null;

  const handleLockDraw = () => {
    setError(null);
    const groups = savedEvent?.groups || [];
    const result = lockDraw(tournament, groups, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: activeClubId,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    if (persistTournament({ settings: result.tournament.settings })) {
      setMessage("Đã khóa bốc thăm. Sẵn sàng công bố.");
    }
  };

  const handlePublishDraw = () => {
    setError(null);
    const groups = savedEvent?.groups || [];
    const result = publishDraw(tournament, groups, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: activeClubId,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    const events = (savedEvents || []).map((event) =>
      String(event.id) === String(savedEvent?.id)
        ? { ...event, groups: result.snapshot || groups }
        : event
    );
    if (
      persistTournament({
        settings: result.tournament.settings,
        events,
      })
    ) {
      setMessage("Đã công bố bốc thăm. Bracket bất biến.");
    }
  };

  const handleReopenDraw = () => {
    setError(null);
    const result = reopenDraw(tournament, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: activeClubId,
      hasReopenPermission: hasDrawReopenPermission,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    if (persistTournament({ settings: result.tournament.settings })) {
      setMessage("Đã mở lại bốc thăm để chỉnh sửa.");
    }
  };

  const handleForceRedraw = () => {
    setError(null);
    const result = forceRedrawDraw(tournament, {
      userId: user?.id,
      actor: buildDrawActor(),
      clubId: activeClubId,
      hasReopenPermission: hasDrawReopenPermission,
    });
    if (!result.ok) {
      setError(result.error);
      return;
    }
    if (persistTournament({ settings: result.tournament.settings })) {
      setMessage("Force redraw được phép. Bạn có thể random lại.");
    }
  };

  const handleEntryInterventionApply = (result) => {
    if (!result?.ok) {
      return;
    }
    setPreviewEntries(result.entries);
    if (savedEvent?.entries?.length) {
      persistEvent({ entries: result.entries });
    }
    setMessage("Super Admin đã cập nhật ghép cặp.");
  };

  const handleGroupInterventionApply = (result) => {
    if (!result?.ok) {
      return;
    }
    if (
      persistEvent({
        entries: result.entries,
        groups: result.groups,
        matches: result.matches,
      })
    ) {
      setMessage("Super Admin đã cập nhật chia bảng và tạo lại lịch vòng bảng.");
    }
  };

  const handleSaveFounderConstraints = async () => {
    setError(null);
    const guard = guardFounderConstraints({ user });
    if (!guard.ok) {
      setError(guard.error);
      return;
    }

    const before = getTournamentPairingConstraints(tournament);
    const result = updateTournament(activeClubId, tournamentId, {
      founderPairingConstraints: founderConstraints,
    });

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setLocalRevision((value) => value + 1);
    setMessage("Đã lưu quy tắc ghép cặp Founder.");
    await logConstraintChange({
      user,
      tournamentId,
      clubId: activeClubId,
      before,
      after: founderConstraints,
    });
  };

  const applyConstraintWarnings = (pairingOptions) => {
    const constraintWarnings = pairingOptions?.constraintWarnings || [];
    if (constraintWarnings.length > 0) {
      setWarnings(
        constraintWarnings.map((item) =>
          typeof item === "string" ? item : item.message || String(item)
        )
      );
    }
  };

  const flowAdapters = useMemo(() => {
    const shared = {
      tournament,
      players: flowPlayers,
      courts,
      selectedPlayerIds,
      eventType,
      groupCount,
      isAiBalance,
      displayEntries,
      persistTournament,
      persistEvent,
      setPreviewEntries,
      setWarnings,
      setMessage,
      setError,
      setLocalRevision,
      refreshClubs,
      getSavedEvent: () => savedEvent,
    };

    if (isAiBalance) {
      return createOfficialFlowAdapters({
        ...shared,
        variant: "ai_balance",
        suggestEntries: (selected, et) =>
          suggestBalancedEntriesFromIndividuals(selected, et, {
            tournamentId,
            eventId: savedEvent?.id || `event-${tournamentId}`,
          }),
        buildPlan: ({ manualEntries }) =>
          buildOfficialAiBalancePlan({
            tournament,
            eventId: savedEvent?.id,
            players: flowPlayers,
            selectedPlayerIds,
            eventType,
            groupCount,
            manualEntries,
            individualRegistration: true,
          }),
        buildPatch: buildOfficialAiBalancePatch,
      });
    }

    return createOfficialFlowAdapters({
      ...shared,
      variant: "open",
      isAiBalance: false,
      suggestEntries: () => displayEntries,
      buildPlan: () =>
        buildOfficialOpenPlan({
          tournament: {
            ...tournament,
            hostClubName: tournament.hostClubName || activeClub?.name || "",
          },
          entries: displayEntries,
          eventType,
          eventId: savedEvent?.id,
          groupCount,
          players: flowPlayers,
          splitUnits,
        }),
      buildPatch: buildOfficialOpenPatch,
    });
  }, [
    isAiBalance,
    tournament,
    flowPlayers,
    courts,
    selectedPlayerIds,
    eventType,
    groupCount,
    displayEntries,
    savedEvent,
    splitUnits,
    activeClub,
    tournamentId,
    refreshClubs,
    persistTournament,
    persistEvent,
  ]);

  const flow = useTournamentFlowOrchestrator(anim, flowAdapters);

  const broadcastFeatureEnabled = isTournamentBroadcastEnabled();
  const broadcast = useTournamentBroadcast({
    tournamentId,
    tournamentName: tournament?.name || "Giải đấu",
    clubId: activeClubId,
  });
  const [broadcastDialogOpen, setBroadcastDialogOpen] = useState(false);

  const handleFlowExit = useCallback(async () => {
    if (broadcastFeatureEnabled) {
      const stopResult = await broadcast.stopBroadcast();
      if (stopResult?.ok === false && stopResult?.error) {
        setError(stopResult.error);
      }
    }
    flow.exitFlow();
  }, [broadcast, broadcastFeatureEnabled, flow]);

  const handleStartGuidedFlow = async () => {
    setError(null);
    setWarnings([]);
    setMessage(null);

    if (broadcastFeatureEnabled && broadcast.shouldBroadcastWithFlow) {
      const broadcastResult = await broadcast.startBroadcast();
      if (broadcastResult?.ok === false) {
        setError(broadcastResult.error || "Không thể bắt đầu phát live.");
        return;
      }
    }

    const pipeline = isAiBalance
      ? undefined
      : resolveOfficialOpenPipeline({
          includeBracket: savedEvent ? canGenerateBracket(savedEvent).ok : true,
        });

    const result = flow.startFlow({}, { pipeline });
    if (result?.ok === false) {
      if (broadcastFeatureEnabled && broadcast.isLive) {
        await broadcast.stopBroadcast();
      }
      setError(result.error || "Không thể bắt đầu trình chiếu.");
    }
  };

  const handleRefereeRosterChange = (nextRoster) => {
    const result = updateTournament(
      activeClubId,
      tournamentId,
      buildRefereeSettingsPatch(tournament, { roster: nextRoster })
    );

    if (!result.ok) {
      setError(result.error);
      return;
    }

    setLocalRevision((value) => value + 1);
    refreshClubs();
    setMessage("Đã cập nhật danh sách trọng tài.");
  };

  const handleOfficialModeChange = (nextMode) => {
    setOfficialMode(nextMode);
    setPreviewEntries([]);
    setRegisteredEntries([]);
    setSelectedPlayerIds([]);
    persistTournament({ officialMode: nextMode });
  };

  const handleAddEvent = () => {
    const newEvent = createOfficialEventRecord(tournament, { eventType });
    const events = [...savedEvents, newEvent];
    if (persistTournament({ events })) {
      setActiveEventId(newEvent.id);
      setMessage(`Da them noi dung "${newEvent.name}".`);
    }
  };

  const toggleAiPlayer = (playerId) => {
    const key = String(playerId);
    setSelectedPlayerIds((current) =>
      current.includes(key) ? current.filter((id) => id !== key) : [...current, key]
    );
  };

  const handleSelectAllAiPlayers = (playerIds = []) => {
    setSelectedPlayerIds((current) => {
      const merged = new Set([...current, ...playerIds.map(String)]);
      return Array.from(merged);
    });
  };

  const handleClearAllAiPlayers = () => {
    setSelectedPlayerIds([]);
  };

  const handleQuickAddSaved = (player) => {
    refreshClubs();
    setLocalRevision((value) => value + 1);

    if (isAiBalance) {
      setSelectedPlayerIds((current) =>
        current.includes(String(player.id)) ? current : [...current, String(player.id)]
      );
      setMessage(`Đã thêm và chọn ${player.name}.`);
      return;
    }

    if (!isAiBalance && isSingleEventType(eventType)) {
      registerPlayerEntry(player);
      return;
    }

    setMessage(`Đã thêm ${player.name}. Chọn VĐV trong dropdown để đăng ký cặp.`);
  };

  const registerPlayerEntry = (player) => {
    const validation = validateOpenRegistrationPlayers([player], eventType);
    if (!validation.ok) {
      setError(validation.errors.join(" "));
      return false;
    }

    const entry = createOpenEntryFromPlayer(player, {
      tournamentId,
      eventId: savedEvent?.id || `event-${tournamentId}`,
      clubName: entryClubName || player.clubName || activeClub?.name || "",
    });

    if (displayEntries.some((item) => item.id === entry.id)) {
      setError("VDV da dang ky.");
      return false;
    }

    setRegisteredEntries([...displayEntries, entry]);
    setMessage(`Da dang ky ${player.name}.`);
    return true;
  };

  const handleRemoveSelectedAiPlayer = (playerId) => {
    const key = String(playerId);
    setSelectedPlayerIds((current) => current.filter((id) => id !== key));
  };

  const handleSourceClubFilterChange = (value) => {
    setSourceClubFilter(value);
    setSelectedPlayerIds([]);
    setPreviewEntries([]);
  };

  const handleSuggestAiPairs = () => {
    setError(null);
    setWarnings([]);

    const pairingOptions = {
      tournamentId,
      eventId: savedEvent?.id || `event-${tournamentId}`,
      pairingConstraints: founderConstraints,
    };

    const entries = suggestBalancedEntriesFromIndividuals(selectedPlayers, eventType, pairingOptions);

    applyConstraintWarnings(pairingOptions);

    if (entries.length === 0) {
      setError("Khong tao duoc cap/VDV nao. Kiem tra gioi tinh va so luong da chon.");
      return;
    }

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.PAIRING_REVEAL,
        pairings: entries,
        steps: buildPairingSteps(entries),
        waitingPlayers: buildPairingWaitingPlayers(entries, selectedPlayers),
        title: "Ghép cặp AI Balance",
        subtitle: "Reveal từng cặp — danh sách chờ hiển thị từng VĐV",
        revealItemLabel: "Cặp",
      },
      () => {
        setPreviewEntries(entries);
        setMessage(`Da de xuat ${entries.length} cap/VDV theo rating.`);
      }
    );
  };

  const handleBuildAiGroups = () => {
    setError(null);
    setWarnings([]);
    setMessage(null);

    const pairingOptions = {
      tournamentId,
      eventId: savedEvent?.id || `event-${tournamentId}`,
      pairingConstraints: founderConstraints,
    };

    const entries =
      previewEntries.length > 0
        ? previewEntries
        : suggestBalancedEntriesFromIndividuals(selectedPlayers, eventType, pairingOptions);

    if (previewEntries.length === 0) {
      applyConstraintWarnings(pairingOptions);
    }

    const plan = buildOfficialAiBalancePlan({
      tournament,
      eventId: savedEvent?.id,
      players: flowPlayers,
      selectedPlayerIds,
      eventType,
      groupCount,
      manualEntries: entries,
      individualRegistration: true,
      pairingConstraints: founderConstraints,
    });

    if (!plan.ok) {
      setError(plan.errors?.join(" "));
      setWarnings(plan.warnings || []);
      return;
    }

    const steps = buildSnakeSteps({
      entries: plan.event.entries,
      players: selectedPlayers,
      groupCount,
      finalGroups: plan.event.groups,
    });

    pendingPlanRef.current = plan;

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.SNAKE_GROUP,
        groups: plan.event.groups,
        steps,
        matchCount: plan.matchCount,
        onStartMatchPairing: () => openMatchPairingAnimation(plan),
      },
      () => {
        const patch = buildOfficialAiBalancePatch(tournament, plan);
        if (!patch.ok) {
          setError(patch.error || "Khong luu duoc bang dau.");
          return;
        }

        const events = patch.events.map((event) =>
          String(event.id) === String(patch.event?.id)
            ? stripMatchesFromEvent(event)
            : event
        );

        const saved = persistTournament({
          events,
          officialMode: OFFICIAL_MODE.AI_BALANCE,
          status: TOURNAMENT_STATUS.READY,
          settings: {
            ...(tournament.settings || {}),
            aiBalance: {
              updatedAt: new Date().toISOString(),
            },
          },
        });

        if (!saved) {
          return;
        }

        setPreviewEntries([]);
        setWarnings(patch.warnings || []);
        setActiveEventId(patch.event.id);
        setMessage(`Đã chia ${patch.event.groups.length} bảng. Bấm "Ghép cặp thi đấu" trên màn hình kết quả.`);
      }
    );
  };

  const handleRegisterSingle = (playerId, playerOverride = null) => {
    setError(null);
    const player =
      playerOverride ||
      allTenantPlayers.find((item) => String(item.id) === String(playerId));
    if (!player) {
      return;
    }

    registerPlayerEntry(player);
  };

  const handleRegisterPair = () => {
    setError(null);
    const playerA = allTenantPlayers.find((item) => String(item.id) === String(pairPlayerAId));
    const playerB = allTenantPlayers.find((item) => String(item.id) === String(pairPlayerBId));

    if (!playerA || !playerB) {
      setError("Chon du 2 VDV de dang ky cap.");
      return;
    }

    if (String(playerA.id) === String(playerB.id)) {
      setError("Cap phai gom 2 VDV khac nhau.");
      return;
    }

    const validation = validateOpenRegistrationPlayers([playerA, playerB], eventType);
    if (!validation.ok) {
      setError(validation.errors.join(" "));
      return;
    }

    const entry = createOpenEntryFromPair(playerA, playerB, {
      tournamentId,
      eventId: savedEvent?.id || `event-${tournamentId}`,
      clubName: entryClubName || playerA.clubName || playerB.clubName || activeClub?.name || "",
    });

    const duplicatePlayer = displayEntries.some((item) =>
      (item.playerIds || []).some((id) => entry.playerIds.includes(String(id)))
    );

    if (duplicatePlayer) {
      setError("Mot trong hai VDV da dang ky noi dung khac.");
      return;
    }

    setRegisteredEntries([...displayEntries, entry]);
    setPairPlayerAId("");
    setPairPlayerBId("");
    setMessage(`Da dang ky cap ${entry.name}.`);
  };

  const handleRemoveEntry = (entryId) => {
    setRegisteredEntries(displayEntries.filter((entry) => entry.id !== entryId));
  };

  const handleDrawGroups = (isRedraw = false) => {
    setError(null);
    setWarnings([]);
    setMessage(null);

    if (isRedraw) {
      const regenCheck = canRegenerateDraw(tournament);
      if (!regenCheck.ok) {
        setError(regenCheck.error);
        return;
      }
    }

    if (displayEntries.length < 2) {
      setError("Can it nhat 2 doi/VDV da dang ky.");
      return;
    }

    const plan = buildOfficialOpenPlan({
      tournament: {
        ...tournament,
        hostClubName: tournament.hostClubName || activeClub?.name || "",
      },
      entries: displayEntries,
      eventType,
      eventId: savedEvent?.id,
      groupCount,
      players: flowPlayers,
      splitUnits,
    });

    if (!plan.ok) {
      setError(plan.errors?.join(" "));
      setWarnings(plan.warnings || []);
      return;
    }

    const patch = buildOfficialOpenPatch(tournament, plan);
    if (!patch.ok) {
      setError(patch.error || "Khong luu duoc bang dau.");
      return;
    }

    const steps = buildRandomDrawSteps(plan.event.groups);

    pendingPlanRef.current = plan;

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.RANDOM_DRAW,
        steps,
        groups: plan.event.groups,
        matchCount: plan.matchCount,
        onStartMatchPairing: () => openMatchPairingAnimation(plan),
      },
      () => {
        pendingPlanRef.current = plan;

        const events = patch.events.map((event) =>
          String(event.id) === String(patch.event?.id)
            ? stripMatchesFromEvent(event)
            : event
        );

        const saved = persistTournament({
          events,
          officialMode: OFFICIAL_MODE.OPEN,
          hostClubName: tournament.hostClubName || activeClub?.name || "",
          status: TOURNAMENT_STATUS.READY,
          settings: {
            ...(tournament.settings || {}),
            openDraw: {
              splitUnits,
              drawScore: patch.drawScore,
              updatedAt: new Date().toISOString(),
            },
          },
        });

        if (!saved) {
          return;
        }

        const created = recordDrawCreated(
          getTournament(activeClubId, tournamentId),
          patch.events[0]?.groups || [],
          {
            userId: user?.id,
            actor: buildDrawActor(),
            clubId: activeClubId,
            before: isRedraw ? summarizeGroups(savedEvent?.groups || []) : null,
          }
        );
        if (created.ok) {
          persistTournament({ settings: created.tournament.settings });
        }

        setRegisteredEntries([]);
        setWarnings(patch.warnings || []);
        if (patch.event?.id) {
          setActiveEventId(patch.event.id);
        }
        setMessage(
          isRedraw
            ? `Đã random lại ${patch.events[0].groups.length} bảng. Bấm "Ghép cặp thi đấu" trên màn hình kết quả.`
            : `Đã chia ${patch.events[0].groups.length} bảng. Bấm "Ghép cặp thi đấu" trên màn hình kết quả.`
        );
      }
    );
  };

  const persistMatchPairing = (plan) => {
    if ((savedEvent?.matches?.length || 0) > 0) {
      return true;
    }

    if (isAiBalance) {
      const patch = buildOfficialAiBalancePatch(tournament, plan);
      if (!patch.ok) {
        setError(patch.error || "Không lưu được lịch thi đấu.");
        return false;
      }

      const saved = persistTournament({
        events: patch.events,
        officialMode: OFFICIAL_MODE.AI_BALANCE,
        status: TOURNAMENT_STATUS.READY,
      });

      if (!saved) {
        return false;
      }
    } else {
      const patch = buildOfficialOpenPatch(tournament, plan);
      if (!patch.ok) {
        setError(patch.error || "Không lưu được lịch thi đấu.");
        return false;
      }

      const saved = persistTournament({
        events: patch.events,
        officialMode: OFFICIAL_MODE.OPEN,
        hostClubName: tournament.hostClubName || activeClub?.name || "",
        status: TOURNAMENT_STATUS.READY,
      });

      if (!saved) {
        return false;
      }
    }

    pendingPlanRef.current = null;
    setLocalRevision((value) => value + 1);
    refreshClubs();
    setMessage(`Đã ghép ${plan.matchCount} trận vòng bảng. Xem lịch bên dưới.`);
    return true;
  };

  const openMatchPairingAnimation = (plan) => {
    if (!plan?.ok || !plan.event?.groups?.length) {
      setError("Chưa có bảng đấu để ghép cặp.");
      return;
    }

    const steps = buildGroupMatchPairingSteps({
      groups: plan.event.groups,
      matches: plan.event.matches,
      entries: plan.event.entries,
      courts,
    });

    if (!steps.length) {
      setError("Không có trận đấu để ghép cặp.");
      return;
    }

    anim.transitionAnimation(
      {
        animationMode: ANIMATION_MODES.GROUP_MATCH_PAIRING,
        tournamentName: tournament.name,
        groups: plan.event.groups,
        entries: plan.event.entries,
        steps,
        courts,
        autoStart: true,
        controlMode: PAIRING_CONTROL_MODES.AUTO,
        autoNextGroup: true,
      },
      () => {
        persistMatchPairing(plan);
      }
    );
  };

  const handleGenerateBracket = () => {
    setError(null);
    const check = canGenerateBracket(savedEvent);
    if (!check.ok) {
      setError(check.errors.join(" "));
      return;
    }

    const generated = generateKnockoutBracket(savedEvent);
    if (!generated.ok) {
      setError(generated.errors?.join(" ") || "Khong tao duoc bracket.");
      return;
    }

    const progress = resolveBracketProgress(generated.event);

    anim.showAnimation(
      {
        animationMode: ANIMATION_MODES.BRACKET_REVEAL,
        bracket: progress,
      },
      () => {
        if (persistEvent(generated.event)) {
          setWarnings(generated.warnings || []);
          setMessage(`Da tao bracket knock-out (${generated.knockoutMatchCount} tran).`);
        }
      }
    );
  };

  const handleSelectBracketWinner = (bracketMatchId, winnerSide) => {
    const result = setBracketWinner(savedEvent, bracketMatchId, winnerSide || null);
    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (winnerSide) {
      const progress = resolveBracketProgress(result.event);
      const match = progress.rounds
        .flatMap((round) => round.matches)
        .find((item) => item.id === bracketMatchId);
      const winnerName =
        winnerSide === "home"
          ? match?.home?.name || match?.homeSeed
          : match?.away?.name || match?.awaySeed;

      setBracketAdvanceAnim({
        winnerName,
        bracket: progress,
      });
    } else {
      setBracketAdvanceAnim(null);
    }

    if (persistEvent(result.event)) {
      setMessage(winnerSide ? "Da cap nhat winner." : "Da xoa winner.");
    }
  };

  const handleSubmitGroupScore = (matchId, scores) => {
    const result = submitTournamentDirectorMatchScore(savedEvent, matchId, scores);
    if (!result.ok) {
      setError(result.error);
      return false;
    }

    if (persistEvent(result.event, { processMatchId: matchId })) {
      if (result.bracketAutoGenerated) {
        setMessage(
          `Đã lưu kết quả vòng bảng. Tự động tạo bracket knock-out (${result.bracketKnockoutMatchCount} trận).`
        );
      } else {
        setMessage("Đã lưu kết quả vòng bảng.");
      }
      return true;
    }

    return false;
  };

  const handleSubmitKnockoutScore = (matchId, scores) => {
    const result = submitKnockoutMatchScore(savedEvent, matchId, scores);
    if (!result.ok) {
      setError(result.error);
      return false;
    }

    if (persistEvent(result.event, { processMatchId: matchId })) {
      setMessage("Da luu ket qua knock-out.");
      return true;
    }

    return false;
  };

  const handleToggleRoundLock = (roundName, unlock) => {
    const result = toggleBracketRoundUnlock(savedEvent, roundName, unlock);
    if (!result.ok) {
      setError(result.error);
      return;
    }

    if (persistEvent(result.event)) {
      setMessage(unlock ? `Da mo khoa vong ${roundName}.` : `Da khoa vong ${roundName}.`);
    }
  };

  const handleResetBracket = () => {
    const confirmed = window.confirm("Reset bracket knock-out?");
    if (!confirmed) {
      return;
    }

    if (persistEvent(resetBracketState(savedEvent))) {
      setMessage("Da reset bracket.");
    }
  };

  if (!tournament) {
    return (
      <Box>
        <Alert severity="error">Khong tim thay giai.</Alert>
        <Button component={RouterLink} to="/tournament" sx={{ mt: 2 }}>
          Quay lai
        </Button>
      </Box>
    );
  }

  if (tournament.mode !== TOURNAMENT_MODE.OFFICIAL_TOURNAMENT) {
    return (
      <Box>
        <Alert severity="warning">Giai nay khong phai che do chinh thuc.</Alert>
        <Button component={RouterLink} to="/tournament" sx={{ mt: 2 }}>
          Quay lai
        </Button>
      </Box>
    );
  }

  const modeLabel = isAiBalance ? "AI Balance Mode" : "Open Mode";
  const modeDescription = isAiBalance
    ? "Ghép cặp theo rating, hạt giống snake seeding, hỗ trợ nhiều nội dung thi đấu"
    : "Random có điều kiện, không dùng rating/seed";

  return (
    <TournamentManageGate tournamentId={tournamentId}>
    <TournamentSetupShell
      tournament={tournament}
      description={`Giải chính thức — ${modeLabel} (${modeDescription})`}
      onBack={() => navigate("/tournament")}
      headerActions={
        savedEvent?.matches?.length > 0 ? (
          <Button
            variant="outlined"
            onClick={() =>
              navigate(
                `/tournament/director/${tournamentId}?eventId=${encodeURIComponent(savedEvent.id)}`
              )
            }
          >
            Mở Director Mode
          </Button>
        ) : null
      }
      alerts={
        <>
          {broadcastFeatureEnabled && broadcast.lastVodUpload ? (
            <BroadcastVodResultAlert
              result={broadcast.lastVodUpload}
              onClose={broadcast.clearLastVodUpload}
            />
          ) : null}
          {message && (
            <Alert severity="success" sx={{ mb: 2 }} onClose={() => setMessage(null)}>
              {message}
            </Alert>
          )}
          {error && (
            <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
              {error}
            </Alert>
          )}
          {warnings.length > 0 && (
            <Alert severity="warning" sx={{ mb: 2 }}>
              {warnings.join(" ")}
            </Alert>
          )}
        </>
      }
      setupTab={setupTab}
      onSetupTabChange={(_, value) => setSetupTab(value)}
      showAiTab={aiEnabled}
    >
      <Paper variant="outlined" sx={{ p: 1.5, mb: 2 }}>
        <Grid container spacing={2} alignItems="center">
          <Grid size={{ xs: 12, md: 4 }}>
            <FormControl fullWidth size="small">
              <InputLabel>Chế độ giải</InputLabel>
              <Select
                label="Chế độ giải"
                value={officialMode}
                onChange={(event) => handleOfficialModeChange(event.target.value)}
              >
                {OFFICIAL_MODE_OPTIONS.map((option) => (
                  <MenuItem key={option.value} value={option.value}>
                    {option.label}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
          <Grid size={{ xs: 12, md: 8 }}>
            <Stack direction="row" spacing={1} alignItems="center" flexWrap="wrap">
              <Tabs
                value={savedEvent?.id || false}
                onChange={(_, value) => setActiveEventId(value)}
                variant="scrollable"
                scrollButtons="auto"
                sx={{ flexGrow: 1, minHeight: 40 }}
              >
                {savedEvents.map((event) => (
                  <Tab
                    key={event.id}
                    value={event.id}
                    label={`${event.name} (${event.entries?.length || 0})`}
                  />
                ))}
              </Tabs>
              <Button size="small" variant="outlined" onClick={handleAddEvent}>
                Thêm nội dung
              </Button>
            </Stack>
          </Grid>
        </Grid>
      </Paper>

      <TournamentVprPanel
        clubId={activeClubId}
        tournament={tournament}
        onUpdated={() => {
          setLocalRevision((value) => value + 1);
          refreshClubs();
        }}
      />

      {aiEnabled && setupTab === 1 ? (
        <TournamentAiAssistantPanel
          tournamentId={tournamentId}
          clubId={activeClubId}
          tenantId={currentTenantId || tournament?.tenantId || resolveTenantIdForClub(activeClubId)}
          players={players}
          courts={courts}
          userId={user?.id || ""}
          onApplied={() => {
            setLocalRevision((v) => v + 1);
            refreshClubs();
            setMessage("Đã áp dụng đề xuất AI.");
          }}
        />
      ) : (
      <>
      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12 }}>
          <RefereeRosterPanel roster={refereeRoster} onChange={handleRefereeRosterChange} />
        </Grid>
        {isAiBalance ? (
          <Grid size={{ xs: 12 }}>
            <FounderPairingConstraintsPanel
              constraints={founderConstraints}
              players={flowPlayers}
              onChange={setFounderConstraints}
              onSave={handleSaveFounderConstraints}
            />
          </Grid>
        ) : null}
        <Grid size={{ xs: 12 }}>
          <RegistrationOpsPanel
            tournament={tournament}
            event={savedEvent}
            players={flowPlayers}
            actor={
              user
                ? { id: user.id, email: user.email || "", name: user.displayName || user.name || "" }
                : null
            }
            clubId={activeClubId}
            onPersist={(nextTournament) =>
              persistTournament({
                events: nextTournament.events,
                settings: nextTournament.settings,
                status: nextTournament.status,
              })
            }
          />
        </Grid>
      </Grid>

      <Grid container spacing={2} sx={{ mb: 2 }}>
        <Grid size={{ xs: 12, md: 3 }}>
          <FormControl fullWidth size="small">
            <InputLabel>Nội dung</InputLabel>
            <Select
              label="Nội dung"
              value={eventType}
              onChange={(event) => setEventType(event.target.value)}
            >
              {EVENT_OPTIONS.map((option) => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid size={{ xs: 12, md: 3 }}>
          <TextField
            fullWidth
            size="small"
            type="number"
            label="Số bảng"
            value={groupCount}
            inputProps={{ min: 1, max: 16 }}
            onChange={(event) => setGroupCount(Number(event.target.value) || 1)}
          />
        </Grid>
        <Grid size={{ xs: 12, md: 3 }}>
          {!isAiBalance && (
            <TextField
              fullWidth
              size="small"
              label="CLB đại diện (mặc định)"
              value={entryClubName}
              onChange={(event) => setEntryClubName(event.target.value)}
              placeholder={activeClub?.name || "CLB chủ nhà"}
            />
          )}
        </Grid>
        <Grid size={{ xs: 12, md: 3 }}>
          {!isAiBalance ? (
            <FormControlLabel
              control={
                <Switch
                  checked={splitUnits}
                  onChange={(event) => setSplitUnits(event.target.checked)}
                />
              }
              label="Tách đơn vị/công ty"
            />
          ) : (
            <Chip label="Snake seeding theo hạt giống" color="info" />
          )}
        </Grid>
      </Grid>

      {isAiBalance ? (
        <Grid container spacing={2}>
          <Grid size={{ xs: 12, lg: 4 }}>
            <Paper variant="outlined" sx={{ p: 1.5, mb: 2 }}>
              <TournamentPlayerPickerPanel
                title="Chọn VĐV đăng ký cá nhân"
                players={allTenantPlayers}
                selectedIds={selectedPlayerIds}
                onToggle={toggleAiPlayer}
                onSelectAll={handleSelectAllAiPlayers}
                onClearAll={handleClearAllAiPlayers}
                clubFilter={sourceClubFilter}
                onClubFilterChange={handleSourceClubFilterChange}
                clubs={clubs}
                genderFilter={pickerGenderFilter}
                onGenderFilterChange={setPickerGenderFilter}
                search={pickerSearch}
                onSearchChange={setPickerSearch}
                eventType={eventType}
                onAddNew={() => setQuickAddOpen(true)}
                showSkillLevel={canViewSkillInSetup}
                emptyMessage={
                  sourceClubFilter === ALL_CLUBS_FILTER
                    ? "Chưa có VĐV trong tenant."
                    : "CLB này chưa có VĐV."
                }
              />
            </Paper>
            <Stack spacing={1}>
              <Button
                fullWidth
                variant="contained"
                color="secondary"
                onClick={handleStartGuidedFlow}
                disabled={selectedPlayerIds.length === 0}
              >
                Bắt đầu trình chiếu
              </Button>
              {broadcastFeatureEnabled ? (
                <>
                  <Button
                    fullWidth
                    variant="outlined"
                    onClick={() => setBroadcastDialogOpen(true)}
                  >
                    Cài đặt phát live
                  </Button>
                  {broadcast.isLive ? (
                    <BroadcastLiveIndicator status={broadcast.status} error={broadcast.error} />
                  ) : null}
                </>
              ) : null}
              <Stack direction="row" spacing={1}>
                <Button fullWidth variant="outlined" onClick={handleSuggestAiPairs}>
                  Đề xuất ghép cặp
                </Button>
                <Button fullWidth variant="contained" onClick={handleBuildAiGroups}>
                  Chia bảng seed
                </Button>
              </Stack>
            </Stack>
          </Grid>
          <Grid size={{ xs: 12, lg: 3 }}>
            <TournamentSelectedPlayersPanel
              title="VĐV đã chọn"
              players={selectedPlayers}
              onRemove={handleRemoveSelectedAiPlayer}
              showClubName
              emptyMessage="Chưa chọn VĐV nào. Bấm tên VĐV bên trái để thêm."
            />
          </Grid>
          <Grid size={{ xs: 12, lg: 5 }}>
            <Paper variant="outlined" sx={{ p: 1.5, mb: 2 }}>
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
                Cặp / VĐV theo rating ({displayEntries.length})
              </Typography>
              <Stack spacing={1} sx={{ maxHeight: 360, overflow: "auto" }}>
                {displayEntries.map((entry) => (
                  <Paper key={entry.id} variant="outlined" sx={{ p: 1 }}>
                    <Stack direction="row" justifyContent="space-between" spacing={1}>
                      <Typography variant="body2" fontWeight="bold">
                        {entry.name}
                      </Typography>
                      <Chip size="small" label={`Seed ${entry.seed || "-"}`} />
                    </Stack>
                    <Typography variant="caption" color="text.secondary">
                      Rating đội: {entry.rating}
                    </Typography>
                  </Paper>
                ))}
              </Stack>
            </Paper>
            {isAiBalance ? (
              <TournamentEntryEditor
                entries={displayEntries}
                players={flowPlayers}
                eventType={eventType}
                canIntervene={canInterveneSetup && displayEntries.length > 0}
                tournamentId={tournamentId}
                eventId={savedEvent?.id || ""}
                onApply={handleEntryInterventionApply}
                onAudit={pairingIntervention.auditEntryChange}
              />
            ) : null}
            <Paper variant="outlined" sx={{ p: 1.5 }}>
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
                Bảng đấu ({savedEvent?.groups?.length || 0})
              </Typography>
              {!savedEvent?.groups?.length ? (
                <Typography variant="body2" color="text.secondary">
                  Chọn VĐV, đề xuất ghép cặp rồi bấm &quot;Chia bảng seed&quot;.
                </Typography>
              ) : (
                <Stack spacing={1}>
                  {savedEvent.groups.map((group) => (
                    <Paper key={group.id} variant="outlined" sx={{ p: 1.25 }}>
                      <Stack direction="row" justifyContent="space-between" alignItems="center">
                        <Typography fontWeight="bold">{group.name}</Typography>
                        <Chip
                          size="small"
                          label={`${group.entryIds?.length || 0} doi • ${group.matches?.length || 0} tran`}
                        />
                      </Stack>
                      <Typography variant="caption" color="text.secondary">
                        {(group.entries || []).map((entry) => entry.name).join(" | ")}
                      </Typography>
                    </Paper>
                  ))}
                </Stack>
              )}
            </Paper>
            <TournamentGroupEditor
              groups={savedEvent?.groups || []}
              entries={savedEvent?.entries || displayEntries}
              players={flowPlayers}
              canIntervene={canInterveneSetup && (savedEvent?.groups?.length || 0) > 0}
              tournamentId={tournamentId}
              eventId={savedEvent?.id || ""}
              onApply={handleGroupInterventionApply}
              onAudit={pairingIntervention.auditGroupChange}
            />
          </Grid>
        </Grid>
      ) : (
      <Grid container spacing={2}>
        <Grid size={{ xs: 12, lg: 5 }}>
          <Paper variant="outlined" sx={{ p: 1.5, mb: 2 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Đăng ký VĐV / cặp ({displayEntries.length})
            </Typography>

            <Tabs
              value={openRegistrationTab}
              onChange={(_, value) => setOpenRegistrationTab(value)}
              sx={{ mb: 1.5, borderBottom: 1, borderColor: "divider" }}
            >
              <Tab label="Trong hệ thống" />
              <Tab label="Thêm VĐV mới" />
            </Tabs>

            {openRegistrationTab === 0 ? (
              isSingleEventType(eventType) ? (
                <TournamentPlayerPickerPanel
                  title=""
                  players={allTenantPlayers}
                  mode="register"
                  onRegister={handleRegisterSingle}
                  clubFilter={openClubFilter}
                  onClubFilterChange={setOpenClubFilter}
                  clubs={clubs}
                  genderFilter={pickerGenderFilter}
                  onGenderFilterChange={setPickerGenderFilter}
                  search={pickerSearch}
                  onSearchChange={setPickerSearch}
                  eventType={eventType}
                  excludePlayerIds={registeredPlayerIds}
                  onAddNew={() => setQuickAddOpen(true)}
                  showSkillLevel={canViewSkillInSetup}
                  showSelectActions={false}
                  emptyMessage="Không có VĐV phù hợp hoặc tất cả đã đăng ký."
                />
              ) : (
                <Stack spacing={1.5}>
                  <TournamentPlayerPickerPanel
                    title=""
                    players={allTenantPlayers}
                    clubFilter={openClubFilter}
                    onClubFilterChange={setOpenClubFilter}
                    clubs={clubs}
                    genderFilter={pickerGenderFilter}
                    onGenderFilterChange={setPickerGenderFilter}
                    search={pickerSearch}
                    onSearchChange={setPickerSearch}
                    eventType={eventType}
                    excludePlayerIds={registeredPlayerIds}
                    onAddNew={() => setQuickAddOpen(true)}
                    showSelectActions={false}
                    showPlayerList={false}
                    emptyMessage="Không có VĐV phù hợp."
                  />
                  <FormControl fullWidth size="small">
                    <InputLabel>VDV 1</InputLabel>
                    <Select
                      label="VDV 1"
                      value={pairPlayerAId}
                      onChange={(event) => setPairPlayerAId(event.target.value)}
                    >
                      {openFilteredPlayers.map((player) => (
                        <MenuItem key={player.id} value={String(player.id)}>
                          {player.name} — {formatPlayerPickerMeta(player)}
                        </MenuItem>
                      ))}
                    </Select>
                  </FormControl>
                  <FormControl fullWidth size="small">
                    <InputLabel>VDV 2</InputLabel>
                    <Select
                      label="VDV 2"
                      value={pairPlayerBId}
                      onChange={(event) => setPairPlayerBId(event.target.value)}
                    >
                      {openFilteredPlayers.map((player) => (
                        <MenuItem key={player.id} value={String(player.id)}>
                          {player.name} — {formatPlayerPickerMeta(player)}
                        </MenuItem>
                      ))}
                    </Select>
                  </FormControl>
                  <Button variant="contained" onClick={handleRegisterPair}>
                    Đăng ký cặp
                  </Button>
                </Stack>
              )
            ) : (
              <Stack spacing={1.5}>
                <Typography variant="body2" color="text.secondary">
                  Thêm VĐV chưa có trong hệ thống. VĐV sẽ được lưu vào CLB chủ nhà giải dưới dạng
                  khách (guest) và có thể đăng ký ngay sau khi tạo.
                </Typography>
                <Button variant="contained" onClick={() => setQuickAddOpen(true)}>
                  Thêm VĐV mới
                </Button>
              </Stack>
            )}
          </Paper>

          <Stack spacing={1}>
            <Button
              fullWidth
              variant="contained"
              color="secondary"
              onClick={handleStartGuidedFlow}
              disabled={displayEntries.length < 2}
            >
              Bắt đầu trình chiếu
            </Button>
            {broadcastFeatureEnabled ? (
              <>
                <Button
                  fullWidth
                  variant="outlined"
                  onClick={() => setBroadcastDialogOpen(true)}
                >
                  Cài đặt phát live
                </Button>
                {broadcast.isLive ? (
                  <BroadcastLiveIndicator status={broadcast.status} error={broadcast.error} />
                ) : null}
              </>
            ) : null}
            <Stack direction="row" spacing={1}>
              <Button fullWidth variant="contained" onClick={() => handleDrawGroups(false)}>
                Chia bảng random
              </Button>
              {savedEvent?.groups?.length > 0 && canRegenerateDraw(tournament).ok && (
                <Button fullWidth variant="outlined" onClick={() => handleDrawGroups(true)}>
                  Random lại
                </Button>
              )}
            </Stack>
            {savedEvent?.groups?.length > 0 && (
              <DrawPublishControls
                tournament={tournament}
                groups={savedEvent.groups}
                drawPublish={drawPublish}
                hasReopenPermission={hasDrawReopenPermission}
                onLock={handleLockDraw}
                onPublish={handlePublishDraw}
                onReopen={handleReopenDraw}
                onForceRedraw={handleForceRedraw}
                compact
              />
            )}
          </Stack>
        </Grid>

        <Grid size={{ xs: 12, lg: 7 }}>
          <Paper variant="outlined" sx={{ p: 1.5, mb: 2 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Danh sách đăng ký
            </Typography>
            {displayEntries.length === 0 ? (
              <Typography variant="body2" color="text.secondary">
                Chưa có đăng ký. VĐV/cặp tự đăng ký theo nội dung đã chọn.
              </Typography>
            ) : (
              <Stack spacing={1} sx={{ maxHeight: 360, overflow: "auto" }}>
                {displayEntries.map((entry) => (
                  <Paper key={entry.id} variant="outlined" sx={{ p: 1 }}>
                    <Stack direction="row" justifyContent="space-between" spacing={1}>
                      <Box>
                        <Typography variant="body2" fontWeight="bold">
                          {entry.name}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {entry.clubName || entry.representativeClubName || "Chua ro CLB"}
                        </Typography>
                        <TournamentRegistrationRatingPanel
                          players={resolveTournamentEntryPlayers(entry, allTenantPlayers)}
                          tournamentId={tournamentId}
                          hostClubId={activeClubId}
                          compact
                          onVerified={() => {
                            refreshClubs();
                            setLocalRevision((value) => value + 1);
                          }}
                        />
                      </Box>
                      {!savedEvent?.groups?.length && (
                        <Button
                          size="small"
                          color="error"
                          onClick={() => handleRemoveEntry(entry.id)}
                        >
                          Xoa
                        </Button>
                      )}
                    </Stack>
                  </Paper>
                ))}
              </Stack>
            )}
          </Paper>

          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Bảng đấu ({savedEvent?.groups?.length || 0})
            </Typography>
            {!savedEvent?.groups?.length ? (
              <Typography variant="body2" color="text.secondary">
                Chưa chia bảng. Đăng ký đủ đội rồi bấm &quot;Chia bảng random&quot;.
              </Typography>
            ) : (
              <Stack spacing={1}>
                {savedEvent.groups.map((group) => (
                  <Paper key={group.id} variant="outlined" sx={{ p: 1.25 }}>
                    <Stack direction="row" justifyContent="space-between" alignItems="center">
                      <Typography fontWeight="bold">{group.name}</Typography>
                      <Chip
                        size="small"
                        label={`${group.entryIds?.length || 0} doi • ${group.matches?.length || 0} tran`}
                      />
                    </Stack>
                    <Typography variant="caption" color="text.secondary">
                      {(group.entries || []).map((entry) => entry.name).join(" | ")}
                    </Typography>
                  </Paper>
                ))}
              </Stack>
            )}
          </Paper>

          <TournamentGroupEditor
            groups={savedEvent?.groups || []}
            entries={savedEvent?.entries || displayEntries}
            players={flowPlayers}
            canIntervene={canInterveneSetup && (savedEvent?.groups?.length || 0) > 0}
            tournamentId={tournamentId}
            eventId={savedEvent?.id || ""}
            onApply={handleGroupInterventionApply}
            onAudit={pairingIntervention.auditGroupChange}
          />
        </Grid>
      </Grid>
      )}

      {savedEvent?.groups?.length > 0 && (
        <Stack spacing={2} sx={{ mt: 2 }}>
          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <DrawPublishControls
              tournament={tournament}
              groups={savedEvent.groups}
              drawPublish={drawPublish}
              hasReopenPermission={hasDrawReopenPermission}
              onLock={handleLockDraw}
              onPublish={handlePublishDraw}
              onReopen={handleReopenDraw}
              onForceRedraw={handleForceRedraw}
            />
            <Button
              component={RouterLink}
              to={`/tournament/publish-schedule?tournamentId=${encodeURIComponent(tournamentId)}`}
              variant="outlined"
              sx={{ mt: 1.5 }}
              fullWidth
            >
              Lịch thi đấu & công bố (S1-E)
            </Button>
          </Paper>

          <GroupStagePanel
            event={savedEvent}
            players={flowPlayers}
            onSubmitScore={handleSubmitGroupScore}
            draftScope={scoreDraftScope}
          />

          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
              Bảng xếp hạng vòng bảng
            </Typography>
            {groupStandings[0]?.tieBreakExplanation ? (
              <Typography variant="caption" color="text.secondary" display="block" sx={{ mb: 1 }}>
                Tie-break: {groupStandings[0].tieBreakExplanation}
                {groupStandings[0].source === "standings_v2" ? " · STANDINGS_V2" : " · Legacy"}
              </Typography>
            ) : null}
            {groupStandings.length === 0 ? (
              <Typography variant="body2" color="text.secondary">
                Chưa có kết quả trận vòng bảng.
              </Typography>
            ) : (
              <Grid container spacing={1.5}>
                {groupStandings.map((groupStanding) => (
                  <Grid key={groupStanding.group} size={{ xs: 12, md: 6, lg: 3 }}>
                    <Paper variant="outlined" sx={{ p: 1.25 }}>
                      <Typography fontWeight="bold" sx={{ mb: 0.75 }}>
                        Bảng {groupStanding.group}
                      </Typography>
                      <Stack spacing={0.5}>
                        {groupStanding.standing.map((team, index) => (
                          <Typography
                            key={team.id}
                            variant="body2"
                            fontWeight={index < 2 ? "bold" : "regular"}
                          >
                            {index + 1}. {team.name} — {team.matchPoints} điểm
                            {team.qualificationStatus?.startsWith("qualified") ? " ✓ KO" : ""}
                          </Typography>
                        ))}
                      </Stack>
                    </Paper>
                  </Grid>
                ))}
              </Grid>
            )}
          </Paper>

          <Paper variant="outlined" sx={{ p: 1.5 }}>
            <Stack
              direction={{ xs: "column", sm: "row" }}
              spacing={1}
              justifyContent="space-between"
              alignItems={{ xs: "stretch", sm: "center" }}
              sx={{ mb: 1.5 }}
            >
              <Typography variant="subtitle1" fontWeight="bold">
                Sơ đồ knock-out
              </Typography>
              <Stack direction="row" spacing={1}>
                {savedEvent?.bracket?.rounds?.length > 0 && (
                  <Button
                    component={RouterLink}
                    to={`/tournament/official/${tournamentId}/bracket`}
                    variant="outlined"
                  >
                    Mở sơ đồ đầy đủ
                  </Button>
                )}
                {!savedEvent?.bracket?.rounds?.length && (
                  <Button variant="contained" onClick={handleGenerateBracket}>
                    Tạo bracket từ BXH
                  </Button>
                )}
              </Stack>
            </Stack>

            {!savedEvent?.bracket?.rounds?.length ? (
              <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                Chưa có sơ đồ. Nhập điểm vòng bảng xong rồi bấm &quot;Tạo bracket từ BXH&quot;.
                Cần số bảng chẵn (2, 4, 8...).
              </Typography>
            ) : null}

            <BracketView
              progress={bracketProgress}
              unlockedRounds={savedEvent?.bracket?.unlockedRounds || {}}
              knockoutMatchesByBracketId={knockoutMatchesByBracketId}
              onSelectWinner={handleSelectBracketWinner}
              onToggleRoundLock={handleToggleRoundLock}
              onSubmitScore={handleSubmitKnockoutScore}
              onReset={handleResetBracket}
              canReset={Boolean(savedEvent?.bracket?.rounds?.length)}
              draftScope={scoreDraftScope}
            />
          </Paper>
        </Stack>
      )}

      <TournamentAnimationDialog
        {...flow.dialogProps}
        onFlowExit={handleFlowExit}
        broadcastStatus={broadcastFeatureEnabled ? broadcast.status : undefined}
        broadcastError={broadcastFeatureEnabled ? broadcast.error : undefined}
      />

      {broadcastFeatureEnabled ? (
        <BroadcastSetupDialog
          open={broadcastDialogOpen}
          tournamentId={tournamentId}
          config={broadcast.config}
          onChange={broadcast.updateConfig}
          onClose={() => setBroadcastDialogOpen(false)}
        />
      ) : null}

      <TournamentPlayerQuickAddDialog
        open={quickAddOpen}
        onClose={() => setQuickAddOpen(false)}
        hostClubId={activeClubId}
        defaultClubName={entryClubName || activeClub?.name || ""}
        onSaved={handleQuickAddSaved}
      />

      {bracketAdvanceAnim && (
        <Box
          sx={{
            position: "fixed",
            bottom: 16,
            left: 16,
            right: 16,
            zIndex: 1300,
            maxWidth: 360,
            mx: "auto",
          }}
        >
          <BracketRevealAnimation
            animationMode={ANIMATION_MODES.BRACKET_ADVANCE}
            advanceHint={bracketAdvanceAnim}
            bracket={bracketAdvanceAnim.bracket}
            onAnimationComplete={() => setBracketAdvanceAnim(null)}
            onSkip={() => setBracketAdvanceAnim(null)}
          />
        </Box>
      )}

      {tournament && (
        <Box sx={{ mt: 3 }}>
          <TournamentCourtSchedulePanel
            clubId={activeClubId}
            tournament={tournament}
            courts={courts}
            onSaved={() => {
              refreshClubs();
              setLocalRevision((value) => value + 1);
            }}
          />
        </Box>
      )}
      </>
      )}
    </TournamentSetupShell>
    </TournamentManageGate>
  );
}

import { useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";

import {
  Alert,
  Box,
  Button,
  Chip,
  Paper,
  Stack,
  Typography,
} from "@mui/material";
import AccountTreeIcon from "@mui/icons-material/AccountTree";
import ChevronRightIcon from "@mui/icons-material/ChevronRight";

import { useClub } from "../../context/ClubContext.jsx";
import { useSeasonLeague } from "../../context/SeasonContext.jsx";
import { listTournaments } from "../../domain/tournamentService.js";
import { TOURNAMENT_MODE, TOURNAMENT_STATUS } from "../../models/tournament/index.js";
import { getTournamentBracketPath,
  getTournamentSetupPath,
  isBracketTournament,
  rankTournamentsForBracket,
} from "../../utils/tournamentNavigation.js";
import TournamentPageHeader from "../../components/tournament/TournamentPageHeader.jsx";
import { tournamentCardHoverSx, tournamentCardSx } from "../../components/tournament/tournamentLayout.js";

const MODE_LABELS = {
  [TOURNAMENT_MODE.INTERNAL_TOURNAMENT]: "Nội bộ",
  [TOURNAMENT_MODE.OFFICIAL_TOURNAMENT]: "Chính thức",
};

const STATUS_LABELS = {
  [TOURNAMENT_STATUS.ACTIVE]: "Đang diễn ra",
  [TOURNAMENT_STATUS.READY]: "Sẵn sàng",
  [TOURNAMENT_STATUS.REGISTRATION]: "Đăng ký",
  [TOURNAMENT_STATUS.COMPLETED]: "Hoàn thành",
  [TOURNAMENT_STATUS.DRAFT]: "Nháp",
};

export default function TournamentBracketHub() {
  const navigate = useNavigate();
  const { activeClubId, revision } = useClub();
  const { activeSeason, activeLeague } = useSeasonLeague();

  const tournaments = useMemo(
    () => listTournaments(activeClubId),
    [activeClubId, revision]
  );

  const bracketTournaments = useMemo(
    () =>
      rankTournamentsForBracket(tournaments, {
        seasonId: activeSeason?.id,
        leagueId: activeLeague?.id,
      }),
    [tournaments, activeSeason?.id, activeLeague?.id]
  );

  const pendingSetup = useMemo(
    () =>
      tournaments.filter(
        (tournament) =>
          isBracketTournament(tournament) &&
          tournament.status !== TOURNAMENT_STATUS.CANCELLED &&
          tournament.status !== TOURNAMENT_STATUS.DRAFT
      ),
    [tournaments]
  );

  useEffect(() => {
    if (bracketTournaments.length === 1) {
      const path = getTournamentBracketPath(bracketTournaments[0]);
      if (path) {
        navigate(path, { replace: true });
      }
    }
  }, [bracketTournaments, navigate]);

  if (bracketTournaments.length === 1) {
    return null;
  }

  return (
    <Box>
      <TournamentPageHeader
        title="Sơ đồ thi đấu"
        description={`Chọn giải để xem bracket knock-out của ${activeLeague?.name || "giải hiện tại"}.`}
      />

      {bracketTournaments.length > 0 ? (
        <Stack spacing={1.5}>
          {bracketTournaments.map((tournament) => (
            <Paper
              key={tournament.id}
              variant="outlined"
              elevation={0}
              sx={{
                ...tournamentCardSx,
                ...tournamentCardHoverSx,
                p: 2,
                cursor: "pointer",
                "&:hover": {
                  ...tournamentCardHoverSx["&:hover"],
                  transform: "translateY(-1px)",
                },
              }}
              onClick={() => {
                const path = getTournamentBracketPath(tournament);
                if (path) navigate(path);
              }}
            >
              <Stack
                direction={{ xs: "column", sm: "row" }}
                spacing={1}
                alignItems={{ xs: "flex-start", sm: "center" }}
                justifyContent="space-between"
              >
                <Box>
                  <Typography variant="subtitle1" fontWeight={800}>
                    {tournament.name}
                  </Typography>
                  <Stack direction="row" spacing={0.75} sx={{ mt: 0.75 }} flexWrap="wrap">
                    <Chip
                      size="small"
                      label={MODE_LABELS[tournament.mode] || "Giải"}
                      color="primary"
                      variant="outlined"
                    />
                    <Chip
                      size="small"
                      label={STATUS_LABELS[tournament.status] || tournament.status}
                    />
                  </Stack>
                </Box>
                <Button endIcon={<ChevronRightIcon />} variant="contained" size="small">
                  Mở sơ đồ
                </Button>
              </Stack>
            </Paper>
          ))}
        </Stack>
      ) : (
        <Alert severity="info" sx={{ mb: 2 }}>
          {pendingSetup.length > 0
            ? "Các giải đã tạo nhưng chưa có sơ đồ knock-out. Nhập đủ điểm vòng bảng — bracket sẽ được tạo tự động."
            : "Chưa có giải nội bộ/chính thức nào có sơ đồ thi đấu."}
        </Alert>
      )}

      {pendingSetup.length > 0 && bracketTournaments.length === 0 && (
        <Stack spacing={1}>
          {pendingSetup.map((tournament) => (
            <Button
              key={tournament.id}
              variant="outlined"
              onClick={() => navigate(getTournamentSetupPath(tournament))}
              sx={{ justifyContent: "flex-start" }}
            >
              Thiết lập giải: {tournament.name}
            </Button>
          ))}
        </Stack>
      )}

      <Button sx={{ mt: 3 }} onClick={() => navigate("/tournament")}>
        Về danh sách giải
      </Button>
    </Box>
  );
}

import { useMemo, useEffect, useState } from "react";
import { useNavigate, useParams, useLocation } from "react-router-dom";

import {
  Alert,
  Badge,
  Box,
  Breadcrumbs,
  Button,
  Chip,
  CircularProgress,
  Snackbar,
  LinearProgress,
  Link,
  List,
  ListItem,
  ListItemText,
  Paper,
  Tab,
  Tabs,
  Typography,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";
import ArrowForwardIcon from "@mui/icons-material/ArrowForward";
import AutoAwesomeIcon from "@mui/icons-material/AutoAwesome";
import NotificationsIcon from "@mui/icons-material/Notifications";
import ExpandLessIcon from "@mui/icons-material/ExpandLess";
import ExpandMoreIcon from "@mui/icons-material/ExpandMore";

import { useTournamentEngineState } from "../../features/tournament-engine/hooks/useTournamentEngine.js";
import { groupWorkflowHistoryByDate } from "../../features/tournament-engine/hooks/workflowHistory.js";
import EngineSetupTab from "./engine/tabs/EngineSetupTab.jsx";
import EngineSeedTab from "./engine/tabs/EngineSeedTab.jsx";
import EngineDrawTab from "./engine/tabs/EngineDrawTab.jsx";
import EngineScheduleTab from "./engine/tabs/EngineScheduleTab.jsx";
import EngineCourtsTab from "./engine/tabs/EngineCourtsTab.jsx";
import EngineRankingTab from "./engine/tabs/EngineRankingTab.jsx";
import EngineLogsTab from "./engine/tabs/EngineLogsTab.jsx";
import PermissionGate from "../../components/auth/PermissionGate.jsx";
import TournamentPageHeader from "../../components/tournament/TournamentPageHeader.jsx";
import { tournamentCardSx } from "../../components/tournament/tournamentLayout.js";
import { PERMISSIONS } from "../../auth/permissions.js";
import {
  getPlatformEventSummary,
  getPlatformNotificationSummary,
  getUnreadNotificationCount,
  getWorkflowNotificationMessage,
  getWorkflowStageConfig,
  getWorkflowStatusLabel,
} from "./engine/workflowPreviewUtils.js";

const TAB_CONFIG = [
  { key: "setup", label: "Thiết lập" },
  { key: "seed", label: "Hạt giống" },
  { key: "draw", label: "Bốc thăm" },
  { key: "schedule", label: "Lịch đấu" },
  { key: "courts", label: "Sân" },
  { key: "ranking", label: "Xếp hạng" },
  { key: "logs", label: "Nhật ký AI" },
];

function resolveTabFromPath(pathname) {
  if (pathname.endsWith("/seed")) return "seed";
  if (pathname.endsWith("/draw")) return "draw";
  if (pathname.endsWith("/schedule")) return "schedule";
  if (pathname.endsWith("/courts")) return "courts";
  if (pathname.endsWith("/ranking")) return "ranking";
  if (pathname.endsWith("/logs")) return "logs";
  return "setup";
}

function tabPath(tournamentId, tabKey) {
  if (tabKey === "setup") {
    return `/tournaments/${tournamentId}/engine`;
  }
  return `/tournaments/${tournamentId}/${tabKey}`;
}

export default function TournamentEnginePage() {
  const { tournamentId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const activeTab = resolveTabFromPath(location.pathname);
  const [historyExpanded, setHistoryExpanded] = useState(true);
  const [confirmClearHistory, setConfirmClearHistory] = useState(false);
  const [toastMessage, setToastMessage] = useState("");
  const [notificationFilter, setNotificationFilter] = useState("all");

  const engine = useTournamentEngineState(tournamentId);
  const platformSummary = useMemo(() => {
    const participantCount = engine.engineState?.participants?.length || 0;
    const groupCount = engine.engineState?.groups?.length || 0;
    const matchCount = engine.matches?.length || 0;
    const hasRanking = Boolean(engine.engineState?.rankingResult);

    let recommendation = "Bắt đầu workflow Engine 4.0";
    let reason = "Chạy hạt giống → bốc thăm → lịch đấu → xếp hạng.";

    if (hasRanking) {
      recommendation = "Workflow hoàn tất";
      reason = `${participantCount} VĐV · ${groupCount} bảng · ${matchCount} trận.`;
    } else if (matchCount > 0) {
      recommendation = "Tiếp theo: cập nhật xếp hạng";
      reason = `${matchCount} trận đã lên lịch.`;
    } else if (groupCount > 0) {
      recommendation = "Tiếp theo: tạo lịch đấu";
      reason = `${groupCount} bảng đã bốc thăm.`;
    } else if (participantCount > 0) {
      recommendation = "Tiếp theo: bốc thăm";
      reason = `${participantCount} hạt giống sẵn sàng.`;
    }

    return {
      ok: true,
      data: {
        recommendation: { recommendation, reason },
      },
    };
  }, [engine.engineState, engine.matches]);

  const workflowHistoryGroups = useMemo(() => groupWorkflowHistoryByDate(engine.workflowHistory || []), [engine.workflowHistory]);

  const workflowStages = useMemo(() => getWorkflowStageConfig(engine.engineState, engine.matches), [engine.engineState, engine.matches]);

  const completedStageCount = useMemo(() => workflowStages.filter((stage) => stage.done).length, [workflowStages]);

  const workflowStatusLabel = useMemo(() => getWorkflowStatusLabel(completedStageCount), [completedStageCount]);

  const latestHistoryEntry = useMemo(() => {
    return (engine.workflowHistory || [])[0] || null;
  }, [engine.workflowHistory]);

  const platformEventSummaries = useMemo(() => {
    return (engine.platformEvents || []).slice(0, 5).map((event) => getPlatformEventSummary(event));
  }, [engine.platformEvents]);

  const platformNotificationSummaries = useMemo(() => {
    const notifications = (engine.platformNotifications || []).slice(0, 10).map((notification) => getPlatformNotificationSummary(notification));
    if (notificationFilter === "unread") {
      return notifications.filter((notification) => notification?.read !== true && notification?.status !== "read");
    }
    return notifications;
  }, [engine.platformNotifications, notificationFilter]);

  const unreadNotificationCount = useMemo(() => {
    return getUnreadNotificationCount(engine.platformNotifications || []);
  }, [engine.platformNotifications]);

  const nextWorkflowAction = useMemo(() => {
    if (!engine.engineState?.participants?.length) {
      return {
        label: "Next: generate seed and build the initial player pool.",
        tab: "seed",
      };
    }
    if (!engine.engineState?.groups?.length) {
      return {
        label: "Next: create the draw so the bracket structure is ready.",
        tab: "draw",
      };
    }
    if (!engine.matches?.length) {
      return {
        label: "Next: schedule matches and assign court slots.",
        tab: "schedule",
      };
    }
    if (!engine.engineState?.rankingResult) {
      return {
        label: "Next: publish the ranking snapshot for the current workflow.",
        tab: "ranking",
      };
    }
    return {
      label: "Next: review the latest workflow summary and export the plan.",
      tab: "setup",
    };
  }, [engine.engineState, engine.matches]);

  const handleTabChange = (_, tabKey) => {
    navigate(tabPath(tournamentId, tabKey));
  };

  useEffect(() => {
    if (!confirmClearHistory) return undefined;

    const timer = window.setTimeout(() => setConfirmClearHistory(false), 2500);
    return () => window.clearTimeout(timer);
  }, [confirmClearHistory]);

  useEffect(() => {
    if (!engine.platformNotifications?.length) {
      return undefined;
    }

    const latestNotification = engine.platformNotifications[engine.platformNotifications.length - 1];
    const message = getWorkflowNotificationMessage(latestNotification);
    setToastMessage(message);
    return undefined;
  }, [engine.platformNotifications]);

  const handleClearHistory = () => {
    if (confirmClearHistory) {
      engine.clearWorkflowHistory?.();
      setConfirmClearHistory(false);
      return;
    }

    setConfirmClearHistory(true);
  };

  const handleNotificationClick = (notification) => {
    if (notification?.read || notification?.status === "read") {
      return;
    }
    engine.markNotificationAsRead?.(notification.id);
  };

  if (!engine.tournament) {
    return (
      <Box sx={{ p: 3 }}>
        <Alert severity="error">Không tìm thấy giải đấu.</Alert>
        <Button startIcon={<ArrowBackIcon />} sx={{ mt: 2 }} onClick={() => navigate("/tournament")}>
          Quay lại
        </Button>
      </Box>
    );
  }

  const tabContent = (() => {
    switch (activeTab) {
      case "seed":
        return <EngineSeedTab engine={engine} />;
      case "draw":
        return <EngineDrawTab engine={engine} />;
      case "schedule":
        return <EngineScheduleTab engine={engine} />;
      case "courts":
        return <EngineCourtsTab engine={engine} />;
      case "ranking":
        return <EngineRankingTab engine={engine} />;
      case "logs":
        return <EngineLogsTab tournamentId={tournamentId} />;
      default:
        return <EngineSetupTab engine={engine} tournamentId={tournamentId} />;
    }
  })();

  return (
    <PermissionGate
      permission={PERMISSIONS.TOURNAMENT_UPDATE}
      fallback={<Alert severity="warning">Bạn không có quyền cấu hình giải.</Alert>}
    >
      <Box sx={{ p: { xs: 1, md: 2 } }}>
        <Snackbar
          open={Boolean(toastMessage)}
          autoHideDuration={4000}
          onClose={() => setToastMessage("")}
          message={toastMessage}
        />
        <Breadcrumbs sx={{ mb: 1 }}>
          <Link component="button" underline="hover" color="inherit" onClick={() => navigate("/tournament")}>
            Giải đấu
          </Link>
          <Typography color="text.primary">{engine.tournament.name}</Typography>
          <Typography color="text.secondary">Engine 4.0</Typography>
        </Breadcrumbs>

        <TournamentPageHeader
          title="Tournament Engine 4.0"
          description={engine.tournament.name}
          action={<AutoAwesomeIcon color="primary" />}
        />

        <Box sx={{ mb: 2, p: 1.25, border: 1, borderColor: "divider", borderRadius: 1, bgcolor: "background.paper" }}>
          <Box sx={{ display: "flex", flexWrap: "wrap", alignItems: "flex-start", justifyContent: "space-between", gap: 1.25 }}>
            <Box>
              <Box sx={{ display: "flex", alignItems: "center", gap: 1, mb: 0.25 }}>
                <Typography variant="subtitle2" color="primary">
                  Platform v5 Engine Preview
                </Typography>
                <Chip
                  size="small"
                  label={workflowStatusLabel}
                  color={completedStageCount === 4 ? "success" : completedStageCount > 0 ? "info" : "default"}
                  variant="outlined"
                />
              </Box>
              <Typography variant="body2" color="text.secondary" sx={{ fontSize: "0.85rem" }}>
                {platformSummary.data.recommendation.recommendation} · {platformSummary.data.recommendation.reason}
              </Typography>
            </Box>
            <Button
              size="small"
              variant="contained"
              color="primary"
              endIcon={<ArrowForwardIcon />}
              sx={{ py: 0.2, px: 1, fontSize: "0.8rem", fontWeight: 600 }}
              onClick={() => navigate(tabPath(tournamentId, nextWorkflowAction.tab))}
            >
              {nextWorkflowAction.label}
            </Button>
          </Box>
          <Box sx={{ display: "flex", justifyContent: "space-between", alignItems: "center", mt: 0.75, mb: 0.5 }}>
            <Typography variant="caption" color="text.secondary">
              Tiến độ workflow
            </Typography>
            <Typography variant="caption" color="primary">
              {completedStageCount}/4 stages
            </Typography>
          </Box>
          <LinearProgress
            variant="determinate"
            value={(completedStageCount / 4) * 100}
            sx={{ height: 6, borderRadius: 999 }}
          />
          <Typography variant="caption" color="text.secondary" sx={{ display: "block", mt: 0.5 }}>
            {completedStageCount === 4
              ? "Tất cả các bước workflow đã hoàn tất."
              : completedStageCount > 0
                ? `Workflow đang ở ${completedStageCount}/4 bước. Hãy tiếp tục với bước tiếp theo.`
                : "Workflow chưa bắt đầu. Hãy bắt đầu từ bước đầu tiên."}
          </Typography>
          <Box sx={{ display: "flex", flexWrap: "wrap", gap: 0.75, mt: 0.75 }}>
            {workflowStages.map((stage, index) => {
              const isNextStage = !stage.done && workflowStages.findIndex((item) => !item.done) === index;
              return (
                <Box
                  key={stage.key}
                  component="button"
                  title={`Go to ${stage.label.toLowerCase()} workflow`}
                  onClick={() => navigate(tabPath(tournamentId, stage.tab))}
                  sx={{
                    display: "flex",
                    alignItems: "center",
                    gap: 0.5,
                    px: 0.75,
                    py: 0.25,
                    borderRadius: 999,
                    border: "1px solid",
                    borderColor: stage.done ? "success.main" : isNextStage ? "primary.main" : "divider",
                    bgcolor: stage.done ? "success.main" : isNextStage ? "primary.light" : "grey.100",
                    color: stage.done ? "common.white" : isNextStage ? "primary.contrastText" : "text.secondary",
                    cursor: "pointer",
                    fontSize: "0.75rem",
                    transition: "all 120ms ease-in-out",
                    "&:hover": {
                      transform: "translateY(-1px)",
                      boxShadow: 1,
                    },
                    "&:focus-visible": {
                      outline: "2px solid",
                      outlineColor: "primary.main",
                      outlineOffset: 1,
                    },
                  }}
                >
                  <Typography variant="caption" sx={{ color: "inherit" }}>
                    {stage.done ? "●" : isNextStage ? "▶" : "○"}
                  </Typography>
                  <Typography variant="caption" sx={{ color: "inherit" }}>
                    {stage.label}
                  </Typography>
                </Box>
              );
            })}
          </Box>
        </Box>

        <Paper sx={{ p: 1.5, mb: 1.5, bgcolor: "grey.50" }}>
          <Box sx={{ display: "flex", flexWrap: "wrap", justifyContent: "space-between", alignItems: "center", gap: 1, mb: 1 }}>
            <Typography variant="subtitle2" color="text.secondary">
              Platform event feed
            </Typography>
            <Chip size="small" label={`${platformEventSummaries.length} events`} variant="outlined" />
          </Box>
          {platformEventSummaries.length > 0 ? (
            <List dense disablePadding sx={{ mb: 1 }}>
              {platformEventSummaries.map((event, index) => (
                <ListItem key={`${event.title}-${index}`} disablePadding sx={{ py: 0.2 }}>
                  <ListItemText
                    primary={
                      <Box sx={{ display: "flex", alignItems: "center", gap: 1, flexWrap: "wrap" }}>
                        <Typography variant="body2" sx={{ fontWeight: 600 }}>
                          {event.title}
                        </Typography>
                        <Chip size="small" label={event.status} variant="outlined" />
                      </Box>
                    }
                    secondary={
                      <Typography variant="caption" color="text.secondary">
                        {`${event.detail} · ${new Date(event.timestamp).toLocaleString("vi-VN")}`}
                      </Typography>
                    }
                  />
                </ListItem>
              ))}
            </List>
          ) : (
            <Typography variant="body2" color="text.secondary">
              Chưa có event nào được ghi nhận cho workflow này.
            </Typography>
          )}

          <Box sx={{ mt: 1.5 }}>
            <Box sx={{ display: "flex", alignItems: "center", gap: 1, mb: 0.75, flexWrap: "wrap" }}>
              <Typography variant="subtitle2" color="text.secondary">
                Recent notifications
              </Typography>
              <Badge badgeContent={unreadNotificationCount} color="primary" max={99}>
                <NotificationsIcon color="action" fontSize="small" />
              </Badge>
              {unreadNotificationCount > 0 && (
                <Button size="small" variant="text" onClick={() => engine.markAllNotificationsAsRead?.()}>
                  Đánh dấu tất cả đã đọc
                </Button>
              )}
              <Button size="small" variant="text" color={notificationFilter === "all" ? "primary" : "inherit"} onClick={() => setNotificationFilter("all")}>
                Tất cả
              </Button>
              <Button size="small" variant="text" color={notificationFilter === "unread" ? "primary" : "inherit"} onClick={() => setNotificationFilter("unread")}>
                Chưa đọc
              </Button>
            </Box>
            {platformNotificationSummaries.length > 0 ? (
              <List dense disablePadding>
                {platformNotificationSummaries.map((notification, index) => (
                  <ListItem
                    key={`${notification.title}-${index}`}
                    disablePadding
                    sx={{
                      py: 0.2,
                      cursor: notification?.read || notification?.status === "read" ? "default" : "pointer",
                      bgcolor: notification?.read || notification?.status === "read" ? "transparent" : "primary.50",
                      borderRadius: 1,
                      border: notification?.read || notification?.status === "read" ? "1px solid transparent" : "1px solid",
                      borderColor: notification?.read || notification?.status === "read" ? "transparent" : "primary.100",
                    }}
                    onClick={() => handleNotificationClick(notification)}
                  >
                    <ListItemText
                      primary={
                        <Box sx={{ display: "flex", alignItems: "center", gap: 1, flexWrap: "wrap" }}>
                          <Typography variant="body2" sx={{ fontWeight: 600 }}>
                            {notification.title}
                          </Typography>
                          {!notification?.read && notification?.status !== "read" && (
                            <Chip size="small" label="NEW" color="primary" variant="filled" />
                          )}
                          <Chip size="small" label={notification.channel} variant="outlined" />
                        </Box>
                      }
                      secondary={
                        <Typography variant="caption" color="text.secondary">
                          {`${notification.detail} · ${new Date(notification.timestamp).toLocaleString("vi-VN")}`}
                        </Typography>
                      }
                    />
                  </ListItem>
                ))}
              </List>
            ) : (
              <Typography variant="body2" color="text.secondary">
                Chưa có notification nào được tạo cho workflow này.
              </Typography>
            )}
          </Box>
        </Paper>

        {engine.workflowHistory?.length > 0 && (
          <Paper sx={{ p: 1.5, mb: 1.5, bgcolor: "grey.50" }}>
            {latestHistoryEntry && !historyExpanded && (
              <Box sx={{ mb: 0.75, p: 0.75, borderRadius: 1, bgcolor: "background.paper", border: "1px solid", borderColor: "divider" }}>
                <Typography variant="caption" color="text.secondary">
                  Latest action
                </Typography>
                <Typography variant="body2" sx={{ textTransform: "capitalize", fontWeight: 600 }}>
                  {latestHistoryEntry.action}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  {`${latestHistoryEntry.detail} · ${new Date(latestHistoryEntry.timestamp).toLocaleString("vi-VN")}`}
                </Typography>
              </Box>
            )}
            <Box sx={{ display: "flex", flexWrap: "wrap", justifyContent: "space-between", alignItems: "center", gap: 1, mb: 0.75 }}>
              <Typography variant="subtitle2" color="text.secondary">
                Workflow history
              </Typography>
              <Box sx={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: 0.75 }}>
                <Chip size="small" label={`${engine.workflowHistory?.length || 0} entries`} variant="outlined" />
                <Button
                  size="small"
                  variant="text"
                  color={historyExpanded ? "primary" : "inherit"}
                  startIcon={historyExpanded ? <ExpandLessIcon /> : <ExpandMoreIcon />}
                  onClick={() => setHistoryExpanded((value) => !value)}
                >
                  {historyExpanded ? "Thu gọn" : "Mở rộng"}
                </Button>
                <Button size="small" variant="text" color={confirmClearHistory ? "warning" : "inherit"} onClick={handleClearHistory}>
                  {confirmClearHistory ? "Xác nhận" : "Xóa"}
                </Button>
              </Box>
            </Box>
            {historyExpanded && (
              <List dense disablePadding>
                {workflowHistoryGroups.slice(0, 3).map((group) => (
                  <Box key={group.label} sx={{ mb: 1 }}>
                    <Typography variant="caption" color="text.secondary" sx={{ display: "block", mb: 0.5 }}>
                      {group.label}
                    </Typography>
                    {group.entries.slice(0, 3).map((entry) => {
                      const statusColor = entry.status === "success" ? "success" : entry.status === "error" ? "error" : "default";
                      return (
                        <ListItem key={entry.id} disablePadding sx={{ py: 0.1 }}>
                          <ListItemText
                            primary={
                              <Box sx={{ display: "flex", alignItems: "center", gap: 1, flexWrap: "wrap" }}>
                                <Typography variant="body2" sx={{ textTransform: "capitalize", fontWeight: 600 }}>
                                  {entry.action}
                                </Typography>
                                <Chip size="small" label={entry.status} color={statusColor} variant="outlined" />
                              </Box>
                            }
                            secondary={
                              <Typography variant="caption" color="text.secondary">
                                {`${entry.detail} · ${new Date(entry.timestamp).toLocaleString("vi-VN")}`}
                              </Typography>
                            }
                          />
                        </ListItem>
                      );
                    })}
                  </Box>
                ))}
              </List>
            )}
          </Paper>
        )}

        {engine.error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {engine.error}
          </Alert>
        )}

        <Tabs
          value={activeTab}
          onChange={handleTabChange}
          variant="scrollable"
          scrollButtons="auto"
          sx={{ mb: 2, borderBottom: 1, borderColor: "divider" }}
        >
          {TAB_CONFIG.map((tab) => (
            <Tab key={tab.key} label={tab.label} value={tab.key} />
          ))}
        </Tabs>

        {engine.loading && (
          <Box sx={{ display: "flex", alignItems: "center", gap: 1, mb: 2 }}>
            <CircularProgress size={20} />
            <Typography variant="body2">Đang xử lý…</Typography>
          </Box>
        )}

        {tabContent}
      </Box>
    </PermissionGate>
  );
}

import { useMemo } from "react";
import { Link as RouterLink, useSearchParams } from "react-router-dom";

import {
  Alert,
  Button,
  Chip,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Typography,
} from "@mui/material";

import { useClub } from "../../../context/ClubContext.jsx";
import { loadPlayersForClub } from "../../../domain/clubStorage.js";
import { getTournament } from "../../../domain/tournamentService.js";
import { isIndividualTournament, isTeamTournament } from "../../../config/tournamentRoutes.js";
import { checkAllEntriesEligibility } from "../../../features/individual-tournament/engines/eligibilityEngine.js";
import {
  checkAllTeamsEligibility,
} from "../../../features/team-tournament/engines/eligibilityEngine.js";
import {
  getTeamData,
} from "../../../features/team-tournament/engines/teamTournamentEngine.js";
import TournamentConfigPageShell from "../../../components/tournament/TournamentConfigPageShell.jsx";

export default function TournamentEligibilityPage() {
  const [searchParams] = useSearchParams();
  const tournamentId = searchParams.get("tournamentId");
  const { activeClubId, revision } = useClub();

  const tournament = useMemo(() => {
    if (!activeClubId || !tournamentId) return null;
    return getTournament(activeClubId, tournamentId);
  }, [activeClubId, tournamentId, revision]);

  const players = useMemo(
    () => (activeClubId ? loadPlayersForClub(activeClubId) : []),
    [activeClubId, revision]
  );

  const individualReport = useMemo(() => {
    if (!tournament || !isIndividualTournament(tournament)) return null;
    return checkAllEntriesEligibility(tournament, players);
  }, [tournament, players]);

  const teamData = useMemo(
    () => (tournament && isTeamTournament(tournament) ? getTeamData(tournament) : null),
    [tournament]
  );

  const teamReport = useMemo(() => {
    if (!teamData) return null;
    return checkAllTeamsEligibility(teamData, players);
  }, [teamData, players]);

  if (!tournamentId) {
    return (
      <TournamentConfigPageShell
        title="Kiểm tra điều kiện tham gia"
        description="Chọn giải để xem báo cáo điều kiện."
        noCard
      >
        <Alert severity="info" sx={{ mb: 2 }}>
          Chọn giải từ hub điều kiện tham gia.
        </Alert>
        <Button component={RouterLink} to="/tournament/eligibility" variant="contained">
          Chọn giải
        </Button>
      </TournamentConfigPageShell>
    );
  }

  if (!tournament) {
    return (
      <TournamentConfigPageShell title="Kiểm tra điều kiện tham gia" description="Không tìm thấy giải.">
        <Alert severity="error">Giải không tồn tại.</Alert>
      </TournamentConfigPageShell>
    );
  }

  if (isIndividualTournament(tournament) && individualReport) {
    const failed = individualReport.rows.filter((row) => !row.ok);
    return (
      <TournamentConfigPageShell
        title="Kiểm tra điều kiện — giải cá nhân"
        description={tournament.name}
      >
        <Stack direction="row" spacing={1} sx={{ mb: 2 }} alignItems="center">
          <Chip
            label={individualReport.ok ? "Tất cả đạt" : `${failed.length} đăng ký chưa đạt`}
            color={individualReport.ok ? "success" : "warning"}
          />
          <Button component={RouterLink} to={`/tournament/${tournament.id}/register`} size="small">
            Trang đăng ký
          </Button>
        </Stack>
        {failed.length === 0 ? (
          <Alert severity="success">Không có vi phạm điều kiện trên các đăng ký đang mở.</Alert>
        ) : (
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>Đăng ký</TableCell>
                <TableCell>Nội dung</TableCell>
                <TableCell>Vi phạm</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {failed.map((row) => (
                <TableRow key={row.entryId}>
                  <TableCell>{row.entryName}</TableCell>
                  <TableCell>{row.eventName}</TableCell>
                  <TableCell>
                    {row.players
                      .flatMap((player) => player.violations.map((v) => v.message))
                      .join("; ")}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </TournamentConfigPageShell>
    );
  }

  if (!isTeamTournament(tournament) || !teamData || !teamReport) {
    return (
      <TournamentConfigPageShell title="Kiểm tra điều kiện tham gia" description="Không hỗ trợ loại giải này.">
        <Alert severity="warning">Chỉ hỗ trợ giải cá nhân (S1-C) hoặc giải đồng đội.</Alert>
      </TournamentConfigPageShell>
    );
  }

  // Keep existing team report path
  const teamFailed = (teamReport.teams || []).filter((team) => !team.ok);
  return (
    <TournamentConfigPageShell title="Kiểm tra điều kiện — đồng đội" description={tournament.name}>
      <Chip
        sx={{ mb: 2 }}
        label={teamReport.ok ? "Tất cả đạt" : `${teamFailed.length} đội chưa đạt`}
        color={teamReport.ok ? "success" : "warning"}
      />
      <Paper variant="outlined">
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell>Đội</TableCell>
              <TableCell>VĐV</TableCell>
              <TableCell>Vi phạm</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {teamFailed.flatMap((team) =>
              team.players
                .filter((player) => !player.ok)
                .map((player) => (
                  <TableRow key={`${team.teamId}-${player.playerId}`}>
                    <TableCell>{team.teamName}</TableCell>
                    <TableCell>{player.playerName}</TableCell>
                    <TableCell>
                      {player.violations.map((item) => item.message).join("; ")}
                    </TableCell>
                  </TableRow>
                ))
            )}
          </TableBody>
        </Table>
      </Paper>
    </TournamentConfigPageShell>
  );
}

import {
  Alert,
  Button,
  FormControl,
  FormControlLabel,
  InputLabel,
  MenuItem,
  Select,
  Stack,
  Switch,
  TextField,
  Typography,
} from "@mui/material";

import {
  FEE_MODE,
  getEntryFee,
  getEntryFeeSummary,
  setEntryFee,
} from "../../../features/individual-tournament/engines/entryFeeEngine.js";
import { useIndividualTournamentConfig } from "../../../features/individual-tournament/hooks/useIndividualTournamentConfig.js";
import TournamentConfigPageShell from "../../../components/tournament/TournamentConfigPageShell.jsx";
import IndividualTournamentSelector from "../../../components/tournament/IndividualTournamentSelector.jsx";

export default function TournamentFeePage() {
  const {
    tournament,
    tournaments,
    tournamentId,
    selectTournament,
    persistTournament,
    message,
    setMessage,
  } = useIndividualTournamentConfig();

  const fee = getEntryFee(tournament);
  const summary = tournament ? getEntryFeeSummary(tournament) : null;

  const save = (patch) => {
    if (!tournament) {
      setMessage({ type: "error", text: "Chưa chọn giải." });
      return;
    }
    const result = setEntryFee(tournament, patch);
    if (!result.ok) {
      setMessage({ type: "error", text: result.error || "Không lưu được." });
      return;
    }
    if (!persistTournament(result.tournament)) return;
    setMessage({ type: "success", text: "Đã lưu lệ phí." });
  };

  return (
    <TournamentConfigPageShell
      title="Lệ phí tham gia"
      description="Miễn phí / cố định / early-bird / late — lưu trên giải cá nhân."
    >
      <IndividualTournamentSelector
        tournaments={tournaments}
        tournamentId={tournamentId}
        onSelect={selectTournament}
      />

      {message ? (
        <Alert severity={message.type} sx={{ mb: 2 }} onClose={() => setMessage(null)}>
          {message.text}
        </Alert>
      ) : null}

      <Stack spacing={2} sx={{ maxWidth: 480 }}>
        <FormControlLabel
          control={
            <Switch
              checked={fee.enabled}
              onChange={(event) =>
                save({
                  enabled: event.target.checked,
                  mode: event.target.checked ? FEE_MODE.FIXED : FEE_MODE.FREE,
                })
              }
              disabled={!tournament}
            />
          }
          label="Bật thu lệ phí"
        />
        <FormControl fullWidth size="small" disabled={!tournament || !fee.enabled}>
          <InputLabel>Chế độ phí</InputLabel>
          <Select
            label="Chế độ phí"
            value={fee.mode}
            onChange={(event) => save({ mode: event.target.value, enabled: true })}
          >
            <MenuItem value={FEE_MODE.FREE}>Miễn phí</MenuItem>
            <MenuItem value={FEE_MODE.FIXED}>Phí cố định</MenuItem>
            <MenuItem value={FEE_MODE.EARLY_BIRD}>Early-bird</MenuItem>
            <MenuItem value={FEE_MODE.LATE}>Late registration</MenuItem>
          </Select>
        </FormControl>
        <TextField
          label="Số tiền cơ bản"
          type="number"
          value={fee.amount}
          onChange={(event) => save({ amount: Number(event.target.value) || 0 })}
          disabled={!tournament || !fee.enabled}
        />
        <TextField
          label="Early-bird amount"
          type="number"
          value={fee.earlyBirdAmount ?? ""}
          onChange={(event) =>
            save({
              earlyBirdAmount: event.target.value === "" ? null : Number(event.target.value),
            })
          }
          disabled={!tournament || !fee.enabled}
        />
        <TextField
          label="Early-bird đến"
          type="datetime-local"
          InputLabelProps={{ shrink: true }}
          value={fee.earlyBirdUntil ? fee.earlyBirdUntil.slice(0, 16) : ""}
          onChange={(event) =>
            save({
              earlyBirdUntil: event.target.value
                ? new Date(event.target.value).toISOString()
                : null,
            })
          }
          disabled={!tournament || !fee.enabled}
        />
        <TextField
          label="Late amount"
          type="number"
          value={fee.lateAmount ?? ""}
          onChange={(event) =>
            save({ lateAmount: event.target.value === "" ? null : Number(event.target.value) })
          }
          disabled={!tournament || !fee.enabled}
        />
        <TextField
          label="Late từ"
          type="datetime-local"
          InputLabelProps={{ shrink: true }}
          value={fee.lateFrom ? fee.lateFrom.slice(0, 16) : ""}
          onChange={(event) =>
            save({
              lateFrom: event.target.value ? new Date(event.target.value).toISOString() : null,
            })
          }
          disabled={!tournament || !fee.enabled}
        />
        <TextField
          label="Đơn vị tiền tệ"
          value={fee.currency}
          onChange={(event) => save({ currency: event.target.value })}
          disabled={!tournament || !fee.enabled}
        />
        <FormControlLabel
          control={
            <Switch
              checked={fee.perPlayer}
              onChange={(event) => save({ perPlayer: event.target.checked })}
              disabled={!tournament || !fee.enabled}
            />
          }
          label="Tính theo từng VĐV"
        />
        <FormControlLabel
          control={
            <Switch
              checked={fee.requirePaidToApprove}
              onChange={(event) => save({ requirePaidToApprove: event.target.checked })}
              disabled={!tournament || !fee.enabled}
            />
          }
          label="Bắt buộc thanh toán trước khi duyệt"
        />
        <TextField
          label="Ghi chú / hướng dẫn phí"
          multiline
          minRows={2}
          value={fee.notes}
          onChange={(event) => save({ notes: event.target.value })}
          disabled={!tournament || !fee.enabled}
        />
        <TextField
          label="Thông báo xác nhận phí"
          value={fee.confirmationMessage}
          onChange={(event) => save({ confirmationMessage: event.target.value })}
          disabled={!tournament}
        />
        <Button variant="contained" onClick={() => save(fee)} disabled={!tournament}>
          Lưu
        </Button>

        {summary && fee.enabled && (
          <Alert severity="info">
            Tóm tắt: thu {summary.totalCollected}/{summary.totalExpected} {fee.currency} · chưa
            thanh toán: {summary.unpaidCount}
          </Alert>
        )}
      </Stack>
    </TournamentConfigPageShell>
  );
}
